        loadPreferences();
        mapSaveExecutor = Executors.newSingleThreadExecutor(r -> {
            Thread t = new Thread(r, "NotTiled-save");
            t.setDaemon(true);
            return t;
        });
        initErrorHandling();
        loadOpen();
