    byte[] nativeData;
    java.util.List<byte[]> nativeDatas = new ArrayList<byte[]>();
    String nativeFilename = "";
    java.util.List<String> nativeFilenames = new ArrayList<String>();
    String nativeStatus = "";
    String nativeUri = "";

    private boolean newFileToDevice = false; // new map should be created in the granted SAF folder

    private void nativeOpen(final String tujuan, final Table T) {
        nativeData = null;
        nativeFilename = "";
        nativeStatus = "";

        new Thread(new Runnable() {
            @Override
            public void run() {
                face.openFile();
                while (nativeStatus.equalsIgnoreCase("")) {
                    nativeStatus = face.getStatus();
                    try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                }

                if (nativeStatus.equalsIgnoreCase("cancel") || nativeStatus.equalsIgnoreCase("error")) {
                    log("cancel");
                    // UI changes must run on the render thread, not this worker thread.
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            exitDialog(T);
                        }
                    });
                    return;
                } else if (nativeStatus.equalsIgnoreCase("ok")) {
                    log("OK");
                    nativeData = face.getData();
                    nativeFilename = face.getFilename();
                    nativeUri = face.getUri();

                    FileHandle file = Gdx.files.absolute(curdir + "/" + nativeFilename);
                    file.writeBytes(nativeData, false);

                    final String importedName = nativeFilename;
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            exitDialog(null);
                            status(z.importok + ": " + importedName, 3);
                        }
                    });
                }

            }
        }).start();
    }

    private void nativeDirectory(final String tujuan, final Table T) {
        nativeDatas = null;
        nativeFilename = "";
        nativeStatus = "";

        new Thread(new Runnable() {
            @Override
            public void run() {
                face.selectFolder();
                while (nativeStatus.equalsIgnoreCase("")) {
                    nativeStatus = face.getStatus();
                    try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                }

                if (nativeStatus.equalsIgnoreCase("cancel")) {
                    log("cancel");
                    exitDialog(T);
                    return;
                } else if (nativeStatus.equalsIgnoreCase("ok")) {

                    log("OK");
                    nativeDatas = face.getDatas();
                    nativeFilenames = face.getFilenames();
                    if (nativeFilenames == null || nativeFilenames.size() == 0)
                        return;

                    if (nativeDatas != null && nativeDatas.size() > 0) {
                        for (int i = 0; i < nativeDatas.size(); i++) {
                            FileHandle file = Gdx.files.absolute(basepath + "NotTiled/Temp/" + nativeFilenames.get(i));
                            log(basepath + "NotTiled/Temp/" + nativeFilenames.get(i));
                            file.writeBytes(nativeDatas.get(i), false);
                        }
                    }

                    String tmxName = face.getFilename();
                    if (tmxName == null || tmxName.isEmpty()) {
                        tmxName = nativeFilenames.get(0);
                    }
                    FileHandle ff = Gdx.files.absolute(basepath + "NotTiled/Temp/" + tmxName);
                    exitDialog(T);
                    tujuanDialog(tujuan, ff);

                }
                log("here");

            }
        }).start();
    }

    /** Open a TMX file via the system SAF picker, then resolve and copy all
     *  referenced tileset images from the granted folder tree into Temp. */
    /**
     * Like {@link #exitDialog(Table)}, but rebuilds the menu table first. Returning
     * from the SAF picker (a separate activity) leaves the menu's contents stale, so
     * {@code gotoStage(tMenu)} alone shows a blank stage — its children must be
     * repopulated via setMenuMap() (this mirrors what resize() does on resume).
     */
    private void exitDialogRebuild(Table T) {
        if (T == tMenu) {
            setMenuMap();      // reassigns the tMenu field to a fresh, populated table
            gotoStage(tMenu);  // show the new table, not the now-stale reference in T
        } else {
            exitDialog(T);
        }
    }

    private void nativeOpenSAF(final String tujuan, final Table T) {
        nativeData = null;
        nativeFilename = "";
        nativeStatus = "";

        new Thread(new Runnable() {
            @Override
            public void run() {
                // Step 1: let user pick the TMX file
                face.openFile();
                while (nativeStatus.equalsIgnoreCase("")) {
                    nativeStatus = face.getStatus();
                    try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                }
                if (nativeStatus.equalsIgnoreCase("cancel") || nativeStatus.equalsIgnoreCase("error")) {
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            backToMap();
                        }
                    });
                    return;
                }

                final byte[] tmxData     = face.getData();
                final String tmxFilename = face.getFilename();
                final String tmxUri      = face.getUri();
                if (tmxData == null || tmxFilename == null || tmxFilename.isEmpty()) {
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            backToMap();
                        }
                    });
                    return;
                }

                // PNG/JPG/etc picked via Open → route through the normal import screen
                // so the user can set tile width/height before it's added as a tileset.
                String pickedExt = tmxFilename.contains(".")
                        ? tmxFilename.substring(tmxFilename.lastIndexOf('.') + 1).toLowerCase()
                        : "";
                if (pickedExt.equals("png") || pickedExt.equals("jpg") || pickedExt.equals("jpeg")
                        || pickedExt.equals("bmp") || pickedExt.equals("gif")) {
                    final FileHandle imgFile = Gdx.files.absolute(basepath + "NotTiled/Temp/" + tmxFilename);
                    imgFile.parent().mkdirs();
                    imgFile.writeBytes(tmxData, false);
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            backToMap();
                            thefile = imgFile;
                            fImportWidth.setText(Tsw + "");
                            fImportHeight.setText(Tsh + "");
                            cImportEmbed.setChecked(false);
                            gotoStage(tImport);
                        }
                    });
                    return;
                }

                // Step 2: locate the picked document inside the granted folder tree
                // and load it in place through the SAF FileHandle shim (/saf/…) —
                // relative tileset references resolve against its real folder.
                String tmxRelPath = face.hasTreeAccess() ? face.resolveUriToTreePath(tmxUri) : null;

                if (tmxRelPath == null) {
                    // No folder granted, or the file lives outside the granted folder.
                    // Write the TMX to Temp so we can at least open it without images,
                    // then prompt for folder access on the GL thread.
                    FileHandle tempTmx = Gdx.files.absolute(basepath + "NotTiled/Temp/" + tmxFilename);
                    tempTmx.parent().mkdirs();
                    tempTmx.writeBytes(tmxData, false);
                    final FileHandle finalTmx = tempTmx;
                    final String finalUri = tmxUri;
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            showFolderPermissionPrompt(finalTmx, finalUri, tujuan, T);
                        }
                    });
                    return;
                }

                final FileHandle finalFf = Gdx.files.absolute(face.getSafRoot() + tmxRelPath);
                Gdx.app.postRunnable(new Runnable() {
                    @Override
                    public void run() {
                        // Map loaded successfully → return to the editor (backToMap sets
                        // input to im and clears the stage). Using exitDialog(T) here would
                        // route to gotoStage(menu), leaving input stuck on the menu stage so
                        // the editor highlights buttons but never acts on them.
                        exitDialog(null);
                        tujuanDialog(tujuan, finalFf);
                    }
                });
            }
        }).start();
    }

    /** Open a document handed to us by a VIEW intent (tap on a .tmx in a file manager). */
    private void openFromViewIntent(final String uriStr) {
        new Thread(new Runnable() {
            @Override
            public void run() {
                // file:// URIs (legacy senders) carry a real path — open directly.
                if (uriStr.startsWith("file:")) {
                    String p = uriStr.substring("file:".length());
                    while (p.startsWith("//")) p = p.substring(1);
                    try { p = java.net.URLDecoder.decode(p, "UTF-8"); } catch (Exception ignored) {}
                    final FileHandle direct = Gdx.files.absolute(p);
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            if (direct.exists()) {
                                exitDialog(null);
                                tujuanDialog("open", direct);
                            } else {
                                newtmxfile(false);
                            }
                        }
                    });
                    return;
                }

                // Inside the granted folder → open in place through the /saf/ shim so
                // tileset images resolve and saves land in the real file.
                String relPath = face.hasTreeAccess() ? face.resolveUriToTreePath(uriStr) : null;
                if (relPath != null && !relPath.isEmpty()) {
                    final FileHandle ff = Gdx.files.absolute(face.getSafRoot() + relPath);
                    if (ff.exists()) {
                        Gdx.app.postRunnable(new Runnable() {
                            @Override
                            public void run() {
                                exitDialog(null);
                                tujuanDialog("open", ff);
                            }
                        });
                        return;
                    }
                }

                // Outside the granted folder (or none granted): read the document via
                // the one-shot URI grant, stash it in Temp, and prompt for folder
                // access so its tileset images can be resolved.
                final String content = face.getdatafromURI(uriStr);
                if (content == null || content.isEmpty()) {
                    Gdx.app.postRunnable(new Runnable() {
                        @Override
                        public void run() {
                            status(z.error != null ? z.error : "Error", 5);
                            newtmxfile(false);
                        }
                    });
                    return;
                }
                String name = face.getFilename();
                if (name == null || name.isEmpty()) name = "opened.tmx";
                final FileHandle tempTmx = Gdx.files.absolute(basepath + "NotTiled/Temp/" + name);
                tempTmx.parent().mkdirs();
                tempTmx.writeString(content, false);
                final boolean isTmx = name.toLowerCase().endsWith(".tmx");
                Gdx.app.postRunnable(new Runnable() {
                    @Override
                    public void run() {
                        if (isTmx) {
                            showFolderPermissionPrompt(tempTmx, uriStr, "open", null);
                        } else {
                            exitDialog(null);
                            tujuanDialog("open", tempTmx);
                        }
                    }
                });
            }
        }).start();
    }

    /** Shown when a TMX is open but no folder-tree permission is available to resolve images. */
    private void showFolderPermissionPrompt(final FileHandle tmxFile,
            final String tmxUri, final String tujuan, final Table T) {
        final Dialog dlg = new Dialog("", skin, "dialog");
        Table ct = dlg.getContentTable();
        ct.pad(20);

        Label title = new Label(
                z.tilesetImagesNotFound != null ? z.tilesetImagesNotFound : "Tileset images not found",
                skin);
        ct.add(title).colspan(2).padBottom(10).row();

        Label info = new Label(
                z.folderAccessInfo != null ? z.folderAccessInfo
                        : "Grant access to the folder containing your .tmx\nfile so NotTiled can load tileset images.",
                skin);
        info.setWrap(true);
        ct.add(info).width(btnx).colspan(2).padBottom(16).row();

        TextButton btnGrant = new TextButton(
                z.grantFolderAccess != null ? z.grantFolderAccess : "Grant Folder Access", skin);
        btnGrant.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                dlg.hide();
                new Thread(new Runnable() {
                    @Override
                    public void run() {
                        nativeStatus = "";
                        face.selectFolder();
                        while (nativeStatus.equalsIgnoreCase("")) {
                            nativeStatus = face.getStatus();
                            try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                        }
                        if (!nativeStatus.equalsIgnoreCase("cancel")) {
                            // Re-resolve the picked document inside the freshly granted tree
                            String relPath = face.resolveUriToTreePath(tmxUri);
                            if (relPath != null && !relPath.isEmpty()) {
                                FileHandle updated = Gdx.files.absolute(face.getSafRoot() + relPath);
                                if (updated.exists()) {
                                    final FileHandle finalUpdated = updated;
                                    Gdx.app.postRunnable(new Runnable() {
                                        @Override
                                        public void run() {
                                            // Loaded into editor → backToMap (input=im, clears stage)
                                            exitDialog(null);
                                            tujuanDialog(tujuan, finalUpdated);
                                        }
                                    });
                                    return;
                                }
                            }
                        }
                        // Fall through: load with whatever we have
                        Gdx.app.postRunnable(new Runnable() {
                            @Override
                            public void run() {
                                exitDialog(null);
                                tujuanDialog(tujuan, tmxFile);
                            }
                        });
                    }
                }).start();
            }
        });
        ct.add(btnGrant).width(btnx).height(btny).padBottom(8).colspan(2).row();

        TextButton btnSkip = new TextButton(
                z.skipFolderAccess != null ? z.skipFolderAccess : "Skip (load without images)", skin);
        btnSkip.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                dlg.hide();
                exitDialog(null);
                tujuanDialog(tujuan, tmxFile);
            }
        });
        ct.add(btnSkip).width(btnx).height(btny).colspan(2);

        dlg.show(stage);
    }

    private void resetSwatches() {
        Integer sw = 0;
        for (int ii = 0; ii < 6; ii++) {
            swatchValue.set(ii, 0);
        }

        for (property p : properties) {
            if (p.getName().equalsIgnoreCase("sw1")) {
                swatchValue.set(0, Integer.parseInt(p.getValue()));
            }
            if (p.getName().equalsIgnoreCase("sw2")) {
                swatchValue.set(1, Integer.parseInt(p.getValue()));
            }
            if (p.getName().equalsIgnoreCase("sw3")) {
                swatchValue.set(2, Integer.parseInt(p.getValue()));
            }
            if (p.getName().equalsIgnoreCase("sw4")) {
                swatchValue.set(3, Integer.parseInt(p.getValue()));
            }
            if (p.getName().equalsIgnoreCase("sw5")) {
                swatchValue.set(4, Integer.parseInt(p.getValue()));
            }
            if (p.getName().equalsIgnoreCase("sw6")) {
                swatchValue.set(5, Integer.parseInt(p.getValue()));
            }
        }

    }

