    float loadingtime = 0;

    int FPSCount = 0;

    @Override
    public void render() {
        if (!loadingfile && successfulFrames >= 0 && successfulFrames < 120) {
            successfulFrames++;
            if (successfulFrames == 120) {
                prefs.putInteger("abnormal_shutdowns", 0).flush();
            }
        }
        if (kartu.equalsIgnoreCase("game")) {
            if (!mygame.render())
                backToMap();
            return;
        }
        delta = Gdx.graphics.getDeltaTime();
        if (isActiveTerrainEditorPicker()) {
            terrainEditorAnimPhase = (terrainEditorAnimPhase + delta * 0.35f) % 1f;
            if (pinchZoomActive || Gdx.input.isTouched(1))
                terrainHoldPending = false;
            if (terrainHoldPending && Gdx.input.isTouched() && !pinchZoomActive && !Gdx.input.isTouched(1)) {
                terrainHoldTimer -= delta;
                if (terrainHoldTimer <= 0f)
                    beginTerrainPaintAt(Gdx.input.getX(), Gdx.input.getY());
            } else if (terrainHoldPending) {
                terrainHoldPending = false;
            }
            if (terrainPainting) {
                if (!Gdx.input.isTouched()) {
                    terrainPainting = false;
                    lastTerrainPaintCell = -1;
                    terrainHoldPending = false;
                    if (isMacroTerrainEditorPicker())
                        saveMacroAutoTerrain();
                } else if (tilesets.size() > 0) {
                    Vector3 t = new Vector3();
                    tilecam.unproject(t.set(Gdx.input.getX(), Gdx.input.getY(), 0));
                    if (isMacroTerrainEditorPicker()) {
                        paintMacroTerrainBrush(t.x, t.y);
                    } else {
                        tileset editorTs = getActiveTerrainEditorTileset();
                        if (editorTs != null)
                            paintTerrainBrush(editorTs, t.x, t.y);
                    }
                }
            }
        }
        // undolayer.clear();

        if (waittoloadlist > 0)
            waittoloadlist -= delta;
        if (waittoloadlist <= 0 && waittoloadlist != -1) {
            boolean isMulti = sMultiSelect || Gdx.input.isKeyPressed(Input.Keys.SHIFT_LEFT)
                    || Gdx.input.isKeyPressed(Input.Keys.SHIFT_RIGHT) || Gdx.input.isKeyPressed(Input.Keys.CONTROL_LEFT)
                    || Gdx.input.isKeyPressed(Input.Keys.CONTROL_RIGHT);
            if (selobjs.size() > 1 && activeobjtoolmode == 1 && !isMulti)
                loadList("object");
            waittoloadlist = -1;
        }

        if (objectListSearchDebounce >= 0f) {
            objectListSearchDebounce -= delta;
            if (objectListSearchDebounce <= 0f) {
                objectListSearchDebounce = -1f;
                if (objectListShellReady && lastStage == tObjectList) {
                    rebuildObjectListFilter();
                    rebuildObjectListRows();
                }
            }
        }

        tickEdgeFillJob(delta);

        if (movepointer > 0)
            movepointer -= delta;
        if (movepointer <= 0 && movepointer != -1) {
            if (body != null && activeobjtoolmode != 2) {
                body.setAwake(false);
                body.setTransform(-99999f, 99999f, 0);
            }
            movepointer = -1;
            // extra steps so Box2D drops the pointer's stale contact after parking
            physicsSettle = 3;
        }

        if (requestavailable)
            fullfilrequest();
        pointerremoval(delta);
        fulfilloldfunction();

        FPSCount += 1;
        if (FPSCount == 60)
            FPSCount = 0;

        try {
            if (firstrun) {
                asyncinitiation();
                firstrun = false;
            }
            if (loadingfile) {
                loadingtime += delta;
                drawLoadingScreen();
                if (kartu.equals("stage")) {
                    stage.act(delta);
                    stage.draw();
                }

            } else {
                // contacts only change while the pointer sensor is live (plus a
                // short settle after it parks), so skip stepping when idle
                if (movepointer != -1 || physicsSettle > 0) {
                    world.step(1 / 60f, 6, 2);
                    if (movepointer == -1 && physicsSettle > 0)
                        physicsSettle--;
                }

                Gdx.gl.glClearColor(bgr, bgg, bgb, 1f);
                clsEnter();
                if (firstload > 0) {
                    firstload -= 1;
                    Gdx.gl.glClearColor(0f, 0f, 0f, 1f);
                    Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

                    return;
                }
                if (firstload == 0) {
                    uiAnim();
                    firstload = -1;
                }

                if (timeToPan >= 0) {
                    timeToPan -= delta;
                    float progress = timeToPan < 0 ? 1 : 1f - timeToPan / panDuration;
                    OrthographicCamera cammy;
                    switch (panType) {
                        case 1:
                            cammy = tilecam;
                            break;
                        case 2:
                            cammy = uicam;
                            break;
                        default:
                            cammy = cam;
                    }

                    cammy.position.x = Interpolation.fade.apply(panOriginX, panTargetX, progress);
                    cammy.position.y = Interpolation.fade.apply(panOriginY, panTargetY, progress);
                    cammy.zoom = Interpolation.fade.apply(panOriginZoom, panTargetZoom, progress);
                    // cammy.position.x = (float) Math.round(cammy.position.x * 100f) / 100f;
                    // cammy.position.y = (float) Math.round(cammy.position.y * 100f) / 100f;

                    cammy.update();
                }

                autosave += delta;

                if (autosave > 60f * autosaveInterval) {
                    // log(autosaveInterval+"");
                    autosave = 0;
                    if (sAutoSave) {
                        status(z.autosaving, 1);

                        try {
                            Gdx.app.postRunnable(() -> {
                                saveMap(curdir + "/" + curfile);
                            });
                            /*
                             * autosavePool.execute( new Runnable( ){
                             * 
                             * @Override
                             * public void run() {
                             * }
                             * });
                             * 
                             */
                        } catch (Exception e) {
                            e.printStackTrace();
                        }

                    }
                }

                redraw += delta;

                if (redraw > 0.1f) {
                    redraw = 0;
                    cacheTiles();
                }

                if ((sShowAnimations || sShowGID || sShowGIDmap || sShowCoords) && kartu.equalsIgnoreCase("world")) {
                    int currentFps = Gdx.graphics.getFramesPerSecond();
                    if (currentFps > 0 && currentFps < 10) {
                        lowFpsTimer += delta;
                        if (lowFpsTimer >= 3.0f) {
                            StringBuilder sb = new StringBuilder();
                            if (sShowAnimations) {
                                sShowAnimations = false;
                                prefs.putBoolean("showanimations", false);
                                resetCaches();
                                clearPickerCaches();
                                sb.append("Animations");
                            }
                            boolean gidDisabled = false;
                            if (sShowGID) {
                                sShowGID = false;
                                prefs.putBoolean("gid", false);
                                gidDisabled = true;
                            }
                            if (sShowGIDmap) {
                                sShowGIDmap = false;
                                prefs.putBoolean("gidmap", false);
                                gidDisabled = true;
                            }
                            if (gidDisabled) {
                                if (sb.length() > 0)
                                    sb.append(", ");
                                sb.append("GID");
                            }
                            if (sShowCoords) {
                                sShowCoords = false;
                                prefs.putBoolean("coords", false);
                                if (sb.length() > 0)
                                    sb.append(", ");
                                sb.append("Coordinates");
                            }
                            prefs.flush();
                            sb.append(" disabled due to low FPS.");
                            status(sb.toString(), 2f);
                            lowFpsTimer = 0f;
                        }
                    } else {
                        lowFpsTimer = 0f;
                    }
                } else {
                    lowFpsTimer = 0f;
                }

                undohistory += delta;

                if (undohistory > 5f) {
                    undohistory = 0;
                    // Gdx.app.log("Cache","Clearing...");
                    if (undolayer.size() > 100000) {
                        undolayer.subList(0, undolayer.size() - 100000).clear();
                    }
                    // Gdx.app.log("Cache","Cleared");
                }

                rotator += delta;

                if (rotator > 0.15f) {
                    rotator = 0;
                    if (rotating && layers.size() > 0) {
                        viewMode = ViewMode.SINGLE;

                        int lastvis = -1;
                        int firstvis = -1;

                        for (int i = 0; i < layers.size(); i++) {
                            if (layers.get(i).isVisible() && layers.get(i).getType() != layer.Type.GROUP) {
                                if (firstvis == -1) {
                                    firstvis = i;
                                }

                                lastvis = i;
                            }
                        }
                        Gdx.app.log(firstvis + "", lastvis + "");
                        if (firstvis != -1) {
                            if (selLayer >= lastvis) {
                                selLayer = firstvis;
                            } else {

                                for (int i = 0; i < layers.size(); i++) {
                                    if (layers.get(i).isVisible() && layers.get(i).getType() != layer.Type.GROUP
                                            && i > selLayer) {
                                        selLayer = i;
                                        resetCaches();
                                        break;
                                    }
                                }
                            }
                        }

                    }
                }

                animate(delta);

                checkConnectionStatus();

                if (nofling > 0)
                    nofling -= delta;
                switch (kartu) {
                    case "world":
                        bloom.setEnabled(false);
                        vignette.setEnabled(false);
                        Gdx.gl.glEnable(GL20.GL_BLEND);
                        Gdx.gl.glBlendFunc(GL20.GL_SRC_ALPHA, GL20.GL_ONE_MINUS_SRC_ALPHA);

                        postProcessor.capture();
                        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

                        batch.totalRenderCalls = 0;

                        if (layers.size() > 0 && !"newpoly".equals(mode)) {
                            clampSelLayerToSelectable();
                            applyLayerModeForSelLayer();
                        }

                        if (midiplaying) {
                            if (composerPlayer != null) {
                                if (!composerPlayer.isPlaying()) {
                                    composerPlayer = null;
                                    midiplaying = false;
                                }
                            }
                        }

                        resetMinimap();

                        drawTiles();
                        drawGrid();
                        drawObjects();
                        drawObjectsInfo();
                        // drawCollisions();
                        postProcessor.render();
                        drawWorldUI();
                        // draw debug for collision detection (only in edit mode, hide while dragging)
                        if (activeobjtoolmode == 2 && !markermode) {
                            b2dr.render(world, isFull3DMode ? camFull3D.combined : (is3DMode ? cam3d.combined : cam.combined));
                        }

                        drawstage(delta);

                        break;
                    case "stage":
                        // crt.setEnabled(true);
                        bloom.setEnabled(true);

                        Gdx.gl.glEnable(GL20.GL_BLEND);
                        Gdx.gl.glBlendFunc(GL20.GL_SRC_ALPHA, GL20.GL_ONE_MINUS_SRC_ALPHA);

                        postProcessor.capture();
                        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

                        batch.totalRenderCalls = 0;
                        drawTiles();
                        // drawGrid();
                        postProcessor.render();
                        // drawObjects();
                        // drawObjectsInfo();
                        // drawWorldUI();
                        drawstage(delta);
                        stage.getCamera().update();

                        break;
                    case "tile":
                    case "pickanim":
                    case "pick":
                        // Use the same bloom+postProcessor pipeline as the menu ("stage") case
                        bloom.setEnabled(true);

                        Gdx.gl.glEnable(GL20.GL_BLEND);
                        Gdx.gl.glBlendFunc(GL20.GL_SRC_ALPHA, GL20.GL_ONE_MINUS_SRC_ALPHA);

                        postProcessor.capture();
                        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

                        batch.totalRenderCalls = 0;
                        drawTiles();
                        postProcessor.render();

                        drawpicker();
                        drawstage(delta);
                        stage.getCamera().update();

                        break;
                    case "editor":
                        switch (mode) {
                            case "tile":
                            case "object":
                            case "image":
                                bloom.setEnabled(false);
                                vignette.setEnabled(false);
                                Gdx.gl.glEnable(GL20.GL_BLEND);
                                Gdx.gl.glBlendFunc(GL20.GL_SRC_ALPHA, GL20.GL_ONE_MINUS_SRC_ALPHA);

                                postProcessor.capture();
                                Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

                                batch.totalRenderCalls = 0;

                                resetMinimap();

                                drawTiles();
                                drawGrid();
                                drawObjects();
                                drawObjectsInfo();
                                postProcessor.render();
                                drawWorldUI();

                                drawstage(delta);
                                break;
                            case "pick":
                                Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

                                drawpicker();
                                drawstage(delta);

                                break;

                        }

                        break;

                    // case "stage":

                    // break;
                }

                keyinput(delta);
                if (timeToPan2 >= 0) {
                    timeToPan2 -= delta;
                    float progress = timeToPan2 < 0 ? 1 : 1f - timeToPan2 / panDuration2;
                    uicam.zoom = Interpolation.fade.apply(panOriginZoom2, panTargetZoom2, progress);

                    uicam.update();
                    uis.setProjectionMatrix(uicam.combined);
                    uis.begin(ShapeRenderer.ShapeType.Filled);
                    Gdx.gl.glEnable(GL20.GL_BLEND);
                    Gdx.gl.glBlendFunc(GL20.GL_SRC_ALPHA, GL20.GL_ONE_MINUS_SRC_ALPHA);

                    float alfa = timeToPan2;
                    Color cc = new Color(0, 0, 0, alfa);
                    if (!landscape) {
                        uis.rect(0f, 0f, (float) ssx, (float) ssy, cc, cc, cc, cc);
                    } else {
                        uis.rect(0f, 0f, (float) ssy, (float) ssx, cc, cc, cc, cc);
                    }
                    uis.end();

                }

                if (firstload > 0) {
                    uis.setProjectionMatrix(uicam.combined);
                    uis.begin(ShapeRenderer.ShapeType.Filled);
                    Gdx.gl.glEnable(GL20.GL_BLEND);
                    Gdx.gl.glBlendFunc(GL20.GL_SRC_ALPHA, GL20.GL_ONE_MINUS_SRC_ALPHA);

                    Color cc = new Color(0, 0, 0, 1);
                    uis.rect(0f, 0f, (float) ssx, (float) ssy, cc, cc, cc, cc);
                    uis.end();
                    firstload -= 1;
                }

            }
        } catch (Exception e) {
            ErrorBung(e, "errorlog2.txt");
            // status("Error in render", 5);
            if (batch.isDrawing())
                batch.end();
            if (ui.isDrawing())
                ui.end();
            if (sr.isDrawing())
                sr.end();
            if (uis.isDrawing())
                uis.end();

            // newtmxfile(false);
        }

    }

    void drawCoordinates() {
        if (cam.zoom > 0.5f)
            return;

        if (sShowCoords) {
            str1.getData().setScale(0.01f + Tsw / 160f);
            for (int yy = 0; yy < Th; yy++) {
                for (int xx = 0; xx < Tw; xx++) {
                    float drawX, drawY;
                    if (orientation.equalsIgnoreCase("isometric")) {
                        float offsetx = (xx * Tsw / 2f) + (yy * Tsw / 2f);
                        float offsety = (xx * Tsh / 2f) - (yy * Tsh / 2f);
                        drawX = (xx * Tsw + Tsw / 8f) - offsetx;
                        drawY = (-yy * Tsh + Tsh / 3f) - offsety;
                    } else {
                        drawX = xx * Tsw + Tsw / 8f;
                        drawY = -yy * Tsh + Tsh / 3f;
                    }

                    if (cam.frustum.pointInFrustum(drawX, drawY, 0)) {
                        str1.draw(batch, xx + "," + yy, drawX, drawY);
                    }
                }
            }
            str1.getData().setScale(1f);
        }

        if (layers.size() > 0) {
            for (int l = 0; l < layers.size(); l++) {
                if (layers.get(l).getType() == layer.Type.TILE && l == selLayer) {
                    if (sShowGIDmap) {
                        str1.getData().setScale(0.01f + Tsw / 160f);
                        for (int yy = 0; yy < Th; yy++) {
                            for (int xx = 0; xx < Tw; xx++) {
                                int num = yy * Tw + xx;
                                long spr = layers.get(l).getStr().get(num);
                                if (spr == 0)
                                    continue;

                                float drawX, drawY;
                                if (orientation.equalsIgnoreCase("isometric")) {
                                    float offsetx = (xx * Tsw / 2f) + (yy * Tsw / 2f);
                                    float offsety = (xx * Tsh / 2f) - (yy * Tsh / 2f);
                                    drawX = (xx * Tsw + Tsw / 8f) - offsetx;
                                    drawY = (-yy * Tsh + Tsh) - offsety;
                                } else {
                                    drawX = xx * Tsw + Tsw / 8f;
                                    drawY = -yy * Tsh + Tsh;
                                }

                                if (cam.frustum.pointInFrustum(drawX, drawY, 0)) {
                                    str1.draw(batch, spr + "", drawX, drawY);
                                }
                            }
                        }
                        str1.getData().setScale(1f);
                    }
                }
            }
        }
    }

    void initializePostProcessor() { // I DONT EVEN KNOW WHAT THESE MEANS LOL
        ShaderLoader.BasePath = "data/shaders/";
        postProcessor = new PostProcessor(true, true, isDesktop);

        postProcessor.setClearColor(.5f, .5f, .5f, 1);
        int vpW = Gdx.graphics.getWidth();
        int vpH = Gdx.graphics.getHeight();
        // create the effects you want
        bloom = new Bloom((int) (Gdx.graphics.getWidth() * 0.25f), (int) (Gdx.graphics.getHeight() * 0.25f));
        curvature = new Curvature();
        zoomer = new Zoomer(vpW, vpH, isDesktop ? RadialBlur.Quality.VeryHigh : RadialBlur.Quality.Low);
        int effects = CrtScreen.Effect.TweakContrast.v | CrtScreen.Effect.PhosphorVibrance.v
                | CrtScreen.Effect.Scanlines.v | CrtScreen.Effect.Tint.v;
        crt = new CrtMonitor(vpW, vpH, false, false, CrtScreen.RgbMode.ChromaticAberrations, effects);
        crt.setTint(0.8f, 0.8f, .8f);
        Combine combine = crt.getCombinePass();
        combine.setSource1Intensity(0f);
        combine.setSource2Intensity(1f);
        combine.setSource1Saturation(0f);
        combine.setSource2Saturation(1f);
        vignette = new Vignette(vpW, vpH, false);
        // add them to the postprocessor
        postProcessor.addEffect(curvature);
        postProcessor.addEffect(zoomer);
        postProcessor.addEffect(vignette);
        postProcessor.addEffect(crt);
        postProcessor.addEffect(bloom);
        bloom.setBaseIntesity(0.0f);
        bloom.setBlurAmount(1);// 5
        zoomer.setBlurStrength(-0.1f);
        zoomer.setOrigin(Gdx.graphics.getWidth() / 2, Gdx.graphics.getHeight() / 2);
        curvature.setZoom(1f);
        vignette.setIntensity(1f);
        bloom.setEnabled(false);
        crt.setEnabled(false);
        vignette.setEnabled(false);
        curvature.setEnabled(false);
        zoomer.setEnabled(false);
    }

    private void clsEnter() {
        fps = Integer.toString(Gdx.graphics.getFramesPerSecond());

    }

    public void animate(float delta) {
        if (turun) {
            blink -= 0.02f;
        } else {
            blink += 0.02f;
        }
        if (blink >= 1) {
            blink = 1;
            turun = true;
        }
        if (blink <= 0) {
            blink = 0;
            turun = false;
        }

        if (tilesets.size() > 0 && !deletinganim) {
            for (int g = 0; g < tilesets.size(); g++) {
                tiles = tilesets.get(g).getTiles();
                if (tiles.size() > 0) {
                    for (int i = 0; i < tiles.size(); i++) {
                        if (tiles.get(i).getAnimation().size() > 0) {
                            tiles.get(i).addTimer(delta);
                            int actFrame = tiles.get(i).getActiveFrameIndex();
                            if (tiles.get(i).getTimer() >= (float) tiles.get(i).getActiveFrameDuration() / 1000) {
                                tiles.get(i).setTimer(0);
                                tiles.get(i).setActiveFrameIndex(tiles.get(i).getActiveFrameIndex() + 1);
                                if (tiles.get(i).getActiveFrameIndex() >= tiles.get(i).getAnimation().size()) {
                                    tiles.get(i).setActiveFrameIndex(0);
                                }
                                int newActframe = tiles.get(i).getActiveFrameIndex();
                                if (!deletinganim)
                                    tiles.get(i)
                                            .setActiveFrameID(tiles.get(i).getAnimation().get(newActframe).getTileID());
                                if (!deletinganim)
                                    tiles.get(i).setActiveFrameDuration(
                                            tiles.get(i).getAnimation().get(newActframe).getDuration());

                            }
                        }
                    }
                } // if
            } // for
        } // if
    }

    boolean touched, usetool;
    boolean touchable = true;

    void keyinput(float delta) {
        if (!Gdx.input.isTouched() && iseditGUI) {
            iseditGUI = false;
        }

        if (Gdx.input.isTouched()) {
            touched = true;
        }
        if (touched & usetool & !Gdx.input.isTouched()) {
            touched = false;
            usetool = false;
            // updateMinimap();
        }

        if (roll) {
            if (!Gdx.input.isTouched()) {
                if (replaceRangePicking) {
                    finishReplaceRangePick();
                } else if (mapstartSelect == mapendSelect) {
                    if (activetool == 4)
                        endBrushStroke();
                    roll = false;
                }
            } else {
                float pex = (float) Gdx.input.getX() / nssx;
                float pey = (float) Gdx.input.getY() / nssy;
                float edgeStep = 15f * cam.zoom;
                if (pex > 0.90f)
                    cam.translate(edgeStep, 0);
                if (pex < 0.10f)
                    cam.translate(-edgeStep, 0);
                if (pey > 0.90f)
                    cam.translate(0, -edgeStep);
                if (pey < 0.10f)
                    cam.translate(0, edgeStep);
                clampWorldCamPosition();
                cam.update();
            }
        }

        if (Gdx.input.isKeyPressed(Input.Keys.CONTROL_LEFT) && Gdx.input.isKeyJustPressed(Input.Keys.Z)) {
            if ("tile".equals(mode)) {
                try {

                    if (undolayer.size() > 0) {
                        layerhistory lh;
                        long histcount = 0;
                        for (int n = undolayer.size() - 1; n >= 0; n--) {

                            lh = undolayer.get(n);
                            layers.get(lh.getLayer()).getStr().set(lh.getLocation(), lh.getFrom());
                            layers.get(lh.getLayer()).getTset().set(lh.getLocation(), lh.getoldTset());
                            redolayer.add(lh);
                            histcount++;
                            if (!lh.isFollower()) {
                                java.util.List<layerhistory> templist = new ArrayList<layerhistory>();

                                for (int t = 0; t < undolayer.size() - histcount; t++) {
                                    templist.add(undolayer.get(t));
                                }
                                undolayer = new ArrayList<layerhistory>();
                                undolayer = templist;
                                break;
                            }
                        }
                    }
                } catch (Exception e) {
                    ErrorBung(e, "undo.txt");
                }
            }
            if ("newpoly".equals(mode)) {

                newobject.undoPoint();
            }
        }

        if (!"stage".equals(kartu)) {
            if (Gdx.input.isKeyJustPressed(Input.Keys.E)) {
                eraser = !eraser;
            }
            if (Gdx.input.isKeyJustPressed(Input.Keys.Q)) {
                markermode = false;
            }
            if ("object".equals(mode)
                    && (Gdx.input.isKeyJustPressed(Input.Keys.DEL) || Gdx.input.isKeyJustPressed(Input.Keys.FORWARD_DEL)
                            || Gdx.input.isKeyJustPressed(Input.Keys.BACKSPACE))) {
                if (stage.getKeyboardFocus() == null && selobjs.size() > 0) {
                    boolean first = true;
                    for (obj o : selobjs) {
                        o.destroyBody(world);
                        layers.get(selLayer).getObjects().remove(o);
                        
                        layerobjecthistory loh = new layerobjecthistory();
                        loh.setRelatedobj(o);
                        loh.setLayer(selLayer);
                        loh.setAction("delete");
                        loh.follower = !first;
                        first = false;
                        loh.setData(serializeObject(o));
                        undolayerobject.add(loh);
                    }
                    redolayerobject.clear();
                    selobjs.clear();
                    oldobjdata.clear();
                    pushUpdateIfCollaborating();
                }
            }
            if (is3DMode && "world".equals(kartu)) {
                float yawRad = (float) Math.toRadians(cam3dYaw);
                float cosYaw = (float) Math.cos(yawRad);
                float sinYaw = (float) Math.sin(yawRad);
                float speed = 15f * cam3dZoom;
                if (Gdx.input.isKeyPressed(Input.Keys.W) || Gdx.input.isKeyPressed(Input.Keys.UP)) {
                    cam3dTargetX += cosYaw * speed;
                    cam3dTargetY += sinYaw * speed;
                }
                if (Gdx.input.isKeyPressed(Input.Keys.S) || Gdx.input.isKeyPressed(Input.Keys.DOWN)) {
                    cam3dTargetX -= cosYaw * speed;
                    cam3dTargetY -= sinYaw * speed;
                }
                if (Gdx.input.isKeyPressed(Input.Keys.A) || Gdx.input.isKeyPressed(Input.Keys.LEFT)) {
                    cam3dTargetX -= -sinYaw * speed;
                    cam3dTargetY -= cosYaw * speed;
                }
                if (Gdx.input.isKeyPressed(Input.Keys.D) || Gdx.input.isKeyPressed(Input.Keys.RIGHT)) {
                    cam3dTargetX += -sinYaw * speed;
                    cam3dTargetY += cosYaw * speed;
                }
            } else {
                if (Gdx.input.isKeyPressed(Input.Keys.W) || Gdx.input.isKeyPressed(Input.Keys.UP)) {
                    cam.position.add(0, 40f, 0);
                }
                if (Gdx.input.isKeyPressed(Input.Keys.A) || Gdx.input.isKeyPressed(Input.Keys.LEFT)) {
                    cam.position.add(-40f, 0, 0);
                }
                if (Gdx.input.isKeyPressed(Input.Keys.S) || Gdx.input.isKeyPressed(Input.Keys.DOWN)) {
                    cam.position.add(0, -40f, 0);
                }
                if (Gdx.input.isKeyPressed(Input.Keys.D) || Gdx.input.isKeyPressed(Input.Keys.RIGHT)) {
                    cam.position.add(40f, 0, 0);
                }
                cam.update();
            }
        }

        if (Gdx.input.isKeyPressed(Input.Keys.X)) {
            if ("world".equals(kartu)) {
                if (is3DMode) {
                    cam3dZoom = Math.min(cam3dZoom * 1.05f, 10.0f);
                } else if (cam.zoom < maxWorldZoomOut()) {
                    cam.zoom = Math.min(cam.zoom * 1.1f, maxWorldZoomOut());
                    cam.update();
                }
            } else if ("tile".equals(kartu) || "pickanim".equals(kartu)) {
                if (tilecam.zoom < 100) {
                    tilecam.zoom = tilecam.zoom * 1.1f;
                    tilecam.update();
                }
            }
        }
        if (Gdx.input.isKeyPressed(Input.Keys.C)) {
            if ("world".equals(kartu)) {
                if (is3DMode) {
                    cam3dZoom = Math.max(cam3dZoom / 1.05f, 0.1f);
                } else if (cam.zoom > Tsw / 320f) {
                    cam.zoom = cam.zoom / 1.1f;
                    if (cam.zoom < Tsw / 320f)
                        cam.zoom = Tsw / 320f;
                    cam.update();
                }
            } else if ("tile".equals(kartu) || "pickanim".equals(kartu)) {
                float minZoom = tilePickerMinZoom();
                if (tilecam.zoom > minZoom) {
                    tilecam.zoom = tilecam.zoom / 1.1f;
                    if (tilecam.zoom < minZoom)
                        tilecam.zoom = minZoom;
                    tilecam.update();
                }
            }
        }
        // {tilecam.zoom = Tsw/320f;}

        getbacknow();
        if (velx > 10)
            velx = velx / 1.2f;
        if (velx < -10)
            velx = velx / 1.2f;
        if (vely > 10)
            vely = vely / 1.2f;
        if (vely < -10)
            vely = vely / 1.2f;
        if (velx <= 10 && velx >= -10)
            velx = 0;
        if (vely <= 10 && vely >= -10)
            vely = 0;
        if (!(velx == 0 && vely == 0)) {
            if ((is3DMode || isFull3DMode) && kartu.equalsIgnoreCase("world")) {
                // In 3D mode, fling momentum moves the camera target, not orbits
                com.badlogic.gdx.graphics.Camera activeCam = isFull3DMode ? camFull3D : cam3d;
                com.badlogic.gdx.math.Vector3 dir = activeCam.direction.cpy();
                dir.z = 0;
                dir.nor();
                com.badlogic.gdx.math.Vector3 right = dir.cpy().crs(activeCam.up);
                right.z = 0;
                right.nor();
                float speed = cam3dZoom * 0.5f;
                float dx = velx / 50f;
                float dy = vely / 50f;
                cam3dTargetX -= (right.x * dx + dir.x * dy) * speed;
                cam3dTargetY -= (right.y * dx + dir.y * dy) * speed;
            } else {
                pan(0, 0, velx / 50, vely / 50);
            }
        } else {
            drag = false;
        }

    }

