    private void drawObjects() {
        sr.setProjectionMatrix(isFull3DMode ? camFull3D.combined : (is3DMode ? cam3d.combined : cam.combined));

        // Part one of 2, filled.
        sr.begin(ShapeRenderer.ShapeType.Filled); // Edit it with filled to make it looks gorgeous.
        Gdx.gl.glEnable(GL20.GL_BLEND);
        if (isFull3DMode) {
            Gdx.gl.glDepthMask(false);
        }

        Gdx.gl20.glLineWidth(5);// average
        sr.setColor(0.5f, 0.5f, 0.5f, 0.5f); // blink

        if (layers.size() > 0) {
            for (int i = 0; i < layers.size(); i++) {

                if (i == selLayer) {
                    sr.setColor(0.5f, 0.7f, 0.5f, 0.5f); // blink

                } else {
                    sr.setColor(0.5f, 0.5f, 0.5f, 0.5f); // blink

                }

                boolean isShown = layerShownInViewMode(i);

                if (layers.get(i).getType() == layer.Type.OBJECT && isShown && layers.get(i).getObjects().size() > 0) {
                    float layerZ = i * Tsh * 0.75f + 0.1f;
                    if (isFull3DMode) {
                        sr.setTransformMatrix(tmpTransformMatrix.setToTranslation(0, 0, layerZ));
                    } else {
                        sr.setTransformMatrix(IDT_MATRIX);
                    }

                    updateMarkers();
                    for (int j = 0; j < layers.get(i).getObjects().size(); j++) {

                        obj ox = layers.get(i).getObjects().get(j);
                        if (selobjs.contains(ox)) {
                            sr.setColor(0.9f, 0.5f, 0.9f, 0.5f); // not green
                        } else {
                            sr.setColor(0.5f, 0.7f, 0.5f, 0.5f); // green
                        }

                        if (ox.getShape() != null) {
                            switch (ox.getShape()) {
                                case "ellipse":
                                    sr.ellipse(ox.getX(), -ox.getY() + Tsh - ox.getH(), ox.getW(), ox.getH());

                                    break;
                                case "point":
                                    sr.ellipse(ox.getXa() + Tsh / 4, -ox.getYa() + Tsh - Tsh * 3 / 4, Tsw / 2, Tsh / 2);

                                    sr.rect(ox.getXa() + Tsh / 4, -ox.getYa() + Tsh - Tsh * 3 / 4, Tsw / 2, Tsh / 2);

                                    break;
                                case "polygon":
                                    // sr.ellipse(ox.getXa() + Tsh / 4, -ox.getYa() + Tsh - Tsh * 3 / 4, Tsw / 2,
                                    // Tsh / 2);
                                    // sr.ellipse(ox.getXa() + Tsh * 3 / 8, -ox.getYa() + Tsh - Tsh * 5 / 8, Tsw /
                                    // 4, Tsh / 4);

                                    float[] f = ox.getVertices(Tsh);
                                    if (ox.getPointsSize() >= 3) {
                                        Polygon polygon = new Polygon();
                                        polygon.setVertices(f);
                                        polygon.setOrigin(ox.getX(), -ox.getY() + Tsh);
                                        polygon.rotate(360 - ox.getRotation());
                                        sr.polygon(polygon.getTransformedVertices());
                                    }

                                    break;
                                case "polyline":
                                    // sr.ellipse(ox.getXa() + Tsh / 4f, -ox.getYa() + Tsh - Tsh * 3f / 4f, Tsw /
                                    // 2f, Tsh / 2f);
                                    // sr.ellipse(ox.getXa() + Tsh * 3f / 8f, -ox.getYa() + Tsh - Tsh * 5f / 8f, Tsw
                                    // / 4f, Tsh / 4f);

                                    /*
                                     * if (ox.getPointsSize() >= 2) {
                                     * f = ox.getVertices(Tsh);
                                     * Polyline polyline = new Polyline(f);
                                     * polyline.setOrigin(ox.getX(), -ox.getY() + Tsh);
                                     * polyline.rotate(360 - ox.getRotation());
                                     * sr.polyline(polyline.getTransformedVertices());
                                     * }
                                     */

                                    break;
                                case "text":
                                    sr.rect(ox.getX(), ox.getYantingelag(Tsh) - ox.getH(), 0, 0, ox.getW(), ox.getH(),
                                            1, 1, ox.getRotation());
                                    // str1.draw(batch, ox.getText(), ox.getX(), -ox.getYantingelag(Tsh));

                                    break;
                                case "image":
                                    sr.rect(ox.getX(), ox.getYantingelag(Tsh), 0, 0, ox.getW(), ox.getH(), 1, 1,
                                            360 - ox.getRotation());
                                    break;
                                default:
                                    if (orientation.equalsIgnoreCase("orthogonal")) {
                                        sr.rect(ox.getX(), ox.getYantingelag(Tsh) - ox.getH(), 0, ox.getH(), ox.getW(),
                                                ox.getH(), 1, 1, 360 - ox.getRotation());
                                    } else if (orientation.equalsIgnoreCase("isometric")) {
                                        // anchor
                                        float offx = (ox.getX() / Tsh * Tsw / 2) - (ox.getY() / Tsh * Tsw / 2);// -ox.getY();
                                        float offy = (-ox.getX() / Tsh * Tsh / 2) - (ox.getY() / Tsh * Tsh / 2); // -ox.getY()*Tsh/2;

                                        float op1 = Tsw / 2; // '0'
                                        float op2 = Tsh; // 0
                                        float op3 = ox.getW() / Tsh * Tsw / 2;
                                        float op4 = ox.getW() / Tsh * Tsh / 2;
                                        float op5 = (ox.getW() / Tsh * Tsw / 2) - (ox.getH() / Tsh * Tsw / 2);
                                        float op6 = (-ox.getH() / Tsh * Tsh / 2) - (ox.getW() / Tsh * Tsh / 2);
                                        float op7 = -ox.getH() / Tsh * Tsw / 2;
                                        float op8 = -ox.getH() / Tsh * Tsh / 2;

                                        float p1 = offx + op1;
                                        float p2 = offy + op2;
                                        float p3 = offx + op1 + op3;
                                        float p4 = offy + op2 - op4;
                                        float p5 = offx + op1 + op5;
                                        float p6 = offy + op2 + op6;
                                        float p7 = offx + op1 + op7;
                                        float p8 = offy + op2 + op8;

                                        sr.polygon(new float[] { p1, p2, p3, p4, p5, p6, p7, p8 });

                                    }
                                    // str1.draw(batch, j+"", 0, -j);

                                    break;
                            }

                        } else {
                            sr.rect(ox.getX(), ox.getYantingelag(Tsh) - ox.getH(), ox.getW(), ox.getH());

                        }

                    }
                }
            }
        }
        if (isFull3DMode) {
            sr.setTransformMatrix(IDT_MATRIX);
        }
        sr.end();

        // part 2 of 2, outline.
        sr.begin(ShapeRenderer.ShapeType.Line); //
        Gdx.gl.glEnable(GL20.GL_BLEND);
        if (isFull3DMode) {
            Gdx.gl.glDepthMask(false);
        }

        Gdx.gl20.glLineWidth(5);// average
        // sr.setColor(0.8f, 0.8f, 0.8f, 0.5f); //blink

        if (layers.size() > 0) {
            for (int i = 0; i < layers.size(); i++) {

                if (i == selLayer) {
                    sr.setColor(0.5f, 1f, 0.5f, 1f); // blink

                } else {
                    sr.setColor(0.8f, 0.8f, 0.8f, 0.5f); // blink

                }

                boolean isShown = layerShownInViewMode(i);

                if (layers.get(i).getType() == layer.Type.OBJECT && isShown && layers.get(i).getObjects().size() > 0) {
                    float layerZ = i * Tsh * 0.75f + 0.1f;
                    if (isFull3DMode) {
                        sr.setTransformMatrix(tmpTransformMatrix.setToTranslation(0, 0, layerZ));
                    } else {
                        sr.setTransformMatrix(IDT_MATRIX);
                    }

                    for (int j = 0; j < layers.get(i).getObjects().size(); j++) {

                        obj ox = layers.get(i).getObjects().get(j);

                        if (ox.getShape() != null) {
                            switch (ox.getShape()) {
                                case "ellipse":
                                    sr.ellipse(ox.getX(), -ox.getY() + Tsh - ox.getH(), ox.getW(), ox.getH());

                                    break;
                                case "point":
                                    sr.ellipse(ox.getXa() + Tsh / 4, -ox.getYa() + Tsh - Tsh * 3 / 4, Tsw / 2, Tsh / 2);

                                    sr.rect(ox.getXa() + Tsh / 4, -ox.getYa() + Tsh - Tsh * 3 / 4, Tsw / 2, Tsh / 2);

                                    break;
                                case "polygon":
                                    sr.ellipse(ox.getXa() + Tsh / 4, -ox.getYa() + Tsh - Tsh * 3 / 4, Tsw / 2, Tsh / 2);
                                    sr.ellipse(ox.getXa() + Tsh * 3 / 8, -ox.getYa() + Tsh - Tsh * 5 / 8, Tsw / 4,
                                            Tsh / 4);

                                    float[] f = ox.getVertices(Tsh);
                                    if (ox.getPointsSize() == 2) {

                                        f = ox.getVertices(Tsh);
                                        Polyline polyline = new Polyline(f);
                                        polyline.setOrigin(ox.getX(), -ox.getY() + Tsh);
                                        polyline.rotate(360 - ox.getRotation());
                                        sr.polyline(polyline.getTransformedVertices());

                                    } else if (ox.getPointsSize() >= 3) {
                                        Polygon polygon = new Polygon();
                                        polygon.setVertices(f);
                                        polygon.setOrigin(ox.getX(), -ox.getY() + Tsh);
                                        polygon.rotate(360 - ox.getRotation());
                                        sr.polygon(polygon.getTransformedVertices());
                                    }

                                    break;
                                case "polyline":
                                    sr.ellipse(ox.getXa() + Tsh / 4f, -ox.getYa() + Tsh - Tsh * 3f / 4f, Tsw / 2f,
                                            Tsh / 2f);
                                    sr.ellipse(ox.getXa() + Tsh * 3f / 8f, -ox.getYa() + Tsh - Tsh * 5f / 8f, Tsw / 4f,
                                            Tsh / 4f);

                                    if (ox.getPointsSize() >= 2) {
                                        f = ox.getVertices(Tsh);
                                        Polyline polyline = new Polyline(f);
                                        polyline.setOrigin(ox.getX(), -ox.getY() + Tsh);
                                        polyline.rotate(360 - ox.getRotation());
                                        sr.polyline(polyline.getTransformedVertices());
                                    }
                                    break;
                                case "text":
                                    sr.rect(ox.getX(), ox.getYantingelag(Tsh) - ox.getH(), 0, 0, ox.getW(), ox.getH(),
                                            1, 1, ox.getRotation());
                                    // str1.draw(batch, ox.getText(), ox.getX(), -ox.getYantingelag(Tsh));

                                    break;
                                case "image":
                                    sr.rect(ox.getX(), ox.getYantingelag(Tsh), 0, 0, ox.getW(), ox.getH(), 1, 1,
                                            360 - ox.getRotation());
                                    break;
                                default:
                                    if (orientation.equalsIgnoreCase("orthogonal")) {
                                        sr.rect(ox.getX(), ox.getYantingelag(Tsh) - ox.getH(), 0, ox.getH(), ox.getW(),
                                                ox.getH(), 1, 1, 360 - ox.getRotation());
                                    } else if (orientation.equalsIgnoreCase("isometric")) {

                                        // anchor
                                        float offx = (ox.getX() / Tsh * Tsw / 2) - (ox.getY() / Tsh * Tsw / 2);// -ox.getY();
                                        float offy = (-ox.getX() / Tsh * Tsh / 2) - (ox.getY() / Tsh * Tsh / 2); // -ox.getY()*Tsh/2;

                                        float op1 = Tsw / 2; // '0'
                                        float op2 = Tsh; // 0
                                        float op3 = ox.getW() / Tsh * Tsw / 2;
                                        float op4 = ox.getW() / Tsh * Tsh / 2;
                                        float op5 = (ox.getW() / Tsh * Tsw / 2) - (ox.getH() / Tsh * Tsw / 2);
                                        float op6 = (-ox.getH() / Tsh * Tsh / 2) - (ox.getW() / Tsh * Tsh / 2);
                                        float op7 = -ox.getH() / Tsh * Tsw / 2;
                                        float op8 = -ox.getH() / Tsh * Tsh / 2;

                                        float p1 = offx + op1;
                                        float p2 = offy + op2;
                                        float p3 = offx + op1 + op3;
                                        float p4 = offy + op2 - op4;
                                        float p5 = offx + op1 + op5;
                                        float p6 = offy + op2 + op6;
                                        float p7 = offx + op1 + op7;
                                        float p8 = offy + op2 + op8;

                                        sr.polygon(new float[] { p1, p2, p3, p4, p5, p6, p7, p8 });

                                    }
                                    // str1.draw(batch, j+"", 0, -j);

                                    break;
                            }

                        } else {
                            sr.rect(ox.getX(), ox.getYantingelag(Tsh) - ox.getH(), ox.getW(), ox.getH());

                        }

                    }
                }
            }
        }
        if (isFull3DMode) {
            sr.setTransformMatrix(IDT_MATRIX);
            Gdx.gl.glDepthMask(true);
        }
        sr.end();

    }

    public void drawObjectsInfo() {

        batch.setProjectionMatrix(isFull3DMode ? camFull3D.combined : (is3DMode ? cam3d.combined : cam.combined));
        batch.begin();
        if (isFull3DMode) {
            Gdx.gl.glDepthMask(false);
        }
        str1.getData().setScale(Tsw / 200f);
        if (layers.size() > 0) {
            for (int i = 0; i < layers.size(); i++) {
                if (layers.get(i).getType() == layer.Type.OBJECT && layers.get(i).isVisible()
                        && layers.get(i).getObjects().size() > 0) {
                    float layerZ = i * Tsh * 0.75f + 0.1f;
                    if (isFull3DMode) {
                        batch.setTransformMatrix(tmpTransformMatrix.setToTranslation(0, 0, layerZ));
                    } else {
                        batch.setTransformMatrix(IDT_MATRIX);
                    }

                    for (int j = 0; j < layers.get(i).getObjects().size(); j++) {

                        obj ox = layers.get(i).getObjects().get(j);

                        if (ox.getGid() != 0) {
                            int kyut = resolveTilesetIndexForGid(ox.getGid(), -1);
                            if (kyut < 0)
                                continue;

                            int localOx = (int) (stripTileGidFlags(ox.getGid()) - tilesets.get(kyut).getFirstgid());
                            int srcX = tilesets.get(kyut).getSrcX(localOx);
                            int srcY = tilesets.get(kyut).getSrcY(localOx);
                            int Tswa = tilesets.get(kyut).getTilewidth();
                            int Tsha = tilesets.get(kyut).getTileheight();

                            TextureRegion region = new TextureRegion(tilesets.get(kyut).getTexture(),
                                    srcX, srcY, Tswa,
                                    Tsha);
                            Sprite s = new Sprite(region);
                            // s.setX( ox.getX() );
                            // s.setY( ox.getYantingelag( Tsh ) - ox.getH());
                            s.setBounds(ox.getX(), ox.getYantingelag(Tsh), ox.getW(), ox.getH());

                            s.setOrigin(0, 0);
                            s.setRotation(360 - ox.getRotation());

                            // for RW ONLY
                            if (layers.get(i).getName().equalsIgnoreCase("UnitObjects")) {
                                if (s.getRotation() == 360 + 90) {
                                    s.rotate90(true);
                                }
                            }

                            // s.rotate90( false );
                            s.draw(batch);
                            // batch.draw(region, ox.getX(), ox.getYantingelag(Tsh) - ox.getH(),
                            // 0,ox.getH(),ox.getW(), ox.getH(),1,1, 360-ox.getRotation(),true);
                        }
                        String kucing = "";
                        if (ox.getName() != null)
                            kucing = ox.getName();
                        str1.getData().setScale(0.2f + Tsw / 160f);
                        float offx = 0, offy = 0;
                        int multiplier = 1;

                        if (orientation.equalsIgnoreCase("isometric")) {
                            multiplier = 2;
                            offx = (ox.getX() + (ox.getY()));// -ox.getY();
                            offy = (ox.getX() / 2f) + (-ox.getY() / 2f); // -ox.getY()*Tsh/2;
                        }
                        // draw object label
                        str1.getData().setScale(0.1f + Tsw / 160f);
                        str1.draw(batch, kucing, ox.getX() * multiplier - offx, ox.getYantingelag(Tsh) + 2 - offy);

                        if (ox.getShape() != null) {
                            switch (ox.getShape()) {
                                case "text":

                                    str1.getData().setScale(0.2f + Tsw / 160f);
                                    if (ox.getText() != null) {
                                        if (ox.isWrap()) {
                                            str1.draw(batch, ox.getText(), ox.getX() * multiplier - offx,
                                                    ox.getYantingelag(Tsh) - offy, ox.getW(),
                                                    com.badlogic.gdx.utils.Align.left, false);
                                        } else {
                                            str1.draw(batch, ox.getText(), ox.getX() * multiplier - offx,
                                                    ox.getYantingelag(Tsh) - offy);
                                        }
                                    }
                                    str1.getData().setScale(0.2f + Tsw / 160f);

                                    break;
                            }
                        }

                    }
                }
            }
        }
        str1.getData().setScale(1f);
        if (isFull3DMode) {
            batch.setTransformMatrix(IDT_MATRIX);
            Gdx.gl.glDepthMask(true);
        }
        batch.end();
    }

    @Override
    public void dispose() {
        clearPickerCaches();
        if (mapSaveExecutor != null)
            mapSaveExecutor.shutdown();
        if (mygame != null)
            mygame.dispose();
        if (decalBatch != null)
            decalBatch.dispose();
    }

    @Override
    public void resize(int width, int height) {
        if ("game".equals(kartu)) {
            mygame.resize(width, height);
            return;
        }

        // if (loadingfile) return;
        float tx, ty, tz;
        float tx1, ty1, tz1;
        float tx2, ty2, tz2;
        float tx3, ty3, tz3;

        tx = cam.position.x;
        ty = cam.position.y;
        tz = cam.position.z;
        tx1 = tilecam.position.x;
        ty1 = tilecam.position.y;
        tz1 = tilecam.position.z;
        tx3 = uicam.position.x;
        ty3 = uicam.position.y;
        tz3 = uicam.position.z;

        // cam = new OrthographicCamera(Gdx.graphics.getWidth(),
        // Gdx.graphics.getHeight());
        nssx = width;
        nssy = height;
        if (width > height) {
            stage = hstage;
            // stage.addActor(hstage.getRoot());
            cam.setToOrtho(false, ssy, ssx);
            tilecam.setToOrtho(false, ssy, ssx);
            uicam.setToOrtho(false, ssy, ssx);
            minicam.setToOrtho(false, ssy, ssx);
            tx3 = Tsw * Tw * 10f;
            ty3 = 0;
            tz3 = 0;

            landscape = true;
        } else {
            stage = vstage;
            // stage.addActor(vstage.getRoot());
            cam.setToOrtho(false, ssx, ssy);
            tilecam.setToOrtho(false, ssx, ssy);
            uicam.setToOrtho(false, ssx, ssy);
            minicam.setToOrtho(false, ssx, ssy);
            tx3 = 0;
            ty3 = -0;
            tz3 = 0;
            landscape = false;
        }
        stage.getViewport().setScreenSize(width, height);
        if ("stage".equals(kartu)) {
            // setMenuMap();
            gotoStage(lastStage);
            if (lastStage == tMenu || lastStage == tMap) {
                setMenuMap();
                gotoStage(tMenu);
            } else if (lastStage == tLinks) {
                setLinksMap();
                gotoStage(tLinks);
            } else if (lastStage == ttools) {
                setToolsMap();
                gotoStage(ttools);
            } else if (lastStage == tMirrorMenu) {
                setMirrorMap();
                gotoStage(tMirrorMenu);
            }

            // gotoStage(lastStage);
            // backToMap();
        } else {
            if (dialog != null) {
                dialog.hide();

            }
            if (startup != false) {

            }
            startup = true;

        }

        cam.position.set(tx, ty, tz);
        cam.update();
        tilecam.position.set(tx1, ty1, tz1);
        tilecam.update();
        recenterUI();
        resetMinimap();

    }

