    public void uidraw(Texture tx, gui gui, int margin, int srcx, int srcy, int srcw, int srch) {
        float x = 0, y = 0, w = 0, h = 0;
        if (landscape) {
            x = gui.getXl() + margin * 0.5f + 0.5f;
            y = gui.getYl() + margin + 1;
            w = gui.getWl() - margin * 0.5f - 0.5f;
            h = gui.getHl() - margin - 1;
        } else {
            x = gui.getX() + margin + 1;
            y = gui.getY() + margin;
            w = gui.getW() - margin - 1;
            h = gui.getH() - margin;
        }
        float roti = 0;
        boolean flipx = false, flipy = false;
        switch (rotate) {
            case 0:// "20"://diagonal flip
                roti = 0;
                flipx = false;
                flipy = false;
                break;
            case 1:// "40"://flipy
                roti = 270f;
                flipx = false;
                flipy = false;
                break;
            case 2:// "60"://270 degrees clockwise
                roti = 180f;
                flipx = false;
                flipy = false;
                break;
            case 3:// "80"://flipx
                roti = 90f;
                flipx = false;
                flipy = false;
                break;
            case 4:// "A0"://90 degress cw
                roti = 0f;
                flipx = true;
                flipy = false;
                break;
            case 5:// "C0"://180 degrees cw
                roti = 270f;
                flipx = true;
                flipy = false;
                break;
            case 6://
                roti = 180f;
                flipx = true;
                flipy = false;
                break;
            case 7://
                roti = 90f;
                flipx = true;
                flipy = false;
                break;
        }

        if (!landscape) {
            ui.draw(tx, x / 100 * ssx, y / 100 * ssy, (w - x) / 100 * ssx / 2, (h - y) / 100 * ssy / 2,
                    (w - x) / 100 * ssx, (h - y) / 100 * ssy, 1, 1, roti, srcx, srcy, srcw, srch, flipx, flipy);
        } else {
            ui.draw(tx, x / 100 * ssy, y / 100 * ssx, (w - x) / 100 * ssy / 2, (h - y) / 100 * ssx / 2,
                    (w - x) / 100 * ssy, (h - y) / 100 * ssx, 1, 1, roti, srcx, srcy, srcw, srch, flipx, flipy);
        }

    }

