    Pixmap pbg, pts;
    java.util.List<Color> tscolor;

    private void traceBackground() {
        if (background == null) {
            return;
        }

        pbg = new Pixmap(background.getWidth(), background.getHeight(), Pixmap.Format.RGBA8888);
        pbg = pixmapfromtexture(background, "ff00ff");
        pbg = resizepixmap(pbg, Tw * Tsw, Th * Tsh);
        pts = tilesets.get(seltset).getPixmap();

        tileset tts = tilesets.get(seltset);
        tscolor = new ArrayList<Color>();

        for (int yy = 0; yy < tts.getHeight(); yy++) {
            for (int xx = 0; xx < tts.getWidth(); xx++) {

                float tcell = 0;
                float rr = 0, gg = 0, bb = 0, aa = 0;

                for (int j = 0; j < tts.getTileheight(); j++) {
                    for (int i = 0; i < tts.getTilewidth(); i++) {
                        Color tc = new Color(pts.getPixel(xx * tts.getTilewidth() + i, yy * tts.getTileheight() + j));
                        // if (tc.a >0){
                        tcell++;
                        rr += tc.r;
                        gg += tc.g;
                        bb += tc.b;
                        aa += tc.a;

                        // }

                    }
                }
                // if (aa/tcell<0.5f) continue;
                Color tc = new Color(rr / tcell, gg / tcell, bb / tcell, 0);
                tscolor.add(tc);

            }
        }

        for (int x = 0; x < Tw; x++) {
            for (int y = 0; y < Th; y++) {
                traceCell(x, y);
            }
        }
        // background.dispose();
        // background=null;
        resetCaches();

    }

    private void traceCell(int x, int y) {
        // Color bg = new Color(pbg.getPixel( x,y ));
        float tcell = 0;
        float rr = 0, gg = 0, bb = 0, aa = 0;
        for (int i = 0; i < Tsw; i++) {
            for (int j = 0; j < Tsh; j++) {
                Color tc = new Color(pbg.getPixel((int) (x * Tsw) + i, (int) (y * Tsh) + j));
                // if (tc.a >0){
                tcell++;
                rr += tc.r;
                gg += tc.g;
                bb += tc.b;
                aa += tc.a;
                // }

            }
        }
        // if (aa/tcell<0.5f) return;
        Color bg = new Color(rr / tcell, gg / tcell, bb / tcell, 0);

        long cnum = 0;
        float cnumdiff = 999999;

        tileset tts = tilesets.get(seltset);
        for (int xx = 0; xx < tts.getWidth(); xx++) {
            for (int yy = 0; yy < tts.getHeight(); yy++) {

                Color tc = tscolor.get(yy * tts.getWidth() + xx);

                float rdiff = Math.abs(tc.r - bg.r) + Math.abs(tc.g - bg.g) + Math.abs(tc.b - bg.b);
                if (rdiff < cnumdiff) {
                    cnumdiff = rdiff;
                    cnum = (long) tts.getFirstgid() + (yy * tts.getWidth() + xx);
                }
            }
        }

        layers.get(selLayer).getStr().set(y * Tw + x, cnum);
        layers.get(selLayer).getTset().set(y * Tw + x, seltset);

    }

    private int findLayer(String name) {
        if (layers.size() == 0)
            return -1;
        for (int i = 0; i < layers.size(); i++) {
            layer l = layers.get(i);
            if (l.getName().equalsIgnoreCase(name)) {
                return i;
            }
        }
        return -1;
    }

    private boolean isEdge(int num, long spr, List<Long> sprs) {
        if (num % Tw != 0) {
            if (sprs.get(num - 1) != spr)
                return true;
        }
        if (num % Tw != Tw - 1) {
            if (sprs.get(num + 1) != spr)
                return true;
        }
        if (num / Tw != 0) {
            if (sprs.get(num - Tw) != spr)
                return true;
        }
        if (num / Tw != Th - 1) {
            if (sprs.get(num + Tw) != spr)
                return true;
        }
        return false;
    }

    private void generateMap() {
        generateMapWithParams();
    }

    private void generateMapWithParams() {
        activetool = 4;
        eraser = false;

        int p2 = 5;// Integer.parseInt(fgencount.getText());
        int p3 = 5;// Integer.parseInt(fbirthlim.getText());
        int p4 = 3;// Integer.parseInt(fdeathlim.getText());
        int p1 = (int) slfirstgen.getValue();// Float.parseFloat(ffirstgen.getText());
        if (flivestr.getText().equalsIgnoreCase(""))
            flivestr.setText("0");
        if (fdeadstr.getText().equalsIgnoreCase(""))
            fdeadstr.setText("0");
        int genType = sbGenerate.getSelectedIndex();
        long p5 = Long.parseLong(flivestr.getText());
        long p7 = Long.parseLong(fdeadstr.getText());
        if (getTsetFromSpr((int) p5) == -1)
            p5 = 0;
        if (getTsetFromSpr((int) p7) == -1)
            p7 = 0;
        int groundlayer = -1, itemslayer = -1, unitslayer = -1;
        int poolspr = -1;

        groundlayer = findLayer("ground");
        itemslayer = findLayer("items");
        unitslayer = findLayer("units");

        // cache the curtset & sellayer
        int mytset = curtset;
        int mylayer = selLayer;
        List<Long> sprs = new ArrayList<>();

        // if no ground layer, the random map will be drawn on the current layer
        if (groundlayer != -1)
            selLayer = groundlayer;

        int tset1 = -1;
        if (p5 != 0)
            tset1 = getTsetFromSpr((int) p5);
        int tset2 = -1;
        if (p7 != 0)
            tset2 = getTsetFromSpr((int) p7);
        boolean singles = false;
        if (tset1 == -1 || tset2 == -1)
            singles = true;
        curpickAuto = true;

        layers.get(selLayer).clearLayer();

        if (genType == 0) {
            // use perlin noise to draw cool map
            PerlinNoiseGenerator pn = new PerlinNoiseGenerator();
            float[][] pgn = pn.generatePerlinNoise(Tw, Th, p1);
            int fx = 0, fy = 0;
            for (float[] eachRow : pgn) {
                fy = 0;
                for (float j : eachRow) {
                    if (j <= 0.5f) {
                        curtset = tset1;
                        if (p5 != 0)
                            tapTile(fy * Tw + fx, true, false, false, (int) p5);
                    } else {
                        curtset = tset2;
                        if (p7 != 0)
                            tapTile(fy * Tw + fx, true, false, false, (int) p7);
                    }
                    fy++;
                }
                fx++;
            }
            for (Long l : layers.get(selLayer).getStr()) {
                sprs.add(l);
            }

            fx = 0;
            fy = 0;
            for (float[] eachRow : pgn) {
                fy = 0;
                for (float j : eachRow) {
                    if (j <= 0.5f) {
                        curtset = tset1;
                        if (p5 != 0 && singles && isEdge(fy * Tw + fx, p7, sprs)) {
                            tapTile(fy * Tw + fx, true, true, false, (int) p5);
                        }
                    } else {
                        curtset = tset2;
                        if (p7 != 0 && isEdge(fy * Tw + fx, p7, sprs)) {
                            tapTile(fy * Tw + fx, true, true, false, (int) p7);
                            // tapTile(fy * Tw + fx, true, false, false, (int) 14);
                        }
                    }
                    fy++;
                }
                fx++;
            }

            // Dungeon & Maze
        } else if (genType == 1 || genType == 2) {
            // default to dungeon
            int attempt = 500, maxroom = 15, minroom = 13, tolerance = 5;
            if (genType == 2) {
                attempt = 500;
                maxroom = 3;
                minroom = 1;
                tolerance = 5;
            }
            final Grid grid = new Grid(Tw, Th); // This algorithm likes odd-sized maps, although it works either way.

            final DungeonGenerator dungeonGenerator = new DungeonGenerator();
            dungeonGenerator.setRoomGenerationAttempts(attempt);
            dungeonGenerator.setMaxRoomSize(maxroom);
            dungeonGenerator.setTolerance(tolerance); // Max difference between width and height.
            dungeonGenerator.setMinRoomSize(minroom);
            dungeonGenerator.generate(grid);

            for (int x = 0; x < grid.getWidth(); x++) {
                for (int y = 0; y < grid.getHeight(); y++) {
                    if (grid.get(x, y) <= 0.5f) {
                        curtset = tset2;
                        if (p7 != 0)
                            tapTile(y * Tw + x, true, false, false, (int) p7);
                    } else {
                        curtset = tset1;
                        if (p5 != 0)
                            tapTile(y * Tw + x, true, false, false, (int) p5);
                    }
                }
            }
            for (Long l : layers.get(selLayer).getStr()) {
                sprs.add(l);
            }
            for (int x = 0; x < grid.getWidth(); x++) {
                for (int y = 0; y < grid.getHeight(); y++) {
                    if (grid.get(x, y) <= 0.5f) {
                        curtset = tset2;
                        // if (p7!=0 && isEdge(y*Tw+x,p7,sprs)) tapTile(y*Tw+x,true,false,false,(int)
                        // 14);
                        if (p7 != 0 && isEdge(y * Tw + x, p7, sprs))
                            tapTile(y * Tw + x, true, true, false, (int) p7);
                    } else {
                        curtset = tset1;
                        if (p5 != 0 && singles && isEdge(y * Tw + x, p5, sprs))
                            tapTile(y * Tw + x, true, true, false, (int) p5);
                    }
                }
            }

        }
        // Cavern
        else if (genType == 3) {
            final Grid grid = new Grid(Tw, Th); // This algorithm likes odd-sized maps, although it works either way.

            final CellularAutomataGenerator cellularGenerator = new CellularAutomataGenerator();
            cellularGenerator.setAliveChance(0.5f);
            cellularGenerator.setRadius(2);
            cellularGenerator.setBirthLimit(13);
            cellularGenerator.setDeathLimit(9);
            cellularGenerator.setIterationsAmount(6);
            cellularGenerator.generate(grid);

            for (int x = 0; x < grid.getWidth(); x++) {
                for (int y = 0; y < grid.getHeight(); y++) {
                    if (grid.get(x, y) > 0.5f) {
                        curtset = tset2;
                        if (p7 != 0)
                            tapTile(y * Tw + x, true, false, false, (int) p7);
                    } else {
                        curtset = tset1;
                        if (p5 != 0)
                            tapTile(y * Tw + x, true, false, false, (int) p5);
                    }

                }
            }
            for (Long l : layers.get(selLayer).getStr()) {
                sprs.add(l);
            }
            for (int x = 0; x < grid.getWidth(); x++) {
                for (int y = 0; y < grid.getHeight(); y++) {
                    if (grid.get(x, y) > 0.5f) {
                        curtset = tset2;
                        // if (p7!=0 && isEdge(y*Tw+x,p7,sprs)) tapTile(y * Tw + x, true, false, false,
                        // (int) 14);
                        if (p7 != 0 && isEdge(y * Tw + x, p7, sprs))
                            tapTile(y * Tw + x, true, true, false, (int) p7);
                    } else {
                        curtset = tset1;
                        if (p5 != 0 && singles && isEdge(y * Tw + x, p5, sprs))
                            tapTile(y * Tw + x, true, true, false, (int) p5);
                    }

                }
            }

        }

        else if (genType == 4) {
            //////
            // this is the basis of random map, does not matter RW or not.
            if (p7 != 0) {
                for (int cl = 0; cl < Tw * Th; cl++) {
                    tapTile(cl, true, false, false, (int) p7);
                }
            }

        }

        // RESOURCE POOLS
        if (groundlayer != -1 && itemslayer != -1) {
            selLayer = itemslayer;

            // clear the data
            layers.get(selLayer).clearLayer();

            // get the data for pool
            mainloop: for (tileset t : tilesets) {
                for (tile tt : t.getTiles()) {
                    for (property p : tt.getProperties()) {
                        if (p.getName().equalsIgnoreCase("res_pool")) {
                            poolspr = tt.getTileID() + t.getFirstgid();
                            curtset = getTsetFromSpr(poolspr);
                            break mainloop;
                        }
                    }
                }
            }

            if (poolspr != -1) {
                // generate res pool
                DiskGenerator dg = new DiskGenerator(Tw, Th, 20, 8);
                List<Point> lp = dg.generate();
                List<Point> ln = new ArrayList<>();
                for (Point p : lp) {
                    if (p.getX() <= 1)
                        continue;
                    if (p.getY() <= 1)
                        continue;
                    if (p.getX() >= Tw - 2)
                        continue;
                    if (p.getY() >= Th - 2)
                        continue;
                    List<Integer> nums = new ArrayList<>();
                    int num = p.getX() + p.getY() * Tw;
                    nums.add(num);
                    nums.add(num + 1);
                    nums.add(num - 1);
                    nums.add(num + Tw);
                    nums.add(num - Tw);
                    nums.add(num + Tw - 1);
                    nums.add(num - Tw - 1);
                    nums.add(num + Tw + 1);
                    nums.add(num - Tw + 1);

                    boolean cont = true;
                    for (int numa : nums) {
                        if (layers.get(groundlayer).getTile().get(numa) != -1) {
                            layer l = layers.get(groundlayer);
                            if (tilesets.get(l.getTset().get(numa)).getTiles().get(l.getTile().get(numa))
                                    .getProperties().size() > 0) {
                                cont = false;
                                break;
                            }
                        }
                    }
                    if (cont)
                        ln.add(p);
                }

                for (Point p : ln) {
                    int num = p.getX() + p.getY() * Tw;
                    tapTile(num, false, true, false, poolspr);
                }

            }

        }

        if (groundlayer != -1 && itemslayer != -1 && unitslayer != -1) {
            selLayer = unitslayer;

            // clear the data
            layers.get(selLayer).clearLayer();

            // get bases data
            List<Integer> bases = new ArrayList<>();
            List<Integer> builders = new ArrayList<>();

            for (tileset t : tilesets) {
                for (tile tt : t.getTiles()) {
                    boolean isabase = false, isplayer = false, isabuilder = false;
                    for (property p : tt.getProperties()) {
                        if (p.getName().equalsIgnoreCase("unit") && p.getValue().equalsIgnoreCase("commandCenter")) {
                            isabase = true;
                        }
                        if (p.getName().equalsIgnoreCase("unit") && p.getValue().equalsIgnoreCase("builder")) {
                            isabuilder = true;
                        }
                        if (p.getName().equalsIgnoreCase("team") && !p.getValue().equalsIgnoreCase("-1")) {
                            isplayer = true;
                        }
                    }
                    if (isabase && isplayer)
                        bases.add(tt.getTileID() + t.getFirstgid());
                    if (isabuilder && isplayer)
                        builders.add(tt.getTileID() + t.getFirstgid());
                }
            }

            // generate bases
            // create all possible location
            DiskGenerator dg = new DiskGenerator(Tw, Th, 5, 4);
            List<Point> lp = dg.generate();
            List<Point> ln = new ArrayList<>();

            // remove unwanted location
            for (Point p : lp) {
                if (p.getX() <= 5)
                    continue;
                if (p.getY() <= 5)
                    continue;
                if (p.getX() >= Tw - 5)
                    continue;
                if (p.getY() >= Th - 5)
                    continue;
                List<Integer> nums = new ArrayList<>();
                int num = p.getX() + p.getY() * Tw;
                nums.add(num);
                nums.add(num + 1);
                nums.add(num - 1);
                nums.add(num + Tw);
                nums.add(num - Tw);
                nums.add(num + Tw - 1);
                nums.add(num - Tw - 1);
                nums.add(num + Tw + 1);
                nums.add(num - Tw + 1);
                nums.add(num + Tw + Tw);

                boolean cont = true;
                for (int numa : nums) {
                    // if there is a property in the ground layer, it means that it is not placable
                    // by buildings.
                    if (layers.get(groundlayer).getTile().get(numa) != -1) {
                        layer l = layers.get(groundlayer);
                        if (tilesets.get(l.getTset().get(numa)).getTiles().get(l.getTile().get(numa)).getProperties()
                                .size() > 0) {
                            cont = false;
                            break;
                        }
                    }
                    // if there is anything in the items layer, it should not be stacked.
                    if (layers.get(itemslayer).getStr().get(numa) != 0) {
                        cont = false;
                        break;
                    }
                }
                if (cont)
                    ln.add(p);
            }

            // randomise
            Collections.shuffle(ln);
            int count = 0;
            int maxPlayers = 10;
            int space = 50;
            int wide = 6;
            int pool = 10;
            for (Point p : ln) {
                if (count >= maxPlayers)
                    break;
                int num = p.getX() + p.getY() * Tw;

                // check if there is another base nearby
                boolean tooclose = false;
                int cleft = p.getX() - space;
                if (cleft < 0)
                    cleft = 0;
                int cright = p.getX() + space;
                if (cright > Tw - 1)
                    cright = Tw - 1;
                int ctop = p.getY() - space;
                if (ctop < 0)
                    ctop = 0;
                int cbottom = p.getY() + space;
                if (cbottom > Th - 1)
                    cbottom = Th - 1;
                for (int px = cleft; px <= cright; px++) {
                    for (int py = ctop; py <= cbottom; py++) {
                        if (layers.get(unitslayer).getStr().get(py * Tw + px) != 0) {
                            tooclose = true;
                            break;
                        }
                    }
                    if (tooclose)
                        break;
                }
                if (tooclose)
                    continue;

                // check if the base area is big enough
                boolean toosmall = false;
                cleft = p.getX() - wide;
                if (cleft < 0)
                    cleft = 0;
                cright = p.getX() + wide;
                if (cright > Tw - 1)
                    cright = Tw - 1;
                ctop = p.getY() - wide;
                if (ctop < 0)
                    ctop = 0;
                cbottom = p.getY() + wide;
                if (cbottom > Th - 1)
                    cbottom = Th - 1;
                for (int px = cleft; px <= cright; px++) {
                    for (int py = ctop; py <= cbottom; py++) {
                        layer l = layers.get(groundlayer);
                        int numa = py * Tw + px;
                        if (l.getTile().get(numa) != -1) {
                            if (tilesets.get(l.getTset().get(numa)).getTiles().get(l.getTile().get(numa))
                                    .getProperties().size() > 0) {
                                toosmall = true;
                                break;
                            }
                        }
                    }
                    if (toosmall)
                        break;
                }
                if (toosmall)
                    continue;

                // check if the base area contain at least one res pool
                if (poolspr != -1) {
                    boolean respool = false;
                    cleft = p.getX() - pool;
                    if (cleft < 0)
                        cleft = 0;
                    cright = p.getX() + pool;
                    if (cright > Tw - 1)
                        cright = Tw - 1;
                    ctop = p.getY() - pool;
                    if (ctop < 0)
                        ctop = 0;
                    cbottom = p.getY() + pool;
                    if (cbottom > Th - 1)
                        cbottom = Th - 1;
                    for (int px = cleft; px <= cright; px++) {
                        for (int py = ctop; py <= cbottom; py++) {
                            if (layers.get(itemslayer).getStr().get(py * Tw + px) == poolspr) {
                                respool = true;
                                break;
                            }
                        }
                        if (respool)
                            break;
                    }
                    if (!respool)
                        continue;
                }

                curtset = getTsetFromSpr(bases.get(count));
                tapTile(num, false, true, false, bases.get(count));
                tapTile(num + Tw * 3, false, true, false, builders.get(count));
                count++;
            }

        }

        curtset = mytset;
        selLayer = mylayer;

    }

    private void startAiPixelGeneration() {
        if (aiGenerating)
            return;
        if (!isPixelArtMap()) {
            msgbox(z.aipixelonly != null ? z.aipixelonly : "AI sprite generation is for Pixel Editor maps only.");
            return;
        }
        if (selLayer < 0 || selLayer >= layers.size()
                || layers.get(selLayer).getType() != layer.Type.TILE) {
            msgbox(z.aipixellayer != null ? z.aipixellayer : "Select a tile layer to draw on.");
            return;
        }
        if (aiApiKey == null || aiApiKey.trim().isEmpty()) {
            msgbox(z.ainokey != null ? z.ainokey : "Set your AI API key in Preferences first.");
            return;
        }
        if (Tw * Th > 32 * 32) {
            msgbox(z.aicanvaslarge != null ? z.aicanvaslarge
                    : "Large canvas — AI works best at 16x16 or 32x32. Results may vary.");
        }
        int palIdx = getPixelArtPaletteIndex();
        ensureTilesetPixmap(tilesets.get(palIdx));
        final PixelPaletteInfo palette = PixelPaletteInfo.build(tilesets, palIdx, pixelPaletteUsedCount, Tw, Th);
        if (!palette.isReady()) {
            msgbox(z.aipaletteempty != null ? z.aipaletteempty : "Pixel palette is not ready.");
            return;
        }
        final String prompt = fAiPrompt.getText();
        final int targetLayer = selLayer;
        layer active = layers.get(targetLayer);
        String snapshot = null;
        aiRefineSteps.clear();

        aiGenerating = true;
        status(z.aigenerating != null ? z.aigenerating : "Generating...", 0);
        AiPixelDrawingService.requestPixel(aiApiKey, aiApiUrl, aiModel, prompt, palette, snapshot, aiRefineSteps,
                new AiPixelDrawingService.Listener() {
                    @Override
                    public void onSuccess(int[][] grid, boolean fullReplace) {
                        aiGenerating = false;
                        applyAiPixelDraw(grid, fullReplace, palette, targetLayer, prompt);
                    }

                    @Override
                    public void onPartial(int[][] grid, boolean fullReplace) {
                        layer l = layers.get(targetLayer);
                        if (fullReplace)
                            l.clearLayer();
                        for (int y = 0; y < Th; y++) {
                            for (int x = 0; x < Tw; x++) {
                                int idx = y * Tw + x;
                                int slot = grid[y][x];
                                long gid = palette.slotToGid(slot);
                                int tset = gid == 0 ? -1 : palette.paletteTsetIndex;
                                l.getStr().set(idx, gid);
                                l.getTset().set(idx, tset);
                                l.getTile().set(idx, -1);
                            }
                        }
                        resetCaches();
                    }

                    @Override
                    public void onFailure(String message) {
                        aiGenerating = false;
                        String err = z.aierror != null ? z.aierror : "AI generation failed";
                        if (message != null && message.length() > 300) {
                            message = message.substring(0, 300) + "... (truncated)";
                        }
                        msgbox(err + "\n" + message);
                        status("", 0);
                    }
                });
    }

    private boolean activeLayerHasPixels(layer l) {
        if (l == null || l.getStr() == null)
            return false;
        for (Long g : l.getStr()) {
            if (g != null && g != 0)
                return true;
        }
        return false;
    }

    private void applyAiPixelDraw(final int[][] grid, final boolean fullReplace, PixelPaletteInfo palette,
            int targetLayer, String userPrompt) {
        Gdx.app.postRunnable(new Runnable() {
            @Override
            public void run() {
                boolean any = false;
                for (int y = 0; y < Th && !any; y++)
                    for (int x = 0; x < Tw && !any; x++)
                        if (grid[y][x] != 0)
                            any = true;
                if (!any) {
                    msgbox(z.aierror != null ? z.aierror : "AI returned no pixels");
                    status("", 0);
                    return;
                }

                layer l = layers.get(targetLayer);

                if (fullReplace)
                    l.clearLayer();

                // Bulk-write pixels directly to layer arrays (no per-pixel undo/cache)
                for (int y = 0; y < Th; y++) {
                    for (int x = 0; x < Tw; x++) {
                        int idx = y * Tw + x;
                        int slot = grid[y][x];
                        long gid = palette.slotToGid(slot);
                        int tset = gid == 0 ? -1 : palette.paletteTsetIndex;
                        l.getStr().set(idx, gid);
                        l.getTset().set(idx, tset);
                        l.getTile().set(idx, -1);
                    }
                }

                // Single undo clear + cache rebuild instead of per-pixel
                undolayer.clear();
                redolayer.clear();
                resetCaches();

                if (userPrompt != null && !userPrompt.trim().isEmpty())
                    aiRefineSteps.add(userPrompt.trim());
                if (fAiPrompt != null)
                    fAiPrompt.setText("");
                status(z.aigenerated != null ? z.aigenerated : "AI sprite generated", 3);
                backToMap();
            }
        });
    }

