    private void updateReplaceRangeLabel() {
        if (lReplaceRange == null)
            return;
        if (cbReplaceRangeLimit == null || !cbReplaceRangeLimit.isChecked() || replaceRangeMaxX < 0) {
            lReplaceRange.setText(z.replacerangenone != null ? z.replacerangenone : "Whole map");
        } else {
            lReplaceRange.setText("X " + replaceRangeMinX + "-" + replaceRangeMaxX + ", Y " + replaceRangeMinY + "-"
                    + replaceRangeMaxY);
        }
    }

    private boolean replaceTileInRange(int cellIdx) {
        int x = cellIdx % Tw;
        int y = cellIdx / Tw;
        return x >= replaceRangeMinX && x <= replaceRangeMaxX && y >= replaceRangeMinY && y <= replaceRangeMaxY;
    }

    private int mapTileAtScreen(float screenX, float screenY) {
        Vector3 touch = new Vector3();
        unprojectMain(touch.set(screenX, screenY, 0));
        return mapTileAtWorld(touch.x, touch.y);
    }

    private boolean beginReplaceRangeDrag(float screenX, float screenY) {
        if (!replaceRangePicking || !kartu.equals("world"))
            return false;
        int cell = mapTileAtScreen(screenX, screenY);
        if (cell < 0)
            return false;
        roll = true;
        activetool = 0;
        usetool = true;
        touched = true;
        mapstartSelect = cell;
        mapendSelect = cell;
        mapinitialSelect = cell;
        mapfinalSelect = cell;
        return true;
    }

    private void startReplaceRangePick() {
        if (Tw <= 0 || Th <= 0)
            return;
        replaceRangePicking = true;
        replaceRangeSavedTool = activetool;
        activetool = 0;
        stage.clear();
        Gdx.input.setInputProcessor(im);
        kartu = "world";
        status(z.replacerangepick != null ? z.replacerangepick : "Drag on map to set range", 3);
    }

    private void finishReplaceRangePick() {
        if (!replaceRangePicking)
            return;
        replaceRangePicking = false;
        roll = false;
        activetool = replaceRangeSavedTool;

        int x1 = mapstartSelect % Tw;
        int y1 = mapstartSelect / Tw;
        int x2 = mapendSelect % Tw;
        int y2 = mapendSelect / Tw;
        replaceRangeMinX = Math.min(x1, x2);
        replaceRangeMaxX = Math.max(x1, x2);
        replaceRangeMinY = Math.min(y1, y2);
        replaceRangeMaxY = Math.max(y1, y2);
        if (cbReplaceRangeLimit != null)
            cbReplaceRangeLimit.setChecked(true);
        updateReplaceRangeLabel();
        gotoStage(treplacetiles);
    }

    private void replacetiles(long p1, long p3, int p4, boolean allLayers, boolean useRange) {
        if (layers.isEmpty())
            return;
        if (!allLayers && layers.get(selLayer).getType() != layer.Type.TILE)
            return;

        int savedLayer = selLayer;
        curtset = p4;
        activetool = 4;
        eraser = false;
        long fromGid = stripTileGidFlags(p1);
        long toGid = p3;

        int layerStart = allLayers ? 0 : selLayer;
        int layerEnd = allLayers ? layers.size() - 1 : selLayer;

        for (int li = layerStart; li <= layerEnd; li++) {
            if (layers.get(li).getType() != layer.Type.TILE)
                continue;
            selLayer = li;

            for (int i = 0; i < layers.get(li).getStr().size(); i++) {
                if (useRange && !replaceTileInRange(i))
                    continue;
                long prev = layers.get(li).getStr().get(i);
                if (stripTileGidFlags(prev) == fromGid) {
                    tapTile(i, true, false, false, (int) toGid);
                }
            }
        }

        curpickAuto = true;
        for (int li = layerStart; li <= layerEnd; li++) {
            if (layers.get(li).getType() != layer.Type.TILE)
                continue;
            selLayer = li;
            List<Long> sprs = new ArrayList<>();
            for (Long l : layers.get(li).getStr()) {
                sprs.add(l);
            }
            for (int i = 0; i < layers.get(li).getStr().size(); i++) {
                if (useRange && !replaceTileInRange(i))
                    continue;
                if (stripTileGidFlags(sprs.get(i)) == stripTileGidFlags(toGid) && isEdge(i, toGid, sprs)) {
                    tapTile(i, true, true, false, (int) toGid);
                }
            }
        }
        selLayer = savedLayer;
    }

    private void exporttolua(String filenamenya) {
        StringBuilderPlus sb = new StringBuilderPlus();

        sb.wlo("return{");
        sb.wl("version = \"1.2\",");
        sb.wl("luaversion = \"5.1\",");
        sb.wl("tiledversion = \"1.2.3\",");
        sb.wl("orientation = \"" + orientation + "\",");
        sb.wl("renderorder = \"" + renderorder + "\",");
        sb.wl("width = " + Tw + ",");
        sb.wl("height = " + Th + ",");
        sb.wl("tilewidth = " + Tsw + ",");
        sb.wl("tileheight = " + Tsh + ",");
        sb.wl("nextlayerid = " + (1 + layers.size()) + ",");
        sb.wl("nextobjectid = " + exportNextObjectId() + ",");
        sb.wprop(properties);

        sortAllTilesetTileMetadata();
        sb.wlo("tilesets = {");
        for (int n = 0; n < tilesets.size(); n++) {
            tileset t = tilesets.get(n);
            sb.wlo("{");// tileset inside
            sb.wl("name = \"" + StringBuilderPlus.luaString(t.getName()) + "\",");
            sb.wl("firstgid = " + t.getFirstgid() + ",");
            sb.wl("tilewidth = " + t.getTilewidth() + ",");
            sb.wl("tileheight = " + t.getTileheight() + ",");
            sb.wl("spacing = " + t.getSpacing() + ",");
            sb.wl("margin = " + t.getMargin() + ",");
            sb.wl("columns = " + t.getColumns() + ",");
            sb.wl("tilecount = " + t.getTilecount() + ",");
            sb.wl("image = \"" + StringBuilderPlus.luaString(t.getSource()) + "\",");
            sb.wl("imagewidth = " + t.getOriginalwidth() + ",");
            sb.wl("imageheight = " + t.getOriginalheight() + ",");
            sb.wl("tileoffset = {\n        x = 0,\n        y = 0\n      },");
            sb.wl("grid = {\n        orientation = \"" + orientation + "\",\n        width = " + Tsw
                    + ", \n        height = " + Tsh + "\n      },");
            sb.wprop(tilesets.get(n).getProperties());
            sb.wl("terrains = {},");

            if (tilesets.get(n).getTiles().size() != 0) {
                sb.wlo("tiles = {");// tiles
                for (int m = 0; m < tilesets.get(n).getTiles().size(); m++) {
                    tile tt = tilesets.get(n).getTiles().get(m);
                    sb.wlo("{");// tile
                    sb.wl("id = " + tt.getTileID() + ",");
                    sb.wprop(tt.getProperties());

                    if (tt.getAnimation().size() > 0) {
                        sb.wlo("animation = {");
                        for (int am = 0; am < tt.getAnimation().size(); am++) {
                            sb.wlo("{");
                            sb.wl("tileid = " + tt.getAnimation().get(am).getTileID() + ",");
                            sb.wl("duration = " + tt.getAnimation().get(am).getDuration());

                            if (am != tt.getAnimation().size() - 1) {
                                sb.wlc("},");
                            } else {
                                sb.wlc("}");
                            }
                        }
                        sb.wlc("}");
                    }

                    if (m != tilesets.get(n).getTiles().size() - 1) {
                        sb.wlc("},");
                    } else {
                        sb.wlc("}");
                    }
                }
                sb.wlc("}");
            } else {
                sb.wl("tiles = {}");
            }

            if (n != tilesets.size() - 1) {
                sb.wlc("},");// tileset inside
            } else {
                sb.wlc("}");// tileset inside
            }
        }
        sb.wlc("},"); // tileset;

        sb.wlo("layers = {");// layers

        int exportedLayers = 0;
        for (int n = 0; n < layers.size(); n++) {
            layer.Type layerType = layers.get(n).getType();
            if (layerType != layer.Type.TILE && layerType != layer.Type.OBJECT)
                continue;
            exportedLayers++;
        }

        int exportedLayerIndex = 0;
        for (int n = 0; n < layers.size(); n++) {
            if (layers.get(n).getType() == layer.Type.TILE) {
                layer l = layers.get(n);
                sb.wlo("{");// tile layer
                sb.wl("type = \"tilelayer\",");
                sb.wl("id = " + (n + 1) + ",");
                sb.wl("name = \"" + StringBuilderPlus.luaString(l.getName()) + "\",");
                sb.wl("x = 0,");
                sb.wl("y = 0,");
                sb.wl("width = " + Tw + ",");
                sb.wl("height = " + Th + ",");
                sb.wl("visible = " + l.isVisible() + ",");

                if (l.getOpacity() == 0) {
                    sb.wl("opacity = 1,");
                } else {
                    sb.wl("opacity = " + l.getOpacity() + ",");
                }

                sb.wl("offsetx = 0,");
                sb.wl("offsety = 0,");
                sb.wprop(layers.get(n).getProperties());
                sb.wl("encoding = \"lua\",");
                sb.wlo("data = {");

                for (int k = 0; k < Th; k++) {
                    sb.w("        ");
                    for (int j = 0; j < Tw; j++) {
                        sb.append(l.getStr().get(k * Tw + j));
                        if (!(k == Th - 1 && j == Tw - 1))
                            sb.append(", ");
                    }
                    sb.wl("");
                }
                sb.wlc("}");// data

            } else if (layers.get(n).getType() == layer.Type.OBJECT) {
                layer l = layers.get(n);
                sb.wlo("{");// object layer
                sb.wl("type = \"objectgroup\",");
                sb.wl("id = " + (n + 1) + ",");
                sb.wl("name = \"" + StringBuilderPlus.luaString(l.getName()) + "\",");
                sb.wl("visible = " + l.isVisible() + ",");
                if (l.getOpacity() == 0) {
                    sb.wl("opacity = 1,");
                } else {
                    sb.wl("opacity = " + l.getOpacity() + ",");
                }
                sb.wl("offsetx = 0,");
                sb.wl("offsety = 0,");
                sb.wl("draworder = \"topdown\",");
                sb.wprop(l.getProperties());

                if (l.getObjects().size() > 0) {
                    sb.wlo("objects = {");
                    for (int ao = 0; ao < l.getObjects().size(); ao++) {
                        obj oo = l.getObjects().get(ao);
                        sb.wlo("{");
                        sb.wl("id = " + oo.getId() + ",");
                        sb.wl("name = \"" + StringBuilderPlus.luaString(oo.getName()) + "\",");
                        sb.wl("type = \"" + StringBuilderPlus.luaString(oo.getType()) + "\",");
                        if (oo.getGid() != 0) {
                            sb.wl("gid = " + oo.getGid() + ",");
                        }
                        if (oo.getShape().equals("")) {
                            sb.wl("shape = \"rectangle\",");

                        } else {
                            sb.wl("shape = \"" + StringBuilderPlus.luaString(oo.getShape()) + "\",");
                        }
                        sb.wl("x = " + oo.getX() + ",");
                        sb.wl("y = " + oo.getY() + ",");

                        if (oo.getShape().equalsIgnoreCase("point")) {
                            sb.wl("width = 0,");
                            sb.wl("height = 0,");

                        } else {
                            sb.wl("width = " + oo.getW() + ",");
                            sb.wl("height = " + oo.getH() + ",");

                        }
                        sb.wl("rotation = " + oo.getRotation() + ",");
                        sb.wl("visible = true,");
                        if (oo.getShape().equalsIgnoreCase("ellipse")) {
                            sb.wl("ellipse = true,");
                        }
                        if (oo.getShape().equalsIgnoreCase("polygon") || oo.getShape().equalsIgnoreCase("polyline")) {
                            sb.wlo(oo.getShape() + " = {");
                            for (int ok = 0; ok < oo.getPoints().size(); ok++) {
                                float xar = oo.getPoints().get(ok).x;
                                float yar = oo.getPoints().get(ok).y;
                                if (ok != oo.getPoints().size() - 1) {
                                    sb.wl("{ x = " + xar + ", y = " + yar + " },");
                                } else {
                                    sb.wl("{ x = " + xar + ", y = " + yar + " }");
                                }
                            }
                            sb.wlc("},");
                        }

                        sb.wprop(oo.getProperties());

                        if (ao != l.getObjects().size() - 1) {
                            sb.wlc("},");
                        } else {
                            sb.wlc("}");
                        }

                    }
                    sb.wlc("}");// objects
                } else {
                    sb.wl("objects = {}");
                }

            } else {
                continue;
            }

            exportedLayerIndex++;
            if (exportedLayerIndex != exportedLayers) {
                sb.wlc("},");
            } else {
                sb.wlc("}");

            }

        }

        sb.wlc("}");// layers
        sb.wlc("}");// map

        String cleanName = filenamenya;
        if (cleanName.toLowerCase().endsWith(".lua")) {
            cleanName = cleanName.substring(0, cleanName.length() - 4);
        }
        FileHandle fh = Gdx.files.absolute(curdir + "/" + cleanName + ".lua");
        fh.writeString(sb.toString(), false);

        String b = fh.readString();
        face.saveasFile(b, cleanName + ".lua");
        backToMap();
        status(z.exportfinished, 5);
    }

    private void exporttojson(String filenamenya) {
        setjsonmap();
        String cleanName = filenamenya;
        if (cleanName.toLowerCase().endsWith(".json")) {
            cleanName = cleanName.substring(0, cleanName.length() - 5);
        }
        FileHandle fh = Gdx.files.absolute(curdir + "/" + cleanName + ".json");
        savejsonmap(fh);
        backToMap();
        String b = fh.readString();
        face.saveasFile(b, cleanName + ".json");
        status(z.exportfinished, 5);
    }

    public String saveRawCsv(int seltile) {
        java.lang.StringBuilder sb = new java.lang.StringBuilder();
        for (int i = 0; i <= layers.get(seltile).getStr().size() - 1; i++) {
            int cek = (i + 1) % Tw;
            long gid = layers.get(seltile).getStr().get(i);
            long strippedGid = gid & 0x0FFFFFFF; // remove flip flags
            long finalId = strippedGid == 0 ? -1 : strippedGid - 1; // 0-indexed or -1 for empty
            sb.append(finalId);
            if (i != layers.get(seltile).getStr().size() - 1) {
                sb.append(",");
                if (cek == 0) {
                    sb.append("\n");
                }
            }
        }
        return sb.toString();
    }

    private void exportascsv(String filenamenya) {
        int tileLayerCount = 0;
        for (int i = 0; i < layers.size(); i++) {
            if (layers.get(i).getType() == layer.Type.TILE) {
                tileLayerCount++;
            }
        }

        String baseName = filenamenya;
        if (baseName.toLowerCase().endsWith(".csv")) {
            baseName = baseName.substring(0, baseName.length() - 4);
        }

        for (int i = 0; i < layers.size(); i++) {
            if (layers.get(i).getType() == layer.Type.TILE) {
                String outName = baseName;
                if (tileLayerCount > 1) {
                    outName += "_" + layers.get(i).getName();
                }
                FileHandle fh = Gdx.files.absolute(curdir + "/" + outName + ".csv");
                fh.writeString(saveRawCsv(i), false);
                face.saveasFile(fh.readBytes(), outName + ".csv");
            }
        }

        backToMap();
        status(z.exportfinished, 5);
    }

    private static final int MAP_COVER_MAX_SIZE = 500;
    private static final Color RW_RES_POOL_YELLOW = new Color(255 / 255f, 255 / 255f, 4 / 255f, 1f);
    private static final Color[] RW_TEAM_COLORS = {
            new Color(1 / 255f, 255 / 255f, 1 / 255f, 1f),
            new Color(247 / 255f, 8 / 255f, 9 / 255f, 1f),
            new Color(45 / 255f, 50 / 255f, 170 / 255f, 1f),
            new Color(255 / 255f, 255 / 255f, 4 / 255f, 1f),
            new Color(4 / 255f, 254 / 255f, 255 / 255f, 1f),
            new Color(233 / 255f, 233 / 255f, 234 / 255f, 1f),
            new Color(1 / 255f, 2 / 255f, 1 / 255f, 1f),
            new Color(255 / 255f, 1 / 255f, 255 / 255f, 1f),
            new Color(255 / 255f, 139 / 255f, 20 / 255f, 1f),
            new Color(163 / 255f, 110 / 255f, 221 / 255f, 1f)
    };

    private static class MapCoverPoint {
        int tileX;
        int tileY;
    }

    private static class MapCoverTeamMarker extends MapCoverPoint {
        int team;
    }

    private boolean isRustedWarfareMap() {
        return findLayer("units") >= 0 && findLayer("items") >= 0;
    }

    private int computeMapCoverCellPx() {
        return Math.max(1, (int) Math.ceil((double) MAP_COVER_MAX_SIZE / Math.max(Tw, Th)));
    }

    private Pixmap scalePixmapToMaxSize(Pixmap src, int maxW, int maxH) {
        if (src == null)
            return null;
        int w = src.getWidth();
        int h = src.getHeight();
        if (w <= 0 || h <= 0)
            return src;
        float scale = Math.min((float) maxW / w, (float) maxH / h);
        if (scale >= 1f)
            return src;
        int nw = Math.max(1, Math.round(w * scale));
        int nh = Math.max(1, Math.round(h * scale));
        Pixmap out = new Pixmap(nw, nh, src.getFormat());
        out.drawPixmap(src, 0, 0, w, h, 0, 0, nw, nh);
        return out;
    }

    private int[] mapCoverBadgeSpriteCoords(int index) {
        if (index < 0 || index > MAP_COVER_BADGE_POOL_INDEX)
            return null;
        int col = index % MAP_COVER_BADGE_COLS;
        int row = index / MAP_COVER_BADGE_COLS;
        return new int[] { col * MAP_COVER_BADGE_CELL, row * MAP_COVER_BADGE_CELL };
    }

    private java.util.List<MapCoverTeamMarker> collectRWCommandCenters() {
        java.util.List<MapCoverTeamMarker> out = new ArrayList<MapCoverTeamMarker>();
        int unitsLayer = findLayer("units");
        if (unitsLayer < 0)
            return out;
        layer lay = layers.get(unitsLayer);
        for (int position = 0; position < Tw * Th; position++) {
            long mm = lay.getStr().get(position);
            if (mm == 0)
                continue;
            int mmo = lay.getTset().get(position);
            if (mmo < 0 || mmo >= tilesets.size())
                continue;
            tileset ts = tilesets.get(mmo);
            tile t = findTileAtGid(ts, mm);
            if (t == null)
                continue;
            boolean isCC = false;
            int team = -1;
            for (property p : t.getProperties()) {
                if (p.getName().equalsIgnoreCase("unit")
                        && p.getValue().equalsIgnoreCase("commandCenter"))
                    isCC = true;
                if (p.getName().equalsIgnoreCase("team")) {
                    try {
                        team = Integer.parseInt(p.getValue());
                    } catch (Exception e) {
                    }
                }
            }
            if (isCC && team >= 0) {
                MapCoverTeamMarker m = new MapCoverTeamMarker();
                m.tileX = position % Tw;
                m.tileY = position / Tw;
                m.team = team;
                out.add(m);
            }
        }
        return out;
    }

    private java.util.List<MapCoverPoint> collectRWResPools() {
        java.util.List<MapCoverPoint> out = new ArrayList<MapCoverPoint>();
        int itemsLayer = findLayer("items");
        if (itemsLayer < 0)
            return out;
        java.util.HashSet<Long> poolGids = new java.util.HashSet<Long>();
        for (int ti = 0; ti < tilesets.size(); ti++) {
            tileset ts = tilesets.get(ti);
            for (int i = 0; i < ts.getTiles().size(); i++) {
                tile t = ts.getTiles().get(i);
                for (property p : t.getProperties()) {
                    if (p.getName().equalsIgnoreCase("res_pool")) {
                        poolGids.add((long) (t.getTileID() + ts.getFirstgid()));
                        break;
                    }
                }
            }
        }
        layer lay = layers.get(itemsLayer);
        for (int position = 0; position < Tw * Th; position++) {
            long mm = lay.getStr().get(position);
            if (mm == 0)
                continue;
            long bare = stripTileGidFlags(mm);
            boolean isPool = poolGids.contains(bare) || poolGids.contains(mm);
            if (!isPool) {
                int mmo = lay.getTset().get(position);
                if (mmo >= 0 && mmo < tilesets.size()) {
                    tile t = findTileAtGid(tilesets.get(mmo), mm);
                    if (t != null) {
                        for (property p : t.getProperties()) {
                            if (p.getName().equalsIgnoreCase("res_pool")) {
                                isPool = true;
                                break;
                            }
                        }
                    }
                }
            }
            if (isPool) {
                MapCoverPoint pt = new MapCoverPoint();
                pt.tileX = position % Tw;
                pt.tileY = position / Tw;
                out.add(pt);
            }
        }
        return out;
    }

    private tile findTileAtGid(tileset ts, long gid) {
        if (ts == null)
            return null;
        long bare = stripTileGidFlags(gid);
        for (int i = 0; i < ts.getTiles().size(); i++) {
            tile t = ts.getTiles().get(i);
            if (t.getTileID() + ts.getFirstgid() == bare)
                return t;
        }
        return null;
    }

    private String rwMapCoverTeamLabel(int team) {
        if (team < 0)
            return "?";
        return String.valueOf(team + 1);
    }

    private Color rwMapCoverTeamColor(int team) {
        if (team < 0)
            return RW_TEAM_COLORS[0];
        return RW_TEAM_COLORS[team % RW_TEAM_COLORS.length];
    }

    private BitmapFont getMapCoverFont() {
        if (mapCoverFont == null) {
            FreeTypeFontGenerator gen = new FreeTypeFontGenerator(Gdx.files.internal("font.ttf"));
            FreeTypeFontGenerator.FreeTypeFontParameter p = new FreeTypeFontGenerator.FreeTypeFontParameter();
            p.size = 48;
            p.borderWidth = 0;
            p.shadowOffsetX = 0;
            p.shadowOffsetY = 0;
            mapCoverFont = gen.generateFont(p);
            gen.dispose();
        }
        return mapCoverFont;
    }

    private Pixmap renderMapCoverLabelPixmap(String label, Color color, int size) {
        if (label == null || label.isEmpty() || size < 4)
            return null;
        BitmapFont font = getMapCoverFont();
        boolean batchWasDrawing = batch.isDrawing();
        if (batchWasDrawing)
            batch.end();
        float oldScaleX = font.getScaleX();
        float oldScaleY = font.getScaleY();
        FrameBuffer fb = null;
        try {
            int fbSize = Math.max(12, size + 4);
            fb = new FrameBuffer(Pixmap.Format.RGBA8888, fbSize, fbSize, false);
            fb.begin();
            Gdx.gl.glClearColor(0f, 0f, 0f, 0f);
            Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);
            GlyphLayout layout = new GlyphLayout();
            float scale = fbSize * 0.62f / Math.max(1f, font.getLineHeight());
            if (label.length() == 3)
                scale *= 0.62f;
            else if (label.length() > 1)
                scale *= 0.82f;
            font.getData().setScale(scale);
            layout.setText(font, label);
            batch.getProjectionMatrix().setToOrtho2D(0, fbSize, fbSize, -fbSize);
            batch.begin();
            float tx = (fbSize - layout.width) / 2f;
            float ty = (fbSize - layout.height) / 2f;
            font.setColor(1f, 1f, 1f, 1f);
            font.draw(batch, layout, tx + 1f, ty);
            font.setColor(color.r, color.g, color.b, 1f);
            font.draw(batch, layout, tx, ty);
            batch.end();
            Pixmap pm = Pixmap.createFromFrameBuffer(0, 0, fbSize, fbSize);
            fb.end();
            return pm;
        } catch (Exception e) {
            ErrorBung(e, "errorlog.txt");
            return null;
        } finally {
            font.getData().setScale(oldScaleX, oldScaleY);
            if (fb != null)
                fb.dispose();
            if (batchWasDrawing && !batch.isDrawing())
                batch.begin();
        }
    }

    private void drawMapCoverBadge(Pixmap target, int centerX, int centerY, int diameter, String label,
            Color textColor) {
        if (target == null || diameter < 4 || label == null || label.isEmpty())
            return;
        int radius = Math.max(2, Math.round(diameter * 0.44f));
        target.setColor(0f, 0f, 0f, 0.55f);
        target.fillCircle(centerX, centerY, radius);
        Pixmap labelPm = renderMapCoverLabelPixmap(label, textColor, diameter);
        if (labelPm == null)
            return;
        int x = centerX - labelPm.getWidth() / 2;
        int y = centerY - labelPm.getHeight() / 2;
        blitMapCoverOverlay(target, labelPm, 0, 0, labelPm.getWidth(), labelPm.getHeight(), x, y, labelPm.getWidth(),
                labelPm.getHeight());
        labelPm.dispose();
    }

    private void blitMapCoverOverlay(Pixmap target, Pixmap source, int srcX, int srcY, int srcW, int srcH, int destX,
            int destY, int destW, int destH) {
        if (target == null || source == null || destW < 1 || destH < 1)
            return;
        target.setBlending(Pixmap.Blending.SourceOver);
        target.drawPixmap(source, srcX, srcY, srcW, srcH, destX, destY, destW, destH);
    }

    private void ensureMapCoverBadgesPixmap() {
        if (mapCoverBadgesPixmap == null) {
            mapCoverBadgesPixmap = new Pixmap(Gdx.files.internal("images/mapcover_badges.png"));
        }
    }

    private void repairOverlayTextures() {
        if (txnumbers != null)
            txnumbers.dispose();
        if (txresources != null)
            txresources.dispose();
        txnumbers = new Texture(Gdx.files.internal("images/numbers.png"));
        txresources = new Texture(Gdx.files.internal("images/resources.png"));
    }

    private void drawRWMapCoverOverlays(Pixmap pm) {
        if (pm == null || Tw <= 0 || Th <= 0)
            return;
        float cellPx = (float) pm.getWidth() / Tw;
        int teamDraw = Math.max(12, Math.round(pm.getWidth() / 6f * 0.9f));
        int poolDraw = Math.max(7, Math.round(pm.getWidth() / 12f * 0.9f));

        ensureMapCoverBadgesPixmap();
        java.util.List<MapCoverPoint> pools = collectRWResPools();
        for (int i = 0; i < pools.size(); i++) {
            MapCoverPoint pt = pools.get(i);
            int cx = Math.round((pt.tileX + 0.5f) * cellPx);
            int cy = Math.round((pt.tileY + 0.5f) * cellPx);
            int destX = cx - poolDraw / 2;
            int destY = cy - poolDraw / 2;
            int[] spr = mapCoverBadgeSpriteCoords(MAP_COVER_BADGE_POOL_INDEX);
            if (spr != null && mapCoverBadgesPixmap != null) {
                blitMapCoverOverlay(pm, mapCoverBadgesPixmap, spr[0], spr[1], MAP_COVER_BADGE_CELL,
                        MAP_COVER_BADGE_CELL, destX, destY, poolDraw, poolDraw);
            }
        }
        java.util.List<MapCoverTeamMarker> teams = collectRWCommandCenters();
        for (int i = 0; i < teams.size(); i++) {
            MapCoverTeamMarker m = teams.get(i);
            int cx = Math.round((m.tileX + 0.5f) * cellPx);
            int cy = Math.round((m.tileY + 0.5f) * cellPx);
            int destX = cx - teamDraw / 2;
            int destY = cy - teamDraw / 2;
            if (m.team >= 0 && m.team <= MAP_COVER_BADGE_MAX_TEAM) {
                int[] spr = mapCoverBadgeSpriteCoords(m.team);
                if (spr != null && mapCoverBadgesPixmap != null) {
                    blitMapCoverOverlay(pm, mapCoverBadgesPixmap, spr[0], spr[1], MAP_COVER_BADGE_CELL,
                            MAP_COVER_BADGE_CELL, destX, destY, teamDraw, teamDraw);
                }
            } else if (m.team >= 0) {
                drawMapCoverBadge(pm, cx, cy, teamDraw, rwMapCoverTeamLabel(m.team), rwMapCoverTeamColor(m.team));
            }
        }
    }

    private Pixmap renderMapCoverBasePixmap(int cellPx) {
        Gdx.gl.glEnable(GL20.GL_BLEND);
        int drawCell = Math.max(1, cellPx);
        Pixmap pm2 = new Pixmap(Tw * drawCell, Th * drawCell, Pixmap.Format.RGBA8888);
        tilesetsize = tilesets.size();
        if (tilesetsize > 0 && !loadingfile) {
            int offsetx = 0, offsety = 0;
            long ini;
            int total = Tw * Th;
            int startx = 0, stopx = Tw;
            int starty = 0, stopy = Th;
            int aa = 0, bb = 0, cc = 0, dd = 0;
            switch (renderorder) {
                case "right-down":
                    aa = starty;
                    bb = stopy;
                    cc = startx;
                    dd = stopx;
                    break;
                case "left-down":
                    aa = starty;
                    bb = stopy;
                    cc = -stopx + 1;
                    dd = -startx + 1;
                    break;
                case "right-up":
                    aa = -stopy + 1;
                    bb = -starty + 1;
                    cc = startx;
                    dd = stopx;
                    break;
                case "left-up":
                    aa = -stopy + 1;
                    bb = -starty + 1;
                    cc = -stopx + 1;
                    dd = -startx + 1;
                    break;
            }
            String flag;
            Long mm = null;
            flag = "00";
            for (int jo = 0; jo < layers.size(); jo++) {
                if (layers.get(jo).getType() == layer.Type.TILE && layers.get(jo).isVisible()) {
                    java.util.List<drawer> drawers = new ArrayList<drawer>();
                    for (int a = aa; a < bb; a++) {
                        for (int b = cc; b < dd; b++) {
                            position = (abs(a) * Tw) + abs(b);
                            ini = layers.get(jo).getStr().get(position);
                            if (ini == 0)
                                continue;
                            int preferredTset = layers.get(jo).getTset().get(position);
                            xpos = position % Tw;
                            ypos = position / Tw;
                            if (isOrphanedLayerTile(ini, preferredTset)) {
                                drawers.add(orphanTileDrawer(xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                        drawCell / 2f, drawCell / 2f, drawCell, drawCell, ini));
                                continue;
                            }
                            initset = resolveTilesetIndexForGid(ini, preferredTset);
                            mm = ini;
                            flag = "00";
                            if (ini > total) {
                                hex = Long.toHexString(ini);
                                trailer = "00000000" + hex;
                                hex = trailer.substring(trailer.length() - 8);
                                flag = hex.substring(0, 2);
                                mm = Long.decode("#00" + hex.substring(2, 8));
                            }
                            tiles = tilesets.get(initset).getTiles();
                            tilesize = tiles.size();
                            if (tilesize > 0) {
                                for (int n = 0; n < tilesize; n++) {
                                    if (tiles.get(n).getAnimation().size() > 0) {
                                        if (mm == tiles.get(n).getTileID() + tilesets.get(initset).getFirstgid()) {
                                            mm = (long) tiles.get(n).getActiveFrameID()
                                                    + tilesets.get(initset).getFirstgid();
                                        }
                                    }
                                }
                            }
                            resolveSprite(tilesets.get(initset), (int) (mm - tilesets.get(initset).getFirstgid()));
                            margin = tilesets.get(initset).getMargin();
                            spacing = tilesets.get(initset).getSpacing();
                            Tswa = tilesets.get(initset).getTilewidth();
                            Tsha = tilesets.get(initset).getTileheight();
                            tempdrawer = new drawer();
                            tempdrawer.mm = mm;
                            int Tswad = Tswa;
                            int Tshad = Tsha;
                            switch (flag) {
                                case "20":
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 0f, sprX, sprY, Tswa,
                                            Tsha, true, true);
                                    break;
                                case "40":
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 0f, sprX, sprY, Tswa,
                                            Tsha, false, true);
                                    break;
                                case "60":
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 90f, sprX, sprY, Tswa,
                                            Tsha, false, false);
                                    break;
                                case "80":
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 0f, sprX, sprY, Tswa,
                                            Tsha, true, false);
                                    break;
                                case "a0":
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 270f, sprX, sprY, Tswa,
                                            Tsha, false, false);
                                    break;
                                case "c0":
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 180f, sprX, sprY, Tswa,
                                            Tsha, false, false);
                                    break;
                                default:
                                    tempdrawer.setdrawer(initset, xpos * drawCell - offsetx, ypos * drawCell - offsety,
                                            drawCell / 2f, drawCell / 2f, Tswad, Tshad, 1f, 1f, 0f, sprX, sprY, Tswa,
                                            Tsha, false, false);
                                    break;
                            }
                            drawers.add(tempdrawer);
                        }
                    }
                    java.util.Collections.sort(drawers);
                    for (drawer drawer : drawers) {
                        drawMapDrawerPixmap(drawer, pm2, drawCell, drawCell);
                    }
                }
            }
        }
        return pm2;
    }

    private Pixmap buildMapCoverPixmap(boolean includeRwOverlays) {
        int cellPx = computeMapCoverCellPx();
        Pixmap full = renderMapCoverBasePixmap(cellPx);
        if (full == null)
            return null;
        Pixmap scaled = scalePixmapToMaxSize(full, MAP_COVER_MAX_SIZE, MAP_COVER_MAX_SIZE);
        if (scaled != full)
            full.dispose();
        if (includeRwOverlays && isRustedWarfareMap()) {
            try {
                drawRWMapCoverOverlays(scaled);
            } catch (Exception e) {
                ErrorBung(e, "errorlog.txt");
            }
        }
        return scaled;
    }

    private Pixmap createMapCoverPixmap(boolean includeRwOverlays) {
        return buildMapCoverPixmap(includeRwOverlays);
    }

    private String mapCoverOutputBasename() {
        if (curfile == null || curfile.isEmpty())
            return "map";
        int dot = curfile.lastIndexOf('.');
        return dot > 0 ? curfile.substring(0, dot) : curfile;
    }

    private void exportMapCover() {
        if (curfile == null || curfile.isEmpty()) {
            msgbox(z.saveas != null ? z.saveas : "Save the map first.");
            return;
        }
        Gdx.app.postRunnable(new Runnable() {
            @Override
            public void run() {
                runExportMapCover();
            }
        });
    }

    private void runExportMapCover() {
        boolean batchWasDrawing = batch.isDrawing();
        try {
            if (batchWasDrawing)
                batch.end();
            Pixmap scaled = buildMapCoverPixmap(isRustedWarfareMap());
            if (scaled == null) {
                msgbox(z.error);
                return;
            }
            repairOverlayTextures();
            saveMapCoverPixmap(scaled);
        } catch (Exception e) {
            msgbox(z.error);
            ErrorBung(e, "errorlog.txt");
        } finally {
            if (batchWasDrawing && !batch.isDrawing())
                batch.begin();
            backToMap();
        }
    }

    private Pixmap createRWthumbnail(String filenamenya) {
        try {
            Pixmap scaled = buildMapCoverPixmap(isRustedWarfareMap());
            if (scaled == null)
                return null;
            repairOverlayTextures();
            if (filenamenya != null && !filenamenya.isEmpty()) {
                FileHandle fh = Gdx.files.absolute(curdir + "/" + filenamenya + ".png");
                if (!fh.parent().exists())
                    fh.parent().mkdirs();
                PixmapIO.writePNG(fh, scaled);
                scaled.dispose();
                return null;
            }
            return scaled;
        } catch (Exception e) {
            msgbox(z.error);
            ErrorBung(e, "errorlog.txt");
            return null;
        }
    }

    private void exportastemplate(String filenamenya) {
        if (filenamenya == "") {
            return;
        }
        String exportpath = basepath + "NotTiled/sample/template/" + filenamenya;
        FileHandle fh = Gdx.files.absolute(exportpath);
        if (!fh.exists())
            fh.mkdirs();
        saveMap(exportpath + "/" + "template.tmx");
        backToMap();
        status(z.filesaved, 2);
    }

    private void exporttopng(String filenamenya) {
        exporttopng(filenamenya, true);
    }

    private void exporttopng(String filenamenya, boolean export) {
        try {
            Gdx.gl.glEnable(GL20.GL_BLEND);
            Pixmap pm2 = new Pixmap(Tw * Tsw, Th * Tsh, Pixmap.Format.RGBA8888);
            tilesetsize = tilesets.size();
            if (tilesetsize > 0 && !loadingfile) {
                int offsetx = 0, offsety = 0;
                int jon = 0, joni = 0;
                long ini;
                int total = Tw * Th;
                int startx = 0, stopx = Tw;
                int starty = 0, stopy = Th;

                int aa = 0, bb = 0, cc = 0, dd = 0;
                switch (renderorder) {
                    case "right-down":
                        aa = starty;
                        bb = stopy;
                        cc = startx;
                        dd = stopx;
                        break;
                    case "left-down":
                        aa = starty;
                        bb = stopy;
                        cc = -stopx + 1;
                        dd = -startx + 1;
                        break;
                    case "right-up":
                        aa = -stopy + 1;
                        bb = -starty + 1;
                        cc = startx;
                        dd = stopx;
                        break;
                    case "left-up":
                        aa = -stopy + 1;
                        bb = -starty + 1;
                        cc = -stopx + 1;
                        dd = -startx + 1;
                        break;
                }

                String flag;
                Long mm = null;
                flag = "00";

                for (int jo = 0; jo < layers.size(); jo++) {
                    if (layers.get(jo).getType() == layer.Type.TILE && layers.get(jo).isVisible()) {
                        java.util.List<drawer> drawers = new ArrayList<drawer>();
                        drawers.clear();
                        for (int a = aa; a < bb; a++) {
                            for (int b = cc; b < dd; b++) {
                                // position=(Math.abs(a)*Tw)+Math.abs(b);

                                position = (abs(a) * Tw) + abs(b);
                                ini = layers.get(jo).getStr().get(position);
                                if (ini == 0)
                                    continue;// dont draw empty, amazing performance boost
                                int preferredTset = layers.get(jo).getTset().get(position);
                                xpos = position % Tw;
                                ypos = position / Tw;
                                if (orientation.equalsIgnoreCase("isometric")) {
                                    offsetx = (xpos * Tsw / 2) + (ypos * Tsw / 2);
                                    offsety = (xpos * Tsh / 2) - (ypos * Tsh / 2);
                                }
                                if (isOrphanedLayerTile(ini, preferredTset)) {
                                    drawers.add(orphanTileDrawer(xpos * Tsw - offsetx, ypos * Tsh - offsety, Tsw / 2f,
                                            Tsh / 2f, Tsw, Tsh, ini));
                                    continue;
                                }
                                initset = resolveTilesetIndexForGid(ini, preferredTset);

                                mm = ini;
                                flag = "00";
                                if (ini > total) {
                                    hex = Long.toHexString(ini);
                                    trailer = "00000000" + hex;
                                    hex = trailer.substring(trailer.length() - 8);
                                    flag = hex.substring(0, 2);
                                    mm = Long.decode("#00" + hex.substring(2, 8));
                                }
                                tiles = tilesets.get(initset).getTiles();
                                tilesize = tiles.size();

                                if (tilesize > 0) {
                                    for (int n = 0; n < tilesize; n++) {
                                        if (tiles.get(n).getAnimation().size() > 0) {
                                            if (mm == tiles.get(n).getTileID() + tilesets.get(initset).getFirstgid()) {
                                                mm = (long) tiles.get(n).getActiveFrameID()
                                                        + tilesets.get(initset).getFirstgid();
                                            }
                                        }
                                    }
                                }

                                resolveSprite(tilesets.get(initset), (int) (mm - tilesets.get(initset).getFirstgid()));
                                margin = tilesets.get(initset).getMargin();
                                spacing = tilesets.get(initset).getSpacing();
                                Tswa = tilesets.get(initset).getTilewidth();
                                Tsha = tilesets.get(initset).getTileheight();

                                tempdrawer = new drawer();
                                tempdrawer.mm = mm;
                                int Tswad = 0;
                                int Tshad = 0;
                                int ttx = 0;
                                int tty = 0;

                                Tswad = Tswa;
                                Tshad = Tsha;

                                switch (flag) {
                                    case "20":// diagonal flip 'THIS ONE"
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tswad / 2f, Tshad / 2f, Tswad, Tshad, 1f,
                                                1f, 90f, sprX,
                                                sprY, Tswa, Tsha, true, false);
                                        break;
                                    case "40":// flipy nd
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                0f, sprX,
                                                sprY, Tswa, Tsha, false, true);
                                        break;
                                    case "60":// 270 degrees clockwise nd
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                90f, sprX,
                                                sprY, Tswa, Tsha, false, false);
                                        break;
                                    case "80":// flipx nd
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                0f, sprX,
                                                sprY, Tswa, Tsha, true, false);
                                        break;
                                    case "a0":// 90 degress cw
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                270f, sprX,
                                                sprY, Tswa, Tsha, false, false);
                                        break;
                                    case "c0":// 180 degrees cw nd
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                180f, sprX,
                                                sprY, Tswa, Tsha, false, false);
                                        break;
                                    case "e0":// 180 degrees ccw "AND THIS ONE"
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                270f, sprX,
                                                sprY, Tswa, Tsha, true, false);
                                        break;
                                    case "00":
                                        tempdrawer.setdrawer(initset, xpos * Tsw + ttx - offsetx,
                                                ypos * Tsh + tty - offsety, Tsw / 2f, Tsh / 2f, Tswad, Tshad, 1f, 1f,
                                                0f, sprX,
                                                sprY, Tswa, Tsha, false, false);
                                        break;
                                }
                                drawers.add(tempdrawer);

                            } // for b
                        } // for a

                        java.util.Collections.sort(drawers);// fps hogger

                        for (drawer drawer : drawers) {
                            drawMapDrawerPixmap(drawer, pm2, Tsw, Tsh);
                        }
                    }
                } // for jo

            } // no tileswt

            //
            String cleanName = filenamenya;
            if (cleanName.toLowerCase().endsWith(".png")) {
                cleanName = cleanName.substring(0, cleanName.length() - 4);
            }
            FileHandle fh = Gdx.files.absolute(curdir + "/" + cleanName + ".png");
            PixmapIO.writePNG(fh, pm2);
            backToMap();

            if (export) {
                byte[] b = fh.readBytes();
                face.saveasFile(b, cleanName + ".png");
                status(z.exportfinished, 3);
            } else {
                status(z.filesaved, 1);
            }
        } catch (Exception e) {
            msgbox(z.error);
            ErrorBung(e, "errorlog.txt");
        }
    }

