    public void showTilesetManager() {
        if (seltset < 0 || seltset >= tilesets.size())
            seltset = Math.max(0, tilesets.size() - 1);
        rebuildTilesetManagerList();
        gotoStage(tTsetMgrMain);
        scrollTilesetManagerToSelection();
        Gdx.app.postRunnable(new Runnable() {
            @Override
            public void run() {
                scrollTilesetManagerToSelection();
            }
        });
    }

    /**
     * Pick a tileset image directly from the device/cloud via a single-file SAF
     * open (ACTION_OPEN_DOCUMENT). Needs no prior folder grant, so it works even
     * on a brand-new internal map. Copies the bytes into Temp and hands off to the
     * normal import-tileset config screen.
     */
    private void pickTilesetViaSaf(final Runnable onAbort) {
        new Thread(new Runnable() {
            @Override
            public void run() {
                String st = "";
                face.openFile();
                while (st.equalsIgnoreCase("")) {
                    st = face.getStatus();
                    try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                }
                if (!st.equalsIgnoreCase("OK")) {
                    Gdx.app.postRunnable(onAbort);
                    return;
                }
                final byte[] data = face.getData();
                final String name = face.getFilename();
                if (data == null || name == null || name.isEmpty()) {
                    Gdx.app.postRunnable(new Runnable() {
                        @Override public void run() { status(z.error, 5); onAbort.run(); }
                    });
                    return;
                }
                String lower = name.toLowerCase();
                if (!(lower.endsWith(".png") || lower.endsWith(".jpg") || lower.endsWith(".jpeg")
                        || lower.endsWith(".bmp") || lower.endsWith(".gif"))) {
                    Gdx.app.postRunnable(new Runnable() {
                        @Override public void run() { status(z.error, 5); onAbort.run(); }
                    });
                    return;
                }
                final String localPath = basepath + "NotTiled/Temp/" + name;
                try {
                    FileHandle out = Gdx.files.absolute(localPath);
                    out.parent().mkdirs();
                    out.writeBytes(data, false);
                } catch (Exception e) {
                    e.printStackTrace();
                    Gdx.app.postRunnable(new Runnable() {
                        @Override public void run() { status(z.error, 5); onAbort.run(); }
                    });
                    return;
                }
                Gdx.app.postRunnable(new Runnable() {
                    @Override
                    public void run() {
                        FileHandle f = Gdx.files.absolute(localPath);
                        if (f.exists()) {
                            thefile = f;
                            fImportWidth.setText(Tsw + "");
                            fImportHeight.setText(Tsh + "");
                            cImportEmbed.setChecked(false);
                            gotoStage(tImport);
                        } else {
                            status(z.error, 5);
                            onAbort.run();
                        }
                    }
                });
            }
        }).start();
    }

    /**
     * Pick a .tsx via the native SAF picker, fetch its referenced image from the
     * saved folder tree (same machinery as the TMX open flow), drop both into Temp,
     * then route through the normal "seltsx" import so the tileset manager refreshes.
     * onAbort runs (on the GL thread) if the user cancels or the pick fails.
     */
    private void pickTsxViaSaf(final Runnable onAbort) {
        new Thread(new Runnable() {
            @Override
            public void run() {
                String st = "";
                face.openFile();
                while (st.equalsIgnoreCase("")) {
                    st = face.getStatus();
                    try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                }
                if (!st.equalsIgnoreCase("OK")) {
                    Gdx.app.postRunnable(onAbort);
                    return;
                }
                final byte[] data = face.getData();
                final String name = face.getFilename();
                final String uri  = face.getUri();
                if (data == null || name == null || name.isEmpty()
                        || !name.toLowerCase().endsWith(".tsx")) {
                    Gdx.app.postRunnable(new Runnable() {
                        @Override public void run() { status(z.error, 5); onAbort.run(); }
                    });
                    return;
                }

                // Locate the tsx inside the granted folder tree and import it in place
                // through the /saf/ shim so its <image> reference resolves relatively.
                // Outside the tree (or no grant): fall back to a Temp copy — loadtsx
                // then shows empty.jpeg for the image, same as before.
                String tsxRelPath = face.hasTreeAccess() ? face.resolveUriToTreePath(uri) : null;
                FileHandle tsx;
                if (tsxRelPath != null && !tsxRelPath.isEmpty()) {
                    tsx = Gdx.files.absolute(face.getSafRoot() + tsxRelPath);
                } else {
                    tsx = Gdx.files.absolute(basepath + "NotTiled/Temp/" + name);
                    tsx.parent().mkdirs();
                    tsx.writeBytes(data, false);
                }
                final FileHandle finalTsx = tsx;
                Gdx.app.postRunnable(new Runnable() {
                    @Override
                    public void run() {
                        if (finalTsx.exists()) {
                            tujuanDialog("seltsx", finalTsx);
                        } else {
                            status(z.error, 5);
                            onAbort.run();
                        }
                    }
                });
            }
        }).start();
    }

    /** Save As to an external location via SAF ACTION_CREATE_DOCUMENT. */
    private void saveAsViaSaf(final String suggestedName) {
        final String tmpPath = basepath + "NotTiled/Temp/.saveas_tmp.tmx";
        if (!buildTMX(tmpPath)) {
            status(z.error, 5);
            return;
        }
        try {
            FileHandle tmp = Gdx.files.absolute(tmpPath);
            String content = tmp.readString("UTF-8");
            face.saveasFile(content, suggestedName);
            status(z.filesaved, 3);
        } catch (Exception e) {
            e.printStackTrace();
            status(z.error, 5);
        }
    }

