    private void showTilesetRowOptionsDialog(final int tsetIdx) {
        if (tsetIdx < 0 || tsetIdx >= tilesets.size())
            return;
        final tileset ts = tilesets.get(tsetIdx);
        Gdx.input.setInputProcessor(stage);
        final Dialog optionsDlg = new Dialog("", skin, "dialog");
        Table optionsTable = optionsDlg.getContentTable();
        float dialogBtnWidth = getDialogContentWidth();

        Label titleLabel = new Label(ts.getName(), skin);
        titleLabel.setWrap(true);
        titleLabel.setAlignment(Align.center);
        optionsTable.add(titleLabel).width(dialogBtnWidth).pad(10).row();

        TextButton btnProp = new TextButton(z.properties, skin);
        btnProp.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                optionsDlg.hide();
                openTilesetPropertiesForIndex(tsetIdx);
            }
        });
        optionsTable.add(btnProp).width(dialogBtnWidth).height(btny).pad(5).row();

        TextButton btnCustomProp = new TextButton(z.customproperties, skin);
        btnCustomProp.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                optionsDlg.hide();
                selTsetID = tsetIdx;
                refreshProperties(tilesets.get(tsetIdx).getProperties());
                lPropID.setText(z.customproperties);
                sender = "tsetlist";
                gotoStage(tPropsMgmt);
            }
        });
        optionsTable.add(btnCustomProp).width(dialogBtnWidth).height(btny).pad(5).row();

        TextButton btnSaveTsx = new TextButton(z.saveastsx, skin);
        btnSaveTsx.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                optionsDlg.hide();
                tileset t = tilesets.get(tsetIdx);
                t.setTsxfile(t.getName() + ".tsx");
                saveTsx(tsetIdx);
                showTilesetManager();
                status(z.filesaved, 5);
            }
        });
        optionsTable.add(btnSaveTsx).width(dialogBtnWidth).height(btny).pad(5).row();

        TextButton btnSavePng = new TextButton(z.exporttopng, skin);
        btnSavePng.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                optionsDlg.hide();
                saveTsetAsPNG(tsetIdx);
                showTilesetManager();
            }
        });
        optionsTable.add(btnSavePng).width(dialogBtnWidth).height(btny).pad(5).row();

        if (ts.isCollection()) {
            TextButton btnAddTiles = new TextButton(
                    z.appendcollectionfiles != null ? z.appendcollectionfiles : z.addtileimages, skin);
            btnAddTiles.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    optionsDlg.hide();
                    selTsetID = tsetIdx;
                    seltset = tsetIdx;
                    fImportWidth.setText(ts.getTilewidth() + "");
                    fImportHeight.setText(ts.getTileheight() + "");
                    frompick = kartu.equals("tile");
                    if (ts.getCollectionBase() != null && !ts.getCollectionBase().isEmpty()) {
                        String abs = convertToAbsolutepath(ts.getCollectionBase(), curdir);
                        FileHandle bh = Gdx.files.absolute(abs);
                        if (bh.exists() && bh.isDirectory()) {
                            lastpath = bh.path();
                            prefs.putString("lastpath", lastpath);
                            prefs.flush();
                        }
                    }
                    Table exit = frompick ? nullTable : tTsetMgrMain;
                    FileDialog(z.selectfolder, "pickcollectionappend", "dir", new String[] {}, exit);
                }
            });
            optionsTable.add(btnAddTiles).width(dialogBtnWidth).height(btny).pad(5).row();
        }

        if (!isProtectedPixelArtTileset(tsetIdx)) {
            TextButton btnEditNot2Pix = new TextButton(
                    z.editinnot2pix != null ? z.editinnot2pix : "Edit in Not2Pix", skin);
            btnEditNot2Pix.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    if (!face.isNot2PixInstalled()) {
                        showNot2PixNotInstalledDialog();
                        return;
                    }
                    optionsDlg.hide();
                    // Check if tileset has embedded_png - if so, export that
                    boolean hasEmbedded = false;
                    for (property p : ts.getProperties()) {
                        if (p.getName().equalsIgnoreCase("embedded_png")) { hasEmbedded = true; break; }
                    }
                    if (hasEmbedded && ts.getPixmap() != null) {
                        String extPath = face.getFilesDirPath();
                        String tmpPath = extPath + ".not2pix_embedded_edit.png";
                        FileHandle tmp = Gdx.files.absolute(tmpPath);
                        PixmapIO.writePNG(tmp, ts.getPixmap());
                        not2pixEditTsetIdx = tsetIdx;
                        face.editInNot2Pix(tmpPath);
                    } else {
                        String src = ts.getSource();
                        if (src != null && !src.isEmpty()) {
                            String absPath = convertToAbsolutepath(src, curdir);
                            FileHandle extFile = Gdx.files.absolute(absPath);
                            if (!extFile.exists()) {
                                // Check if it's an internal RW tileset
                                String internalpath = "rusted_warfare/assets/tilesets";
                                String inter = convertToAbsolutepath(src, internalpath);
                                FileHandle finter = Gdx.files.internal(inter);
                                if (finter.exists() && ts.getPixmap() != null) {
                                    // Show confirmation dialog
                                    Dialog dlg = new Dialog(z.confirmation, skin, "dialog") {
                                        @Override
                                        protected void result(Object obj) {
                                            if ((boolean) obj) {
                                                // Convert to embedded_png
                                                String extPath = face.getFilesDirPath();
                                                String tmpPath = extPath + ".not2pix_embedded_edit.png";
                                                FileHandle tmp = Gdx.files.absolute(tmpPath);
                                                PixmapIO.writePNG(tmp, ts.getPixmap());
                                                byte[] bytes = tmp.readBytes();
                                                String encoded = android.util.Base64.encodeToString(bytes, 0);
                                                ts.getProperties().add(new property("embedded_png", encoded));
                                                ts.setSource("");
                                                ts.setUsetsx(false);
                                                ts.setTsxfile("");
                                                not2pixEditTsetIdx = tsetIdx;
                                                face.editInNot2Pix(tmpPath);
                                            }
                                        }
                                    };
                                    Label lbl = new Label("Editing Rusted Warfare tileset will convert it into an embedded PNG. Continue?", skin);
                                    lbl.setWrap(true);
                                    dlg.getContentTable().add(lbl).width(getDialogContentWidth()).pad(10).row();
                                    dlg.button(z.yes, true);
                                    dlg.button(z.no, false);
                                    dlg.show(stage);
                                } else {
                                    status("No image for this tileset", 3);
                                }
                            } else {
                                not2pixEditTsetIdx = tsetIdx;
                                if (isSafPath(absPath)) {
                                    // Not2Pix needs a real file path — stage a local copy
                                    // and push it back to the device folder on return.
                                    String tmpPath = face.getFilesDirPath() + ".not2pix_saf_edit.png";
                                    FileHandle tmp = Gdx.files.absolute(tmpPath);
                                    tmp.writeBytes(extFile.readBytes(), false);
                                    not2pixSafWriteBackPath = absPath;
                                    face.editInNot2Pix(tmpPath);
                                } else {
                                    face.editInNot2Pix(absPath);
                                }
                            }
                        } else if (ts.getPixmap() != null) {
                            String extPath = face.getFilesDirPath();
                            String tmpPath = extPath + ".not2pix_embedded_edit.png";
                            FileHandle tmp = Gdx.files.absolute(tmpPath);
                            PixmapIO.writePNG(tmp, ts.getPixmap());
                            not2pixEditTsetIdx = tsetIdx;
                            face.editInNot2Pix(tmpPath);
                        } else {
                            status("No image for this tileset", 3);
                        }
                    }
                }
            });
            optionsTable.add(btnEditNot2Pix).width(dialogBtnWidth).height(btny).pad(5).row();

            TextButton btnDel = new TextButton(z.remove, skin);
            btnDel.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    optionsDlg.hide();
                    confirmRemoveTilesetAt(tsetIdx, new Runnable() {
                        @Override
                        public void run() {
                            showTilesetManager();
                        }
                    });
                }
            });
            optionsTable.add(btnDel).width(dialogBtnWidth).height(btny).pad(5).row();
        }

        TextButton btnCancel = new TextButton(z.cancel, skin);
        btnCancel.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                optionsDlg.hide();
                showTilesetManager();
            }
        });
        optionsTable.add(btnCancel).width(dialogBtnWidth).height(btny).pad(5).row();

        optionsDlg.show(stage);
    }

    /** Reload a tileset texture from disk after external edit (e.g. from Not2Pix). */
    public int not2pixEditTsetIdx = -1;
    /** SAF path a staged Not2Pix edit must be written back to (null if none). */
    private String not2pixSafWriteBackPath = null;

    public void reloadTilesetByPath(String absolutePath) {
        // A staged SAF tileset edit comes back as a local temp file — push the
        // edited PNG into the device folder before reloading the texture from it.
        if (not2pixSafWriteBackPath != null) {
            try {
                FileHandle edited = Gdx.files.absolute(absolutePath);
                if (edited.exists()) {
                    Gdx.files.absolute(not2pixSafWriteBackPath).writeBytes(edited.readBytes(), false);
                }
            } catch (Exception e) {
                ErrorBung(e, "errorlog.txt");
            }
            not2pixSafWriteBackPath = null;
        }
        // Check if this was an embedded PNG edit (temp file)
        if (not2pixEditTsetIdx >= 0 && not2pixEditTsetIdx < tilesets.size()) {
            tileset ts = tilesets.get(not2pixEditTsetIdx);
            String src = ts.getSource();
            boolean isEmbedded = (src == null || src.isEmpty());
            try {
                FileHandle f = Gdx.files.absolute(absolutePath);
                if (f.exists()) {
                    Texture oldTex = ts.getTexture();
                    Pixmap oldPm = ts.getPixmap();
                    Pixmap pm = new Pixmap(f);
                    ts.setPixmap(pm);
                    Texture tex = new Texture(pm);
                    if (ts.getTrans() != null) {
                        Texture keyed = chromaKey(tex, ts.getTrans());
                        tex.dispose();
                        tex = keyed;
                    }
                    ts.setTexture(tex);
                    try { if (oldTex != null) oldTex.dispose(); } catch (Exception ignored) {}
                    try { if (oldPm != null && oldPm != pm) oldPm.dispose(); } catch (Exception ignored) {}
                    // Update embedded_png if this tileset uses it
                    if (isEmbedded) {
                        updateEmbeddedPng(ts, f);
                    } else {
                        updateEmbeddedPng(ts, f);
                    }
                }
            } catch (Exception e) {
                ErrorBung(e, "errorlog.txt");
            }
            not2pixEditTsetIdx = -1;
            invalidateTileCache();
            return;
        }

        // Fallback: find by path
        for (int i = 0; i < tilesets.size(); i++) {
            String src = tilesets.get(i).getSource();
            if (src == null || src.isEmpty()) continue;
            String abs = convertToAbsolutepath(src, curdir);
            if (abs.equals(absolutePath)) {
                try {
                    FileHandle f = Gdx.files.absolute(absolutePath);
                    if (f.exists()) {
                        tileset ti = tilesets.get(i);
                        Texture oldTex = ti.getTexture();
                        Pixmap oldPm = ti.getPixmap();
                        Pixmap pm = new Pixmap(f);
                        ti.setPixmap(pm);
                        Texture tex = new Texture(pm);
                        if (ti.getTrans() != null) {
                            Texture keyed = chromaKey(tex, ti.getTrans());
                            tex.dispose();
                            tex = keyed;
                        }
                        ti.setTexture(tex);
                        try { if (oldTex != null) oldTex.dispose(); } catch (Exception ignored) {}
                        try { if (oldPm != null && oldPm != pm) oldPm.dispose(); } catch (Exception ignored) {}
                        updateEmbeddedPng(ti, f);
                    }
                } catch (Exception e) {
                    ErrorBung(e, "errorlog.txt");
                }
                invalidateTileCache();
                return;
            }
        }
    }

