    private void invalidateTileCache() {
        for (TileCache cace : tcaches) {
            cace.getCache().dispose();
        }
        tcaches.clear();
        pickerCacheValid = false;
        terrainPickerCacheValid = false;
        resetCaches();
    }

    private void updateEmbeddedPng(tileset ts, FileHandle imageFile) {
        try {
            byte[] bytes = imageFile.readBytes();
            String encoded = android.util.Base64.encodeToString(bytes, 0);
            for (property p : ts.getProperties()) {
                if (p.getName().equalsIgnoreCase("embedded_png")) {
                    p.setValue(encoded);
                    return;
                }
            }
        } catch (Exception e) {
            // ignore
        }
    }

    private int getLayerDepth(layer l) {
        int depth = 0;
        int parentId = l.getParentGroupId();
        java.util.Set<Integer> seen = new java.util.HashSet<Integer>();
        while (parentId != -1) {
            if (!seen.add(parentId))
                break;
            depth++;
            layer parent = null;
            for (layer pl : layers) {
                if (pl.getId() == parentId) {
                    parent = pl;
                    break;
                }
            }
            if (parent != null) {
                parentId = parent.getParentGroupId();
            } else {
                break;
            }
        }
        return depth;
    }

    private boolean areAllParentsVisible(layer l) {
        int parentId = l.getParentGroupId();
        while (parentId != -1) {
            layer parent = null;
            for (layer pl : layers) {
                if (pl.getId() == parentId) {
                    parent = pl;
                    break;
                }
            }
            if (parent != null) {
                if (!parent.isVisible()) {
                    return false;
                }
                parentId = parent.getParentGroupId();
            } else {
                break;
            }
        }
        return true;
    }

    private float getCombinedOpacity(layer l) {
        float opacity = l.getOpacity() != 0f ? l.getOpacity() : 1f;
        int parentId = l.getParentGroupId();
        while (parentId != -1) {
            layer parent = null;
            for (layer pl : layers) {
                if (pl.getId() == parentId) {
                    parent = pl;
                    break;
                }
            }
            if (parent != null) {
                float parentOpacity = parent.getOpacity() != 0f ? parent.getOpacity() : 1f;
                opacity *= parentOpacity;
                parentId = parent.getParentGroupId();
            } else {
                break;
            }
        }
        return opacity;
    }

    private float getCombinedOffsetX(layer l) {
        float offset = l.getOffsetX();
        int parentId = l.getParentGroupId();
        while (parentId != -1) {
            layer parent = null;
            for (layer pl : layers) {
                if (pl.getId() == parentId) {
                    parent = pl;
                    break;
                }
            }
            if (parent != null) {
                offset += parent.getOffsetX();
                parentId = parent.getParentGroupId();
            } else {
                break;
            }
        }
        return offset;
    }

    private float getCombinedOffsetY(layer l) {
        float offset = l.getOffsetY();
        int parentId = l.getParentGroupId();
        while (parentId != -1) {
            layer parent = null;
            for (layer pl : layers) {
                if (pl.getId() == parentId) {
                    parent = pl;
                    break;
                }
            }
            if (parent != null) {
                offset += parent.getOffsetY();
                parentId = parent.getParentGroupId();
            } else {
                break;
            }
        }
        return offset;
    }

    private List<Integer> getParentChain(layer l) {
        List<Integer> chain = new ArrayList<>();
        int parentId = l.getParentGroupId();
        while (parentId != -1) {
            chain.add(0, parentId);
            layer parent = null;
            for (layer pl : layers) {
                if (pl.getId() == parentId) {
                    parent = pl;
                    break;
                }
            }
            if (parent != null) {
                parentId = parent.getParentGroupId();
            } else {
                break;
            }
        }
        return chain;
    }

    private boolean isDescendant(int possibleDescendantId, int ancestorId) {
        if (possibleDescendantId == -1 || ancestorId == -1) {
            return false;
        }
        layer l = null;
        for (layer ly : layers) {
            if (ly.getId() == possibleDescendantId) {
                l = ly;
                break;
            }
        }
        if (l == null) {
            return false;
        }
        int parentId = l.getParentGroupId();
        if (parentId == ancestorId) {
            return true;
        }
        return isDescendant(parentId, ancestorId);
    }

    private void showSetParentGroupDialog() {
        if (layers.isEmpty())
            return;
        final int selectedIdx = llayerlist.getSelectedIndex();
        if (selectedIdx < 0 || selectedIdx >= layers.size())
            return;
        final layer targetLayer = layers.get(selectedIdx);

        final List<layer> groups = new ArrayList<>();
        for (layer l : layers) {
            if (l.getType() == layer.Type.GROUP && l.getId() != targetLayer.getId()
                    && !isDescendant(l.getId(), targetLayer.getId())) {
                groups.add(l);
            }
        }

        Dialog dlg = new Dialog(z.setparentgroup != null ? z.setparentgroup : "Set Parent Group", skin, "dialog") {
            @Override
            protected void result(Object object) {
                if (object instanceof Integer) {
                    int parentId = (Integer) object;
                    targetLayer.setParentGroupId(parentId);
                    refreshLayerList();
                    pushUpdateIfCollaborating();
                    showLayerManager();
                }
            }
        };

        TextButton btnNone = new TextButton(z.noneroot != null ? z.noneroot : "None (Root)", skin);
        dlg.button(btnNone, -1);

        for (layer g : groups) {
            TextButton btn = new TextButton(g.getName(), skin);
            dlg.button(btn, g.getId());
        }

        dlg.button(z.cancel, null);
        dlg.show(stage);
    }

