    private void refreshMacroTerrainInfo() {
        if (lMacroTerrainInfo == null)
            return;
        int count = macroTerrain.getTerrains().size();
        String template = z.macroterraininfo != null ? z.macroterraininfo
                : "Macro terrains (%d) — saved in macro auto.json";
        lMacroTerrainInfo.setText(String.format(template, count));
    }

    int assemblyid = -1;
    int assemblynum = -1;
    boolean assemblymode = false;

    private void loadAutotileList() {
        Table tblmain = new Table();
        Table tbl = new Table();
        ScrollPane sp = new ScrollPane(tbl);
        tblmain.add(sp);
        tblmain.setFillParent(true);
        tbl.defaults().width(btnx).height(btny).padBottom(2);
        // java.util.List<TextButton> at = new ArrayList<TextButton>();

        for (int i = 0; i < autotiles.size(); i++) {
            java.util.List<property> sz = autotiles.get(i).getProperties();
            String type = "";
            String name = "";
            boolean hidden = false;
            int num = 0;
            name = autotiles.get(i).getName();

            for (int j = 0; j < sz.size(); j++) {

                if (sz.get(j).getName().equalsIgnoreCase("type")) {
                    type = sz.get(j).getValue();

                    if (type.equalsIgnoreCase("assembly")) {
                        num = -1;
                    }
                }
                if (sz.get(j).getName().equalsIgnoreCase("source")) {
                    num = Integer.parseInt(sz.get(j).getValue());
                }
                if (sz.get(j).getName().equalsIgnoreCase("hidden")) {
                    hidden = true;
                }

            }
            if (hidden)
                continue;
            if (num == 0)
                continue;
            if (type == "")
                continue;
            switch (type) {
                case "bitmask":
                case "completion":
                case "fill":
                case "assembly":
                    Button tat = new Button(skin);
                    tat.left();
                    int initset = 0;
                    for (int o = 0; o < tilesets.size(); o++) {
                        if (num >= tilesets.get(o).getFirstgid()
                                && num < tilesets.get(o).getFirstgid() + tilesets.get(o).getTilecount()) {
                            initset = o;
                            break;
                        }
                    }
                    resolveSprite(tilesets.get(initset), (int) (num - tilesets.get(initset).getFirstgid()));
                    margin = tilesets.get(initset).getMargin();
                    spacing = tilesets.get(initset).getSpacing();
                    Tswa = tilesets.get(initset).getTilewidth();
                    Tsha = tilesets.get(initset).getTileheight();
                    TextureRegion region = null;
                    region = new TextureRegion(tilesets.get(initset).getTexture(), sprX, sprY, Tsw, Tsh);
                    if (type.equalsIgnoreCase("assembly")) {
                        region = new TextureRegion(txautopick, 96, 96);
                    }
                    Image img2 = new Image(region);
                    tat.add(img2).padRight(10).padLeft(2).padTop(2).padBottom(2).width(ssx / 15f).height(ssx / 15f);
                    String nen = "";
                    if (sShowGID) {
                        nen = name + " (" + num + ")";
                    } else {
                        nen = name;
                    }
                    Label lbl = new Label(nen, skin);
                    lbl.setColor(1, 1, 1, 1);
                    lbl.setWrap(true);
                    tat.add(lbl).width(btnx - 55);

                    if (type.equalsIgnoreCase("assembly")) {
                        tat.setName("ass" + i);
                    } else {
                        tat.setName(num + "");
                    }

                    tat.addListener(new ChangeListener() {
                        @Override
                        public void changed(ChangeEvent event, Actor actor) {
                            String neim = actor.getName();
                            if (neim.startsWith("ass")) {
                                neim = neim.replace("ass", "");
                                int a = Integer.parseInt(neim);
                                // status(autotiles.get( a ).getName(),5);
                                assemblymode = true;
                                assemblyid = a;
                                pickMacroTerrain = false;
                                curpickMacroTerrain = false;

                            } else {
                                curspr = Integer.parseInt(actor.getName());
                                addRecentTile(curspr);
                                if (layers.size() > 3) {
                                    if (layers.get(3).getName().equalsIgnoreCase("Set")) {
                                        selLayer = 3;
                                        layers.get(3).setVisible(true);
                                    }
                                }
                                setTsetFromCurspr();
                                pickMacroTerrain = false;
                                curpickMacroTerrain = false;
                                pickAuto = false;
                                curpickAuto = false;

                            }
                            backToMap();
                        }
                    });
                    tbl.add(tat).height(btny * 1.5f).row();
                    break;
            }
        }
        appendMacroTerrainPickButtons(tbl);
        TextButton tat = new TextButton(z.back, skin);
        tat.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                backToMap();
            }
        });
        tbl.add(tat).row();
        gotoStage(tblmain);
    }

    private void appendMacroTerrainPickButtons(Table tbl) {
        if (macroTerrain.getTerrains().isEmpty())
            return;
        tbl.add(new Label(z.macroterraineditor, skin)).row();
        for (int i = 0; i < macroTerrain.getTerrains().size(); i++) {
            final int idx = i;
            terrain tr = macroTerrain.getTerrains().get(i);
            String name = tr.getName();
            if (name == null || name.length() == 0)
                name = "Terrain " + i;
            addTerrainPickerRow(tbl, name, macroTerrainIconGid(idx), new Runnable() {
                @Override
                public void run() {
                    macroTerrain.setSelTerrain(idx);
                    tile center = ensureMacroTerrainCenterTile(idx);
                    int gid = center != null ? center.getTileID() : tr.getTile();
                    curspr = gid;
                    setTsetFromCurspr();
                    seltset = curtset;
                    adjustLayer(tilesets.get(curtset));
                    pickMacroTerrain = true;
                    pickAuto = false;
                    curpickMacroTerrain = true;
                    curpickAuto = false;
                    refreshAutotileGraph();
                    kartu = "world";
                    stamp = false;
                    assemblymode = false;
                    if (activetool == 1)
                        activetool = 0;
                    backToMap();
                    cue("autopick");
                }
            });
        }
    }

    private void addRecentTile(int num) {

        for (int x = 0; x < 6; x++) {
            if (swatchValue.get(x) == num)
                return;
        }

        if (swatchValue.get(0) == 0) {
            swatchValue.set(0, num);
            addSW(num, "sw1");
            return;
        }
        if (swatchValue.get(1) == 0) {
            swatchValue.set(1, num);
            addSW(num, "sw2");
            return;
        }
        if (swatchValue.get(2) == 0) {
            swatchValue.set(2, num);
            addSW(num, "sw3");
            return;
        }
        if (swatchValue.get(3) == 0) {
            swatchValue.set(3, num);
            addSW(num, "sw4");
            return;
        }
        if (swatchValue.get(4) == 0) {
            swatchValue.set(4, num);
            addSW(num, "sw5");
            return;
        }
        if (swatchValue.get(5) == 0) {
            swatchValue.set(5, num);
            addSW(num, "sw6");
            return;
        }
    }

    private void loadList(String wla) {
        this.wl = wla;
        Table tblmain = new Table();
        Table tbl = new Table();
        ScrollPane sp = new ScrollPane(tbl, skin);

        tblmain.add(sp);
        tblmain.setFillParent(true);
        tbl.defaults().width(btnx).height(btny * 1.5f).padBottom(2);
        // java.util.List<TextButton> at = new ArrayList<TextButton>();
        int tt = 0;
        TextButton tit = new TextButton("+", skin);
        TextButton tut = new TextButton(z.back, skin);

        switch (wl) {
            case "layer":
                showLayerManager();
                break;

            case "tset":
            case "tsetlist":
                showTilesetManager();
                break;
            case "macro":
                // cakwe
                tbl.add(new Label(z.runmacro, skin)).row();

                int macrosize = 0;
                for (int i = 0; i < autotiles.size(); i++) {
                    autotile al = autotiles.get(i);
                    automate am = new automate();

                    for (int j = 0; j < al.getProperties().size(); j++) {

                        property p = al.getProperties().get(j);
                        if (p.getName().equalsIgnoreCase("name")) {
                            ++macrosize;
                            am.name = p.getValue();
                            Button tat = new Button(skin);
                            tat.defaults().left();
                            Image img = null;

                            String name = p.getValue();
                            img = new Image(txplay);
                            tat.add(img).width(btnx * 0.15f).padLeft(10);

                            Label lbl = new Label(name, skin);
                            lbl.setColor(1, 1, 1, 1);
                            lbl.setAlignment(Align.left);
                            lbl.setWrap(true);
                            tat.add(lbl).width(btnx * 0.85f);
                            tat.setName(name);
                            tbl.add(tat).width(btnx).row();

                            tat.addListener(new ChangeListener() {
                                @Override
                                public void changed(ChangeEvent event, Actor actor) {
                                    runAutoTiles(actor.getName());
                                    backToMap();

                                }
                            });

                            continue;
                        }
                    }

                    if (macrosize == 0) {
                        try {
                            runAutoTiles("");
                        } catch (Exception e) {
                            msgbox(e.toString());
                        }
                        backToMap();
                        return;
                    }
                }

                tut.addListener(new ChangeListener() {
                    @Override
                    public void changed(ChangeEvent event, Actor actor) {
                        backToMap();
                    }
                });

                tbl.add(tut).row();
                gotoStage(tblmain);

                break;

            case "object":
                // cakwe
                tbl.add(new Label(z.object, skin)).row();

                int objectsize = 0;
                for (int i = 0; i < selobjs.size(); i++) {
                    obj oo = selobjs.get(i);
                    Button tat = new Button(skin);
                    tat.defaults().left();
                    Image img = null;

                    String name = "[" + oo.getId() + "] " + oo.getName();

                    img = new Image(txTypeObject);
                    tat.add(img).width(btnx * 0.15f).padLeft(10);

                    Label lbl = new Label(name, skin);
                    lbl.setColor(1, 1, 1, 1);
                    lbl.setAlignment(Align.left);
                    lbl.setWrap(true);
                    tat.add(lbl).width(btnx * 0.85f);
                    tat.setUserObject(oo);
                    tbl.add(tat).width(btnx).row();

                    tat.addListener(new ChangeListener() {
                        @Override
                        public void changed(ChangeEvent event, Actor actor) {
                            selobjs.clear();
                            selobjs.add((obj) actor.getUserObject());
                            requestupdatemarker = true;
                            backToMap();

                        }
                    });

                }

                tut.addListener(new ChangeListener() {
                    @Override
                    public void changed(ChangeEvent event, Actor actor) {
                        selobjs.clear();
                        requestupdatemarker = true;
                        backToMap();
                    }
                });

                tbl.add(tut).row();
                gotoStage(tblmain);

                break;
        }

    }

    private void saveViewMode() {
        int vm = 0;
        switch (viewMode) {

            case STACK:
                vm = 1;
                break;
            case SINGLE:
                vm = 2;
                break;
            case ALL:
                vm = 3;
                break;
            case CUSTOM:
                vm = 4;
                break;
            case FOCUSED:
                vm = 5;
                break;
        }
        prefs.putInteger("viewmode", vm).flush();
    }

    private void loadViewMode() {
        int vm = prefs.getInteger("viewmode", 4);

        switch (vm) {
            case 1:
                viewMode = ViewMode.STACK;
                break;
            case 2:
                viewMode = ViewMode.SINGLE;
                break;
            case 3:
                viewMode = ViewMode.ALL;
                break;
            case 4:
                viewMode = ViewMode.CUSTOM;
                break;
            case 5:
                viewMode = ViewMode.FOCUSED;
                break;
        }
    }

