    public void loadautotiles() {
        try {
            autotiles.clear();
            FileHandle f = Gdx.files.absolute(curdir + "/" + curfile + ".auto.json");
            if (!f.exists()) return;
            autotiles at = new autotiles();
            Json json = new Json();
            at = json.fromJson(autotiles.class, f);
            autotiles = at.getAutotiles();
        } catch (Exception e) {
        }
    }

    public void loadMacroAutoTerrain() {
        try {
            FileHandle f = Gdx.files.absolute(curdir + "/" + curfile + ".macro.json");
            if (f.exists())
                macroTerrain.fromJsonString(f.readString());
            else
                macroTerrain.clear();
        } catch (Exception e) {
            macroTerrain.clear();
        }
    }

    public void saveMacroAutoTerrain() {
        if (macroTerrain.isEmpty()) {
            try {
                FileHandle f = Gdx.files.absolute(curdir + "/" + curfile + ".macro.json");
                if (f.exists())
                    f.delete();
            } catch (Exception ignored) {
            }
            return;
        }
        // curdir may be a /saf/ path — writeThisAbs goes through the shim either way.
        writeThisAbs(curdir + "/" + curfile + ".macro.json", macroTerrain.toJsonPretty());
    }

    public void saveRecents() {
        try {
            FileHandle fh2 = Gdx.files.absolute(basepath + "NotTiled/");
            if (!fh2.exists())
                fh2.mkdirs();
            Json json = new Json();
            FileHandle fh = Gdx.files.absolute(basepath + "NotTiled/recents.json");
            fh.writeString(json.prettyPrint(recents), false);
        } catch (Exception e) {
            log("failed to save recents: " + e.getMessage());
        }
    }

