    private int extractMapAttr(String xml, String attr, int fallback) {
        String needle = attr + "=\"";
        int i = xml.indexOf(needle);
        if (i < 0)
            return fallback;
        int start = i + needle.length();
        int end = xml.indexOf('\"', start);
        if (end < 0)
            return fallback;
        try {
            return Integer.parseInt(xml.substring(start, end));
        } catch (NumberFormatException e) {
            return fallback;
        }
    }

    private int[] readTemplateMapDimensions(String templateFolder) {
        int tsw = 20, tsh = 20, tw = 50, th = 50;
        try {
            FileHandle tmx = Gdx.files
                    .absolute(basepath + "NotTiled/sample/template/" + templateFolder + "/template.tmx");
            if (!tmx.exists())
                return new int[] { tsw, tsh, tw, th };
            String head = tmx.readString();
            if (head.length() > 800)
                head = head.substring(0, 800);
            tsw = extractMapAttr(head, "tilewidth", tsw);
            tsh = extractMapAttr(head, "tileheight", tsh);
            tw = extractMapAttr(head, "width", tw);
            th = extractMapAttr(head, "height", th);
        } catch (Exception e) {
            log(e.toString());
        }
        return new int[] { tsw, tsh, tw, th };
    }

    private void applyNewFilePresets(String templateFolder) {
        newFileTemplateFolder = templateFolder;
        int tsw = 32, tsh = 32, tw = 30, th = 30;
        if (templateFolder != null) {
            if (templateFolder.contains("Rusted Warfare")) {
                tsw = 20;
                tsh = 20;
                tw = 100;
                th = 100;
            } else {
                int[] size = readTemplateMapDimensions(templateFolder);
                tsw = size[0];
                tsh = size[1];
                tw = size[2];
                th = size[3];
            }
        }
        fNTsw.setText(String.valueOf(tsw));
        fNTsh.setText(String.valueOf(tsh));
        fNTw.setText(String.valueOf(tw));
        fNTh.setText(String.valueOf(th));
        if (templateFolder != null && templateFolder.toLowerCase().contains("pixel"))
            fNFilename.setText("pixel.tmx");
        else
            fNFilename.setText("Map01.tmx");
    }

