    private void finishNewFileCreation() {
        if (!softcue("newfilecreate") && lockUI)
            return;
        if (fNTsh.getText() == null)
            fNTsh.setText("20");
        if (fNTsw.getText() == null)
            fNTsw.setText("20");
        if (fNTh.getText() == null)
            fNTh.setText("20");
        if (fNTw.getText() == null)
            fNTw.setText("20");

        chooseNewFileLocation();
    }

    /**
     * Internal-storage new file: check for an existing file at the chosen internal
     * directory (overwrite prompt) before creating. The overwrite check lives here,
     * after the location is chosen, rather than blindly at Create time.
     */
    private void finishInternalNewFile() {
        newFileToDevice = false;
        final String dir = fNCurdir.getText().replace("//", "/");
        final String file = fNFilename.getText();
        final FileHandle target = Gdx.files.absolute(dir + "/" + file);
        if (target.exists()) {
            Dialog dlg = new Dialog(z.confirmation, skin, "dialog") {
                @Override
                protected void result(Object object) {
                    if (Boolean.TRUE.equals(object)) {
                        // Delete existing file and associated terrain files
                        target.delete();
                        FileHandle autoF = Gdx.files.absolute(dir + "/" + file + ".auto.json");
                        if (autoF.exists()) autoF.delete();
                        FileHandle macroF = Gdx.files.absolute(dir + "/" + file + ".macro.json");
                        if (macroF.exists()) macroF.delete();
                        doFinishNewFile();
                    }
                }
            };
            dlg.text(file + " already exists. Overwrite?");
            dlg.button(z.yes, true);
            dlg.button(z.no, false);
            dlg.show(stage);
            return;
        }
        doFinishNewFile();
    }

    /**
     * After pressing Create, ask where the new map should live: Device/Cloud (top,
     * the recommended default so files don't get lost in internal storage) or
     * Internal. This is asked here rather than via a directory field so a user who
     * ignores it doesn't silently end up internal-only.
     */
    private void chooseNewFileLocation() {
        final Dialog dlg = new Dialog("", skin, "dialog");
        Table ct = dlg.getContentTable();
        ct.pad(20);
        final float bw = getDialogContentWidth();
        ct.add(new Label("Where should your map be saved?", skin)).width(bw).pad(10).row();
        // Plain-language consequences: "Internal Storage" reads as "my phone" to
        // most users, who then can't find their file in any file manager.
        TextButton bDevice = new TextButton(
                (z.browseDevice != null ? z.browseDevice : "Browse Device / Cloud")
                        + "\nRecommended - visible in your Files app",
                skin);
        bDevice.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                dlg.hide();
                grantFolderThenFinishNewFile();
            }
        });
        ct.add(bDevice).width(bw).height(btny * 1.6f).pad(5).row();
        TextButton bInternal = new TextButton(
                "App storage\nHidden from other apps - deleted if you uninstall", skin);
        bInternal.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                dlg.hide();
                finishInternalNewFile();
            }
        });
        ct.add(bInternal).width(bw).height(btny * 1.6f).pad(5).row();
        dlg.show(stage);
    }

    /**
     * Grant a Device/Cloud folder, then create the new map into it. If the user
     * cancels the folder picker, falls back to creating the file internally so it
     * is never lost.
     */
    private void grantFolderThenFinishNewFile() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                String st = "";
                face.selectFolder();
                while (st.equalsIgnoreCase("")) {
                    st = face.getStatus();
                    try { Thread.sleep(16); } catch (InterruptedException ignored) {}
                }
                final boolean granted = st.equalsIgnoreCase("OK") && face.hasTreeAccess();
                Gdx.app.postRunnable(new Runnable() {
                    @Override
                    public void run() {
                        newFileToDevice = granted; // cancelled grant → internal fallback
                        doFinishNewFile();
                    }
                });
            }
        }).start();
    }

    private void doFinishNewFile() {
        prefs.putString("Tsw", fNTsw.getText());
        prefs.putString("Tsh", fNTsh.getText());
        prefs.putString("Tw", fNTw.getText());
        prefs.putString("Th", fNTh.getText());
        prefs.flush();
        final boolean toDevice = newFileToDevice;
        newFileToDevice = false; // consume the flag
        if (toDevice) {
            // Create the map directly in the granted device/cloud folder (SAF shim root).
            fNCurdir.setText(safRootDir());
        }
        backToMap();
        if (newFileTemplateFolder != null) {
            selectTemplateFolder(newFileTemplateFolder);
            newtmxfileplus(true);
            cue("newfilecreate");
        } else {
            newtmxfile(true);
            cue("newmap");
        }
        if (toDevice) {
            saveMap(curdir + "/" + curfile); // initial save so the file appears there now
        }
        mapDirty = false;
        if (tilesets.isEmpty()) {
            // An empty map is a dead end for a beginner: no tiles, silent taps.
            // Offer the way forward immediately.
            Gdx.input.setInputProcessor(stage);
            Dialog dlg = new Dialog("", skin, "dialog") {
                @Override
                protected void result(Object o) {
                    Gdx.input.setInputProcessor(im);
                    if (Boolean.TRUE.equals(o)) {
                        showAddTilesetDialog();
                    }
                }
            };
            Label lab = new Label(
                    "This map has no tileset yet — you need one before you can draw.",
                    skin);
            lab.setWrap(true);
            dlg.getContentTable().add(lab).width(btnx).pad(10).row();
            dlg.button(z.addnew != null ? z.addnew + " " + z.tileset : "Add tileset", true);
            dlg.button("Later", false);
            dlg.show(stage);
        }
    }

