    public void getNewTextInput(TextPromptListener tpl, String title, String value, String hint) {
        GDXTextPrompt textPrompt = dialogs.newDialog(GDXTextPrompt.class);
        textPrompt.setTitle(title);
        textPrompt.setMessage(hint);
        textPrompt.setValue(value);
        textPrompt.setMaxLength(1000);
        textPrompt.setCancelButtonLabel(z.cancel);
        textPrompt.setConfirmButtonLabel(z.ok);
        textPrompt.setTextPromptListener(tpl);
        textPrompt.build().show();
    }

    public void showFileManager(final FileHandle dir) {
        if (fmTxBack == null)
            fmTxBack = new Texture(Gdx.files.internal("images/up96.png"));
        if (fmTxFolder == null)
            fmTxFolder = new Texture(Gdx.files.internal("images/folder96.png"));
        if (fmTxFile == null)
            fmTxFile = new Texture(Gdx.files.internal("images/file96.png"));

        if (dir == null) {
            fileManagerDir = resolveFileManagerStartDir();
        } else {
            fileManagerDir = dir;
        }

        if (!fileManagerDir.exists()) {
            fileManagerDir.mkdirs();
        }

        tFileManager = new Table();
        tFileManager.setFillParent(true);
        tFileManager.top().left();

        Table topBar = new Table(skin);
        topBar.left().pad(10);
        topBar.defaults().left().pad(5);

        String relativePath = fileManagerDir.path().replace(basepath, "");
        if (relativePath.startsWith("/"))
            relativePath = relativePath.substring(1);
        Label pathLabel = new Label("NotTiled / " + relativePath, skin);
        pathLabel.setWrap(true);
        topBar.add(pathLabel).expandX().fillX().colspan(3).row();

        // Clear Temp Cache button — shown with current cache size
        final FileHandle tempDir = Gdx.files.absolute(basepath + "NotTiled/Temp");
        if (tempDir.exists()) {
            long tempBytes = folderSize(tempDir);
            String sizeStr = tempBytes > 1024 * 1024
                    ? String.format("%.1f MB", tempBytes / (1024.0 * 1024.0))
                    : String.format("%d KB", tempBytes / 1024);
            String clearLabel = (z.clearTempCache != null ? z.clearTempCache : "Clear Temp Cache")
                    + " (" + sizeStr + ")";
            TextButton btnClearTemp = new TextButton(clearLabel, skin);
            btnClearTemp.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    Dialog confirm = new Dialog("", skin, "dialog") {
                        @Override
                        protected void result(Object obj) {
                            if ((boolean) obj) {
                                deleteRecursiveHandle(tempDir);
                                tempDir.mkdirs();
                                showFileManager(fileManagerDir);
                            }
                        }
                    };
                    String msg = z.clearTempCacheConfirm != null ? z.clearTempCacheConfirm
                            : "Delete all cached files in NotTiled/Temp?";
                    confirm.getContentTable().add(new Label(msg, skin)).pad(20).row();
                    confirm.button(z.yes != null ? z.yes : "Yes", true);
                    confirm.button(z.cancel, false);
                    confirm.show(stage);
                }
            });
            topBar.add(btnClearTemp).expandX().fillX().colspan(3).padBottom(6).row();
        }

        TextButton btnNewFolder = new TextButton(z.addnew + " " + z.directory, skin);
        btnNewFolder.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                getNewTextInput(new TextPromptListener() {
                    @Override
                    public void confirm(String input) {
                        if (input != null && !input.trim().isEmpty()) {
                            FileHandle newDir = fileManagerDir.child(input.trim());
                            newDir.mkdirs();
                            showFileManager(fileManagerDir);
                        }
                    }

                    @Override
                    public void cancel() {
                    }
                }, z.addnew + " " + z.directory, "", "Folder name:");
            }
        });

        // Initialize active stage dimensions
        float stageWidth = stage.getWidth();

        float btnNewFolderWidth;
        if (fileManagerClipboardFile != null && fileManagerClipboardFile.exists()) {
            btnNewFolderWidth = stageWidth * 0.3f;
        } else {
            btnNewFolderWidth = stageWidth * 0.5f;
        }
        topBar.add(btnNewFolder).width(btnNewFolderWidth).height(btny);

        if (fileManagerClipboardFile != null && fileManagerClipboardFile.exists()) {
            TextButton btnPaste = new TextButton(z.paste + " (" + (fileManagerIsCopy ? z.copy : z.move) + ")", skin);
            btnPaste.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    try {
                        FileHandle dest = fileManagerDir.child(fileManagerClipboardFile.name());
                        if (fileManagerIsCopy) {
                            fileManagerClipboardFile.copyTo(dest);
                        } else {
                            fileManagerClipboardFile.moveTo(dest);
                            fileManagerClipboardFile = null;
                        }
                        showFileManager(fileManagerDir);
                    } catch (Exception e) {
                        e.printStackTrace();
                        msgbox(e.getMessage());
                    }
                }
            });
            topBar.add(btnPaste).width(stageWidth * 0.35f).height(btny);

            TextButton btnCancelPaste = new TextButton(z.cancel, skin);
            btnCancelPaste.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    fileManagerClipboardFile = null;
                    showFileManager(fileManagerDir);
                }
            });
            topBar.add(btnCancelPaste).width(stageWidth * 0.25f).height(btny);
        }
        tFileManager.add(topBar).expandX().fillX().row();

        Table listTable = new Table(skin);
        listTable.top().left();
        listTable.defaults().left().pad(5);

        String limitPath = basepath + "NotTiled";
        if (fileManagerDir.path().length() > limitPath.length()) {
            listTable.row();
            Image img = new Image(fmTxBack);
            listTable.add(img).size(48, 48);

            Label upLabel = new Label("..", skin);
            upLabel.addListener(new ClickListener() {
                @Override
                public void clicked(InputEvent event, float x, float y) {
                    showFileManager(fileManagerDir.parent());
                }
            });
            listTable.add(upLabel).expandX().fillX().colspan(5).row();
        }

        FileHandle[] children = fileManagerDir.list();
        java.util.Arrays.sort(children, new java.util.Comparator<FileHandle>() {
            @Override
            public int compare(FileHandle o1, FileHandle o2) {
                if (o1.isDirectory() && !o2.isDirectory())
                    return -1;
                if (o2.isDirectory() && !o1.isDirectory())
                    return 1;
                return o1.name().compareToIgnoreCase(o2.name());
            }
        });

        for (final FileHandle child : children) {
            listTable.row().pad(5);
            Image typeImg = new Image(child.isDirectory() ? fmTxFolder : fmTxFile);
            listTable.add(typeImg).size(48, 48).padRight(10);

            Label nameLabel = new Label(child.name(), skin);
            nameLabel.setWrap(true);
            if (child.isDirectory()) {
                nameLabel.setColor(1f, 1f, 0f, 1f);
            }

            ClickListener rowClickListener = new ClickListener() {
                @Override
                public void clicked(InputEvent event, float x, float y) {
                    if (child.isDirectory()) {
                        showFileManager(child);
                    } else if (isPreviewableImageFile(child)) {
                        showImageFilePreview(child);
                    } else {
                        showOptionsDialog(child);
                    }
                }
            };
            typeImg.addListener(rowClickListener);
            nameLabel.addListener(rowClickListener);

            listTable.add(nameLabel).expandX().fillX().width(stageWidth - 200f);

            TextButton btnOpt = new TextButton("...", skin);
            btnOpt.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    showOptionsDialog(child);
                }
            });
            listTable.add(btnOpt).width(80f).height(btny).padLeft(10);
        }

        ScrollPane listPane = new ScrollPane(listTable, skin);
        listPane.setScrollingDisabled(true, false);
        tFileManager.add(listPane).expand().fill().pad(10).row();

        Table bottomBar = new Table(skin);
        bottomBar.defaults().center().pad(5);
        TextButton btnBack = new TextButton(z.back, skin);
        btnBack.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                gotoStage(tMenu);
            }
        });
        bottomBar.add(btnBack).width(Math.min(stageWidth * 0.6f, 300f)).height(btny);
        tFileManager.add(bottomBar).expandX().fillX().pad(10);

        gotoStage(tFileManager);
    }

    private long folderSize(FileHandle dir) {
        long total = 0;
        if (!dir.exists()) return 0;
        for (FileHandle child : dir.list()) {
            total += child.isDirectory() ? folderSize(child) : child.length();
        }
        return total;
    }

    private void deleteRecursiveHandle(FileHandle fh) {
        if (fh.isDirectory()) {
            for (FileHandle child : fh.list()) deleteRecursiveHandle(child);
        }
        fh.delete();
    }

    private FileHandle resolveFileManagerStartDir() {
        if (curdir != null && !curdir.isEmpty()) {
            FileHandle projectDir = Gdx.files.absolute(curdir);
            if (projectDir.exists() && projectDir.isDirectory())
                return projectDir;
        }
        return Gdx.files.absolute(basepath + "NotTiled");
    }

    private boolean isPreviewableImageFile(FileHandle file) {
        if (file == null || file.isDirectory())
            return false;
        String ext = file.extension().toLowerCase();
        return ext.equals("png") || ext.equals("jpg") || ext.equals("jpeg") || ext.equals("webp")
                || ext.equals("gif");
    }

    private void showImageFilePreview(FileHandle imageFile) {
        try {
            Pixmap pm = new Pixmap(imageFile);
            showPixmapPreviewDialog(pm, imageFile.name(), false, null);
        } catch (Exception e) {
            ErrorBung(e, "errorlog.txt");
            msgbox(z.error);
        }
    }

    private void showPixmapPreviewDialog(final Pixmap pixmap, String title, final boolean offerSave,
            final Runnable onSave) {
        if (pixmap == null)
            return;
        final Pixmap retainedPixmap = offerSave ? pixmap : null;
        final Texture tex = new Texture(pixmap);
        tex.setFilter(Texture.TextureFilter.Linear, Texture.TextureFilter.Linear);
        if (!offerSave)
            pixmap.dispose();

        final Dialog previewDlg = new Dialog("", skin, "dialog") {
            @Override
            protected void result(Object object) {
                tex.dispose();
                boolean save = Boolean.TRUE.equals(object) && onSave != null;
                if (save) {
                    onSave.run();
                } else if (retainedPixmap != null && !retainedPixmap.isDisposed()) {
                    retainedPixmap.dispose();
                }
                backToMap();
            }
        };
        Table content = previewDlg.getContentTable();
        Label titleLabel = new Label(title != null ? title : "Preview", skin);
        titleLabel.setAlignment(Align.center);
        content.add(titleLabel).width(getDialogContentWidth()).pad(8).row();

        Image img = new Image(new TextureRegionDrawable(new TextureRegion(tex)));
        float maxW = stage.getWidth() * 0.92f;
        float maxH = stage.getHeight() * 0.72f;
        float scale = Math.min(maxW / tex.getWidth(), maxH / tex.getHeight());
        if (scale > 1f)
            scale = 1f;
        float displayW = tex.getWidth() * scale;
        float displayH = tex.getHeight() * scale;

        Table imgHost = new Table();
        imgHost.add(img).width(displayW).height(displayH);
        if (displayW <= maxW && displayH <= maxH) {
            content.add(imgHost).pad(8).row();
        } else {
            ScrollPane scrollPane = new ScrollPane(imgHost, skin);
            scrollPane.setFadeScrollBars(false);
            scrollPane.setForceScroll(false, false);
            content.add(scrollPane).width(maxW).height(maxH).pad(8).row();
        }

        if (offerSave && onSave != null)
            previewDlg.button(z.save, true);
        previewDlg.button(z.back, false);
        previewDlg.getButtonTable().defaults().height(btny).pad(4);
        Gdx.input.setInputProcessor(stage);
        previewDlg.show(stage);
    }

    private String resolveUniqueExportFilename(String preferredName, String ext) {
        String lowerExt = ext.toLowerCase();
        if (!lowerExt.startsWith("."))
            lowerExt = "." + lowerExt;

        String base = preferredName;
        if (base == null || base.isEmpty()) {
            if (curfile != null && !curfile.isEmpty()) {
                int dot = curfile.lastIndexOf('.');
                base = dot > 0 ? curfile.substring(0, dot) : curfile;
            } else {
                base = "export";
            }
        }
        if (base.toLowerCase().endsWith(lowerExt))
            base = base.substring(0, base.length() - lowerExt.length());
        else {
            int dot = base.lastIndexOf('.');
            if (dot > 0)
                base = base.substring(0, dot);
        }

        FileHandle dir = Gdx.files.absolute(curdir != null && !curdir.isEmpty() ? curdir : basepath + "NotTiled");
        String first = base + lowerExt;
        if (!dir.child(first).exists())
            return first;
        for (int n = 2; n < 10000; n++) {
            String candidate = base + n + lowerExt;
            if (!dir.child(candidate).exists())
                return candidate;
        }
        return base + "_" + System.currentTimeMillis() + lowerExt;
    }

    private void previewMapCover() {
        if (curfile == null || curfile.isEmpty()) {
            msgbox(z.saveas != null ? z.saveas : "Save the map first.");
            return;
        }
        Gdx.app.postRunnable(new Runnable() {
            @Override
            public void run() {
                boolean batchWasDrawing = batch.isDrawing();
                try {
                    if (batchWasDrawing)
                        batch.end();
                    final Pixmap scaled = buildMapCoverPixmap(isRustedWarfareMap());
                    if (scaled == null) {
                        msgbox(z.error);
                        return;
                    }
                    repairOverlayTextures();
                    String previewTitle = mapCoverOutputBasename() + "_map.png";
                    showPixmapPreviewDialog(scaled, previewTitle, true, new Runnable() {
                        @Override
                        public void run() {
                            saveMapCoverPixmap(scaled);
                        }
                    });
                } catch (Exception e) {
                    msgbox(z.error);
                    ErrorBung(e, "errorlog.txt");
                } finally {
                    if (batchWasDrawing && !batch.isDrawing())
                        batch.begin();
                }
            }
        });
    }

    private void saveMapCoverPixmap(Pixmap scaled) {
        if (scaled == null)
            return;
        try {
            FileHandle fh = Gdx.files.absolute(curdir + "/" + mapCoverOutputBasename() + "_map.png");
            if (!fh.parent().exists())
                fh.parent().mkdirs();
            PixmapIO.writePNG(fh, scaled);
            status(z.screenshotsaved != null ? z.screenshotsaved : "Screenshot saved", 2);
            cue("screenshot");
        } catch (Exception e) {
            msgbox(z.error);
            ErrorBung(e, "errorlog.txt");
        } finally {
            if (!scaled.isDisposed())
                scaled.dispose();
        }
    }

