    public void tujuanDialog(String dialog, FileHandle file) {
        openedfile = file.path();
        switch (dialog) {
            case "propfile":
                bPropValfile.setText(file.name());
                break;
            case "proppng":
                byte[] fileContent = file.readBytes();
                String asu = android.util.Base64.encodeToString(fileContent, 0);
                fPropVal.setText(asu);
                break;
            case "open":
                if (file.extension().equalsIgnoreCase("ntp")) {
                    log("loading ntp");
                    backToMap();
                    curdir = file.parent().path();
                    log("file :" + file.name());

                    FileHandle tmpfolder = Gdx.files.absolute(basepath + "NotTiled/Temp");
                    log("tmpfolder :" + tmpfolder);
                    unzip(file, tmpfolder);
                    recents.addrecent(file.path(), file.name(), "legacy");
                    saveRecents();
                    requesttomainthread("play", "");
                    addandsaverecent(file.path(), file.name());
                } else if (file.extension().equalsIgnoreCase("tmx")) {
                    log("loading tmx");
                    curdir = file.parent().path();
                    loadtmx(openedfile);

                    addandsaverecent(file.path(), file.name());
                } else if (file.extension().equalsIgnoreCase("png")) {
                    log("loading png");
                    curdir = file.parent().path();
                    loadpng(file);
                } else if (file.extension().equalsIgnoreCase("json")) {
                    log("loading json");
                    curdir = file.parent().path();
                    loadjsonmap(file);
                } else {
                    status(z.error, 5);
                }

                break;
            case "background":
                requesttomainthread("background", openedfile);
                break;
            case "customfont":
                tfCustomFont.setText(openedfile);
                break;
            case "imagesource":
                FileHandle f = file;
                tfImageSource.setText(convertToRelativePath(curdir, f.path()));

                break;
            case "saveas":
                saveasdir = file.path();
                getNewTextInput(pSaveAs, z.saveas, "new.tmx", "");

                break;

            case "importassets":
                status(z.filesaved, 4);
                break;
            case "selfoldercollection":
                showCollectionFileSelectDialog(Gdx.files.absolute(file.path()), -1, false,
                        frompick ? nullTable : tTsetMgrMain);
                break;
            case "selfoldertsx":
                showCollectionFileSelectDialog(Gdx.files.absolute(file.path()), -1, true,
                        frompick ? nullTable : tTsetMgrMain);
                break;
            case "pickcollectionappend":
                if (selTsetID >= 0 && selTsetID < tilesets.size())
                    showCollectionFileSelectDialog(Gdx.files.absolute(file.path()), selTsetID, false,
                            frompick ? nullTable : tTsetMgrMain);
                break;
            case "addcollectiontiles":
                if (selTsetID >= 0 && selTsetID < tilesets.size())
                    showCollectionFileSelectDialog(Gdx.files.absolute(file.path()), selTsetID, false,
                            frompick ? nullTable : tTsetMgrMain);
                break;
            case "selfolder":

                errors = "";
                String dir = file.path();
                FileHandle[] filehandles;
                filehandles = Gdx.files.absolute(dir).list();
                int tsxFromFolder = 0;
                for (int i = 0; i < filehandles.length; i++) {

                    switch (filehandles[i].extension().toLowerCase()) {
                        case "tsx": {
                            int before = tilesets.size();
                            loadtsx(filehandles[i], tilesets, curdir);
                            if (tilesets.size() > before)
                                tsxFromFolder++;
                        }
                            break;
                        case "png":
                        case "jpg":
                        case "jpeg":
                        case "gif":
                        case "bmp":
                            addImageTset(filehandles[i]);
                            break;

                    }
                }
                if (tsxFromFolder > 0)
                    rebuildAllCollectionTilesets(curdir);
                CacheAllTset();
                int saiz = tilesets.size();
                String[] srr = new String[saiz];
                for (int i = 0; i < saiz; i++) {
                    srr[i] = tilesets.get(i).getName();
                }
                ltsetlist.setItems(srr);
                ltsetlist.setSelectedIndex(saiz - 1);
                status(errors, 5);
                pushUpdateIfCollaborating();
                if (frompick) {
                    seltset = Math.max(0, saiz - 1);
                    showTilesetManager();
                }

                break;
            case "seltsx":
                errors = "";

                loadingfile = true;
                loadtsx(file, tilesets, curdir);

                saiz = tilesets.size();
                srr = new String[saiz];
                for (int i = 0; i < saiz; i++) {
                    srr[i] = tilesets.get(i).getName();
                }
                ltsetlist.setItems(srr);
                ltsetlist.setSelectedIndex(saiz - 1);
                CacheAllTset();
                status(errors, 5);
                pushUpdateIfCollaborating();
                loadingfile = false;
                if (frompick) {
                    seltset = Math.max(0, saiz - 1);
                    showTilesetManager();
                }
                break;
            case "newseldir":
                String path = file.path();

                if (path.length() >= 0) {
                    prefs.putString("lastpath", path).flush();
                    fNCurdir.setText(path);
                }

                break;
            case "quickaddtset":
                thefile = file;
                Gdx.app.log("", file.extension() + "||||" + file.path());
                if (file.extension().equalsIgnoreCase("tmx")) {
                    requesttomainthread("tmximport", file.path());
                } else {
                    fImportWidth.setText(Tsw + "");
                    fImportHeight.setText(Tsh + "");
                    cImportEmbed.setChecked(false);
                    gotoStage(tImport);
                    cue("import");
                    resetcam(false);
                }
                return;

            case "addtset":
                thefile = file;
                fImportWidth.setText(Tsw + "");
                fImportHeight.setText(Tsh + "");
                cImportEmbed.setChecked(false);
                gotoStage(tImport);

                return;

            // change source button
            case "replacetset":
                f = file;
                fTsPropSource.setText(convertToRelativePath(curdir, f.path()));
                CacheAllTset();
                break;
        }
    }

    public void addImageTset(FileHandle f) {
        try {
            SimpleImageInfo s = new SimpleImageInfo(f.read());
            tileset t = new tileset();
            String nn = f.name();
            if (f.name().indexOf(".") > 0) {
                nn = f.name().substring(0, f.name().lastIndexOf("."));
            }
            t.setName(nn);

            t.setSource(convertToRelativePath(curdir, f.path()));

            int Tswa = Tsw;
            int Tsha = Tsh;
            if (!fImportWidth.getText().equalsIgnoreCase("")) {
                Tswa = Integer.parseInt(fImportWidth.getText());
                Tsha = Integer.parseInt(fImportHeight.getText());
            }
            t.setOriginalwidth(s.getWidth());
            t.setOriginalheight(s.getHeight());
            t.setColumns(s.getWidth() / Tswa);
            t.setTilecount((s.getHeight() / Tswa) * (s.getWidth() / Tsha));
            if (t.getTilecount() == 0)
                t.setTilecount(1);
            t.setWidth(s.getWidth() / Tswa);
            t.setHeight(s.getHeight() / Tsha);
            t.setTilewidth(Tswa);
            t.setTileheight(Tsha);
            t.setTrans("");
            t.setTexture(new Texture(f));
            t.setPixmap(pixmapfromtexture(t.getTexture(), t.getTrans()));

            t.setFirstgid(allocateFirstgid(t.getTilecount()));

            if (cImportEmbed.isChecked()) {
                byte[] fileContent = f.readBytes();
                String asu = android.util.Base64.encodeToString(fileContent, 0);
                property po = new property("embedded_png", asu);
                t.getProperties().add(po);
                t.setSource("");
                cImportEmbed.setChecked(false);
            }
            curspr = t.getFirstgid();
            tilesets.add(t);
            recenterpick();
        } catch (Exception e) {
            errors += "\nError: " + f.name();
            ErrorBung(e, "eRRROBUNG.txt");
        }
    }

    private tileset addPixelArtTilesetFromFile(FileHandle f, boolean embed) {
        try {
            SimpleImageInfo s = new SimpleImageInfo(f.read());
            tileset t = new tileset();
            String nn = f.name();
            if (f.name().indexOf(".") > 0)
                nn = f.name().substring(0, f.name().lastIndexOf("."));
            t.setName(nn);
            t.setSource(convertToRelativePath(curdir, f.path()));
            t.setOriginalwidth(s.getWidth());
            t.setOriginalheight(s.getHeight());
            t.setTilewidth(1);
            t.setTileheight(1);
            t.setColumns(s.getWidth());
            t.setWidth(s.getWidth());
            t.setHeight(s.getHeight());
            t.setTilecount(s.getWidth() * s.getHeight());
            if (t.getTilecount() == 0)
                t.setTilecount(1);
            t.setTrans("");
            t.setTexture(new Texture(f));
            t.setPixmap(pixmapfromtexture(t.getTexture(), t.getTrans()));
            t.setFirstgid(allocateFirstgid(t.getTilecount()));
            if (embed) {
                byte[] fileContent = f.readBytes();
                String asu = android.util.Base64.encodeToString(fileContent, 0);
                t.getProperties().add(new property("embedded_png", asu));
                t.setSource("");
            }
            tilesets.add(t);
            return t;
        } catch (Exception e) {
            errors += "\nError: " + f.name();
            ErrorBung(e, "eRRROBUNG.txt");
            return null;
        }
    }

    private tileset addPixelArtTilesetFromPixmap(Pixmap pm, String name, boolean embed) {
        tileset t = new tileset();
        t.setName(name);
        t.setSource(name.toLowerCase() + ".png");
        t.setTilewidth(1);
        t.setTileheight(1);
        t.setColumns(pm.getWidth());
        t.setWidth(pm.getWidth());
        t.setHeight(pm.getHeight());
        t.setTilecount(pm.getWidth() * pm.getHeight());
        t.setOriginalwidth(pm.getWidth());
        t.setOriginalheight(pm.getHeight());
        t.setTrans("");
        Pixmap copy = new Pixmap(pm.getWidth(), pm.getHeight(), pm.getFormat());
        copy.drawPixmap(pm, 0, 0);
        t.setPixmap(copy);
        t.setTexture(new Texture(copy));
        t.setFirstgid(allocateFirstgid(t.getTilecount()));
        if (embed) {
            FileHandle tmp = Gdx.files.local(".pixel_palette_import.png");
            try {
                PixmapIO.writePNG(tmp, copy);
                byte[] fileContent = tmp.readBytes();
                String asu = android.util.Base64.encodeToString(fileContent, 0);
                t.getProperties().add(new property("embedded_png", asu));
                t.setSource("");
            } finally {
                if (tmp.exists())
                    tmp.delete();
            }
        }
        tilesets.add(t);
        return t;
    }

