    public void resetMinimap() {

        if (landscape) {
            if (Tsw * Tw > Tsh * Th) {
                minicam.zoom = ((Tw * Tsw * ((Tsw * Tw) / (ssy / 8))) / (Tw * Tsw));
            } else {
                minicam.zoom = ((Th * Tsh * ((Tsh * Th) / (ssy / 8))) / (Th * Tsh));
            }

            minicam.position.set(0, 0, 0);
            minicam.update();
            Vector3 ve, vo;
            ve = uicam.project(new Vector3((gui.minimap.getXl() + 1f) / 100 * ssy,
                    ssx - ((gui.minimap.getHl() - 1f) / 100 * ssx), 0));
            vo = minicam.unproject(ve);
            minicam.position.set(-vo.x, -vo.y, 0);
            if (orientation.equalsIgnoreCase("isometric")) {
                minicam.position.set(minicam.position.x - (Tsw * Tw / 2), minicam.position.y, minicam.position.z);
            }

        } else {
            if (Tsw * Tw > Tsh * Th) {
                minicam.zoom = ((Tw * Tsw * ((Tsw * Tw) / (ssy / 8))) / (Tw * Tsw));
            } else {
                minicam.zoom = ((Th * Tsh * ((Tsh * Th) / (ssy / 8))) / (Th * Tsh));
            }
            minicam.position.set(0, 0, 0);
            minicam.update();
            Vector3 ve, vo;
            ve = uicam.project(new Vector3((gui.minimap.getX() + 1f) / 100 * ssx,
                    ssy - ((gui.minimap.getH() - 1f) / 100 * ssy), 0));
            vo = minicam.unproject(ve);
            minicam.position.set(-vo.x, -vo.y, 0);
            if (orientation.equalsIgnoreCase("isometric")) {
                minicam.position.set(minicam.position.x - (Tsw * Tw / 2), minicam.position.y, minicam.position.z);
            }
        }
        // status(ve.x+" - "+ve.y,5f);
        // minicam.update();

        // minicam.position.set(Tw*Tsw*3.5f,-Tw*Tsw*1.47f,0);
        // }else{
        // minicam.zoom = ((Th * Tsh * ((Tsh * Th) / 200f)) / (Th * Tsh));
        // minicam.position.set(Th*Tsh*3.5f,-Th*Tsh*1.47f,0);
        // }

        minicam.update();

    }

    public boolean isFarAwayFromMap() {
        int onset = 0;
        if (orientation.equalsIgnoreCase("isometric")) {
            onset = Tsw * Tw / 2;
        }
        float toleranceX = Math.max(200f, Tsw * Tw * 0.1f);
        float toleranceY = Math.max(200f, Tsh * Th * 0.1f);
        return cam.position.x < 0 - onset - toleranceX ||
                cam.position.x > Tsw * Tw - onset + toleranceX ||
                cam.position.y < -Tsh * Th - toleranceY ||
                cam.position.y > 0 + toleranceY;
    }

    private void clampCamToMap() {
        if (orientation.equalsIgnoreCase("isometric") || sNoScrollBoundary)
            return;
        int onset = 0;
        if (cam.position.x < 0 - onset)
            cam.position.x = 0 - onset;
        if (cam.position.x > Tsw * Tw - onset)
            cam.position.x = Tsw * Tw - onset;
        if (cam.position.y < -Tsh * Th)
            cam.position.y = -Tsh * Th;
        if (cam.position.y > 0)
            cam.position.y = 0;
    }

    private boolean isPixelArtMap() {
        for (property p : properties) {
            if (p.getName().equalsIgnoreCase("type") && p.getValue().equalsIgnoreCase("Pixel Editor"))
                return true;
        }
        return false;
    }

    /**
     * Pixel Editor maps have map property type=Pixel Editor; tileset 0=swatch,
     * 1=palette.
     */
    private int getPixelArtSwatchIndex() {
        if (!isPixelArtMap() || tilesets.size() <= PixelArtPalette.SWATCH_TSET_INDEX)
            return -1;
        return PixelArtPalette.SWATCH_TSET_INDEX;
    }

    private int getPixelArtPaletteIndex() {
        if (!isPixelArtMap() || tilesets.size() <= PixelArtPalette.PALETTE_TSET_INDEX)
            return -1;
        return PixelArtPalette.PALETTE_TSET_INDEX;
    }

    /** Swatch (0) and palette (1) must stay on Pixel Editor maps. */
    private boolean isProtectedPixelArtTileset(int index) {
        if (!isPixelArtMap() || index < 0)
            return false;
        return index == PixelArtPalette.SWATCH_TSET_INDEX || index == PixelArtPalette.PALETTE_TSET_INDEX;
    }

    private void initPixelArtTilesets() {
        if (!isPixelArtMap())
            return;
        pixelPaletteMode = PIXEL_PAL_NONE;
        pixelEditSlot = -1;
        loadPaletteUsedCount();
        int pal = getPixelArtPaletteIndex();
        if (pal >= 0) {
            seltset = pal;
            curtset = pal;
            recenterpick();
        }
        refreshAiSpriteButton();
    }

    private void loadPaletteUsedCount() {
        if (!isPixelArtMap())
            return;
        pixelPaletteUsedCount = -1;
        for (property p : properties) {
            if (p.getName().equalsIgnoreCase(PixelArtPalette.PROP_PALETTE_COUNT)) {
                try {
                    pixelPaletteUsedCount = Integer.parseInt(p.getValue());
                } catch (NumberFormatException ignored) {
                }
                break;
            }
        }
        if (pixelPaletteUsedCount < 1) {
            int pal = getPixelArtPaletteIndex();
            pixelPaletteUsedCount = pal >= 0 ? tilesets.get(pal).getTilecount() : 8;
        }
    }

    private void savePaletteUsedCount() {
        if (!isPixelArtMap())
            return;
        boolean found = false;
        for (property p : properties) {
            if (p.getName().equalsIgnoreCase(PixelArtPalette.PROP_PALETTE_COUNT)) {
                p.setValue(Integer.toString(pixelPaletteUsedCount));
                found = true;
                break;
            }
        }
        if (!found)
            properties.add(new property(PixelArtPalette.PROP_PALETTE_COUNT,
                    Integer.toString(pixelPaletteUsedCount)));
    }

    private void goToSwatchTileset() {
        int sw = getPixelArtSwatchIndex();
        if (sw >= 0) {
            seltset = sw;
            curtset = sw;
            recenterpick();
        }
    }

    private int getSelectedPaletteSlot() {
        if (!isPixelArtMap())
            return -1;
        if (pixelEditSlot >= 0)
            return pixelEditSlot;
        for (int i = 0; i < massprops.size(); i++) {
            if (massprops.get(i))
                return i;
        }
        int palIdx = getPixelArtPaletteIndex();
        if (palIdx >= 0) {
            tileset palette = tilesets.get(palIdx);
            if (curspr >= palette.getFirstgid()
                    && curspr < palette.getFirstgid() + palette.getTilecount())
                return curspr - palette.getFirstgid();
        }
        return -1;
    }

    private void ensureTilesetPixmap(tileset ts) {
        if (ts.getPixmap() == null && ts.getTexture() != null)
            ts.setPixmap(pixmapfromtexture(ts.getTexture(), ts.getTrans() != null ? ts.getTrans() : ""));
    }

    private void pickPaletteSlotAndMap(int slot) {
        int palIdx = getPixelArtPaletteIndex();
        if (palIdx < 0 || slot < 0)
            return;
        tileset palette = tilesets.get(palIdx);
        curtset = palIdx;
        curspr = palette.getFirstgid() + slot;
        curpickAuto = false;
        adjustLayer(palette);
        addRecentTile(curspr);
        pixelPaletteMode = PIXEL_PAL_NONE;
        pixelEditSlot = -1;
        issettingtile = false;
        kartu = "world";
        if (activetool == 1)
            activetool = 0;
        cue("tilepickclick");
    }

    /** Tile index under touch for 1×1 pixel-art tilesets, or -1. */
    private int pixelArtTileAt(tileset ts, float wx, float wy) {
        int tw = Math.max(ts.getTilewidth(), 1);
        int th = Math.max(ts.getTileheight(), 1);
        int cols = ts.getWidth();
        int rows = ts.getHeight();
        if (wx < 0 || wx >= cols * tw)
            return -1;
        int col = (int) (wx / tw);
        if (col >= cols)
            col = cols - 1;

        int row;
        if (rows == 1) {
            row = 0;
        } else if (wy >= th) {
            return -1;
        } else if (wy >= 0) {
            row = 0;
        } else if (wy <= -rows * th) {
            return -1;
        } else {
            // Tiles draw at y = -row*th; row r spans (-r*th, -(r-1)*th] for r >= 1
            row = (int) Math.ceil(-wy / th - 1e-9);
        }
        if (col < 0 || row < 0 || col >= cols || row >= rows)
            return -1;
        return row * cols + col;
    }

    private float maxWorldZoomOut() {
        return Math.max(zoomTreshold, 0.5f);
    }

    private void clampWorldCamPosition() {
        int onset = 0;
        if (orientation.equalsIgnoreCase("isometric")) {
            onset = Tsw * Tw / 2;
        }
        if (!orientation.equalsIgnoreCase("isometric") && !sNoScrollBoundary) {
            if (cam.position.x < 0 - onset)
                cam.position.x = 0 - onset;
            if (cam.position.x > Tsw * Tw - onset)
                cam.position.x = Tsw * Tw - onset;
            if (cam.position.y < -Tsh * Th)
                cam.position.y = -Tsh * Th;
            if (cam.position.y > 0)
                cam.position.y = 0;
        }
    }

    private int mapTileAtWorld(float wx, float wy) {
        if (orientation.equalsIgnoreCase("orthogonal")) {
            return orthogonalTileGridAt(wx, wy, Tw, Th, Tsw, Tsh);
        } else if (orientation.equalsIgnoreCase("isometric")) {
            int ae = (int) wx;
            int ab = (int) wy;
            int newae = ae - ((Tsw / Tsh) * ab) + Tsw / 2;
            int newab = (ae / (Tsw / Tsh)) + ab - Tsh / 2;
            int num = (Tw * ((-newab + Tsh) / Tsh) + (newae / Tsw));
            if (num < 0 || num > Tw * Th)
                return -1;
            return num;
        }
        return -1;
    }

    /**
     * Clamp world coordinates to the nearest valid map tile. Used when dragging a
     * shape past the map edge.
     */
    private int clampToEdgeTile(float wx, float wy) {
        if (orientation.equalsIgnoreCase("orthogonal")) {
            int col = (int) Math.floor(wx / Tsw);
            int row = (int) Math.floor(-wy / Tsh);
            col = Math.max(0, Math.min(col, Tw - 1));
            row = Math.max(0, Math.min(row, Th - 1));
            return row * Tw + col;
        } else if (orientation.equalsIgnoreCase("isometric")) {
            int ae = (int) wx;
            int ab = (int) wy;
            int newae = ae - ((Tsw / Tsh) * ab) + Tsw / 2;
            int newab = (ae / (Tsw / Tsh)) + ab - Tsh / 2;
            int num = (Tw * ((-newab + Tsh) / Tsh) + (newae / Tsw));
            return Math.max(0, Math.min(num, Tw * Th - 1));
        }
        return 0;
    }

    private boolean isBrushCell(int bx, int by, int size, BrushShape shape) {
        float cx = (size - 1) / 2f;
        float cy = (size - 1) / 2f;
        float dx = bx - cx;
        float dy = by - cy;
        switch (shape) {
            case SQUARE:
                return true;
            case CIRCLE:
                float r = size / 2f;
                return dx * dx + dy * dy <= r * r + 0.25f;
            case DIAMOND:
                return Math.abs(dx) + Math.abs(dy) <= cx + 0.01f;
            default:
                return true;
        }
    }

    private boolean isBrushShapeBoundary(int bx, int by, int size, BrushShape shape) {
        if (!isBrushCell(bx, by, size, shape))
            return false;
        for (int ny = by - 1; ny <= by + 1; ny++) {
            for (int nx = bx - 1; nx <= bx + 1; nx++) {
                if (nx == bx && ny == by)
                    continue;
                if (!isBrushCell(nx, ny, size, shape))
                    return true;
            }
        }
        return false;
    }

    private boolean isBrushTerrainAnchor(int bx, int by, int size) {
        if (!isBrushCell(bx, by, size, brushShape))
            return false;
        if (brushShape == BrushShape.SQUARE) {
            if (bx == 0 && by == 0)
                return true;
            if (bx == size - 1 && by == 0)
                return true;
            if (bx == size - 1 && by == size - 1)
                return true;
            if (by == size - 1 && bx == 0)
                return true;
            if (bx == 0 && by % 2 == 0)
                return true;
            if (by == 0 && bx % 2 == 0)
                return true;
            if (bx == size - 1 && by % 2 == 0)
                return true;
            if (by == size - 1 && bx % 2 == 0)
                return true;
            return false;
        }
        return isBrushShapeBoundary(bx, by, size, brushShape);
    }

    private void forEachBrushCell(int centerNum, BrushCellHandler handler) {
        int curx = centerNum % Tw;
        int cury = centerNum / Tw;
        for (int bx = 0; bx < brushsize; bx++) {
            for (int by = 0; by < brushsize; by++) {
                if (!isBrushCell(bx, by, brushsize, brushShape))
                    continue;
                int locx = curx - brushsize / 2 + bx;
                int locy = cury - brushsize / 2 + by;
                if (locx < 0 || locy < 0 || locx >= Tw || locy >= Th)
                    continue;
                handler.onCell(locy * Tw + locx, bx, by);
            }
        }
    }

    private interface BrushCellHandler {
        void onCell(int tileIndex, int bx, int by);
    }

    /**
     * Fast tile application for shape tools (rectangle, circle, line).
     * Like applyBrushCell but for single-tile shapes, bypassing tapTile() overhead.
     */
    private void applyShapeTile(int num, int gid, boolean terra) {
        trackBrushPreviewCell(num);
        if (!isTerrainBrushPaintMode()) {
            // Non-terrain mode: just compute rotated Gid and update
            long oi = computeBrushOutputGid(gid);
            int brushTileIdx = resolveBrushTileListIndex(oi, curtset);
            updateTileData(selLayer, num, oi, curtset, brushTileIdx);
            return;
        }
        // Terrain mode
        long oi = computeBrushOutputGid(gid);
        updateTileData(selLayer, num, oi, curtset);
        if (oi == 0)
            return;
        if (!terra)
            return;
        // Defer terrain handling like the brush does
        if (brushDeferredTerrainAnchors == null)
            brushDeferredTerrainAnchors = new java.util.LinkedHashSet<Integer>();
        brushDeferredTerrainAnchors.add(num);
    }

    private long computeBrushOutputGid(int gid) {
        if (eraser)
            return 0;
        String hex = Long.toHexString(gid);
        String trailer = "00000000" + hex;
        hex = trailer.substring(trailer.length() - 8);
        String spc;
        switch (rotate) {
            case 1:
                spc = "A0";
                break;
            case 2:
                spc = "C0";
                break;
            case 3:
                spc = "60";
                break;
            case 4:
                spc = "80";
                break;
            case 5:
                spc = "E0";
                break;
            case 6:
                spc = "40";
                break;
            case 7:
                spc = "20";
                break;
            default:
                spc = "00";
                break;
        }
        return Long.decode("#" + spc + hex.substring(2));
    }

    private long computeBrushOutputGid() {
        if (eraser)
            return 0;
        int drawGid = curspr;
        String hex = Long.toHexString(drawGid);
        String trailer = "00000000" + hex;
        hex = trailer.substring(trailer.length() - 8);
        String spc;
        switch (rotate) {
            case 1:
                spc = "A0";
                break;
            case 2:
                spc = "C0";
                break;
            case 3:
                spc = "60";
                break;
            case 4:
                spc = "80";
                break;
            case 5:
                spc = "E0";
                break;
            case 6:
                spc = "40";
                break;
            case 7:
                spc = "20";
                break;
            default:
                spc = "00";
                break;
        }
        return Long.decode("#" + spc + hex.substring(2));
    }

    private void runTerrainifyFromCenter(int num, tile t) {
        if (t == null || !t.isTerrainForEditor() || !t.isCenter())
            return;
        Terrainify(num, t, new int[] { 8, 0, 1, 2, 3, 4, 5, 6, 7 }, false);
        while (!numanuma.isEmpty()) {
            int[] dir = new int[] {};
            switch ((int) numanuma.get(0).dir) {
                case 0:
                    dir = new int[] { 0, 1, 3 };
                    break;
                case 1:
                    dir = new int[] { 1 };
                    break;
                case 2:
                    dir = new int[] { 2, 1, 4 };
                    break;
                case 3:
                    dir = new int[] { 3 };
                    break;
                case 4:
                    dir = new int[] { 4 };
                    break;
                case 5:
                    dir = new int[] { 5, 3, 6 };
                    break;
                case 6:
                    dir = new int[] { 6 };
                    break;
                case 7:
                    dir = new int[] { 7, 6, 4 };
                    break;
                case 8:
                    dir = new int[] { 8 };
                    break;
            }
            Terrainify((int) numanuma.get(0).num, numanuma.get(0).t, dir, false);
            try {
                numanuma.remove(0);
            } catch (Exception e) {
            }
        }
    }

    private void runTerrainifyPencil(int num, tile t) {
        if (t == null || !t.isTerrainForEditor() || !t.isCenter())
            return;
        int[] aa = t.getTerrain();
        if (aa == null) return;
        int T = aa[0];
        int[] positions = {num, num + 1, num + Tw, num + Tw + 1};
        int[] innerCorner = {3, 2, 1, 0};
        boolean[] valid = new boolean[4];
        for (int i = 0; i < 4; i++) {
            valid[i] = positions[i] >= 0 && positions[i] < Tw * Th;
            if ((i == 1 || i == 3) && num % Tw == Tw - 1) valid[i] = false;
            if ((i == 2 || i == 3) && num / Tw >= Th - 1) valid[i] = false;
        }
        for (int pass = 0; pass < 2; pass++) {
            for (int i = 0; i < 4; i++) {
                if (!valid[i]) continue;
                int gogo = positions[i];
                int[] cc = pencilBuildCorners(gogo, innerCorner[i], T);
                String ccStr = cc[0] + "," + cc[1] + "," + cc[2] + "," + cc[3];
                if (isMacroTerrainPaintMode()) {
                    placeMacroAutotileCandidate(gogo, ccStr);
                    continue;
                }
                java.util.List<Integer> lint = new ArrayList<>(tilesets.get(curtset).getTilesByTerrain(ccStr));
                if (lint.size() == 0) continue;
                int tileindex = lint.get((int) (Math.random() * lint.size()));
                tile y = tilesets.get(curtset).getTiles().get(tileindex);
                updateTileData(selLayer, gogo, (long) y.getTileID() + tilesets.get(curtset).getFirstgid(), curtset, tileindex);
            }
        }
        // Fix outer neighbors that border the 2x2
        if (!isMacroTerrainPaintMode()) {
            int[] outerPos = {
                num - Tw, num - Tw + 1,
                num - 1, num + 2,
                num + Tw - 1, num + Tw + 2,
                num + 2 * Tw, num + 2 * Tw + 1
            };
            for (int opos : outerPos) {
                if (opos < 0 || opos >= Tw * Th) continue;
                pencilFixNeighbor(opos);
            }
        }
    }

    private void pencilFixNeighbor(int pos) {
        tile m = getLayerTileMeta(selLayer, pos);
        if (m == null || m.getTerrain() == null) return;
        int[] existing = m.getTerrain().clone();
        boolean changed = false;
        int v;
        v = pencilCheckEdge(pos, -Tw, 2, -1, 1);
        if (v >= 0 && existing[0] != v) { existing[0] = v; changed = true; }
        v = pencilCheckEdge(pos, -Tw, 3, 1, 0);
        if (v >= 0 && existing[1] != v) { existing[1] = v; changed = true; }
        v = pencilCheckEdge(pos, Tw, 0, -1, 3);
        if (v >= 0 && existing[2] != v) { existing[2] = v; changed = true; }
        v = pencilCheckEdge(pos, Tw, 1, 1, 2);
        if (v >= 0 && existing[3] != v) { existing[3] = v; changed = true; }
        if (!changed) return;
        String ccStr = existing[0] + "," + existing[1] + "," + existing[2] + "," + existing[3];
        java.util.List<Integer> lint = new ArrayList<>(tilesets.get(curtset).getTilesByTerrain(ccStr));
        if (lint.size() == 0) return;
        int tileindex = lint.get((int) (Math.random() * lint.size()));
        tile y = tilesets.get(curtset).getTiles().get(tileindex);
        updateTileData(selLayer, pos, (long) y.getTileID() + tilesets.get(curtset).getFirstgid(), curtset, tileindex);
    }

    private int[] pencilBuildCorners(int pos, int forceCorner, int T) {
        int[] cc = new int[]{-1, -1, -1, -1};
        cc[forceCorner] = T;
        tile existing = getLayerTileMeta(selLayer, pos);
        if (existing != null && existing.getTerrain() != null) {
            int[] ex = existing.getTerrain();
            for (int c = 0; c < 4; c++) {
                if (ex[c] >= 0) cc[c] = ex[c];
            }
        }
        if (cc[0] < 0) cc[0] = pencilCheckEdge(pos, -Tw, 2, -1, 1);
        if (cc[1] < 0) cc[1] = pencilCheckEdge(pos, -Tw, 3, 1, 0);
        if (cc[2] < 0) cc[2] = pencilCheckEdge(pos, Tw, 0, -1, 3);
        if (cc[3] < 0) cc[3] = pencilCheckEdge(pos, Tw, 1, 1, 2);
        cc[forceCorner] = T;
        return cc;
    }

    private int pencilCheckEdge(int pos, int off1, int c1, int off2, int c2) {
        int n1 = pos + off1;
        if (n1 >= 0 && n1 < Tw * Th && !(off1 == -1 && pos % Tw == 0) && !(off1 == 1 && pos % Tw == Tw - 1)) {
            tile m = getLayerTileMeta(selLayer, n1);
            if (m != null && m.getTerrain() != null && m.getTerrain()[c1] >= 0)
                return m.getTerrain()[c1];
        }
        int n2 = pos + off2;
        if (n2 >= 0 && n2 < Tw * Th && !(off2 == -1 && pos % Tw == 0) && !(off2 == 1 && pos % Tw == Tw - 1)) {
            tile m = getLayerTileMeta(selLayer, n2);
            if (m != null && m.getTerrain() != null && m.getTerrain()[c2] >= 0)
                return m.getTerrain()[c2];
        }
        return -1;
    }

    private void beginBrushStroke() {
        if (brushStrokeActive)
            return;
        brushStrokeActive = true;
        brushDeferSideEffects = true;
        brushLastCenter = -1;
        redolayer.clear();
        if (brushDirtyCacheChunks != null)
            brushDirtyCacheChunks.clear();
        if (brushDeferredTerrainAnchors != null)
            brushDeferredTerrainAnchors.clear();
        if (brushStrokePaintedCells != null)
            brushStrokePaintedCells.clear();
        if (brushUndoSnapshots != null)
            brushUndoSnapshots.clear();
    }

    private void endBrushStroke() {
        if (!brushStrokeActive)
            return;
        brushStrokeActive = false;
        brushLastCenter = -1;
        flushBrushDeferredTerrain();
        commitBrushUndoBatch();
        brushDeferSideEffects = false;
        flushBrushDeferredCache();
        pushUpdateIfCollaborating();
        if (brushStrokePaintedCells != null)
            brushStrokePaintedCells.clear();
    }

    private void trackBrushUndoCell(int lay, int num, long fromStr, int fromTset, int fromTile, long toStr, int toTset,
            int toTile) {
        if (!brushDeferSideEffects)
            return;
        if (brushUndoSnapshots == null)
            brushUndoSnapshots = new java.util.LinkedHashMap<Integer, BrushUndoSnapshot>();
        BrushUndoSnapshot snap = brushUndoSnapshots.get(num);
        if (snap == null) {
            snap = new BrushUndoSnapshot();
            snap.layer = lay;
            snap.fromStr = fromStr;
            snap.fromTset = fromTset;
            snap.fromTile = fromTile;
            brushUndoSnapshots.put(num, snap);
        }
        snap.toStr = toStr;
        snap.toTset = toTset;
        snap.toTile = toTile;
    }

    private void commitBrushUndoBatch() {
        if (brushUndoSnapshots == null || brushUndoSnapshots.isEmpty())
            return;
        boolean first = true;
        for (java.util.Map.Entry<Integer, BrushUndoSnapshot> entry : brushUndoSnapshots.entrySet()) {
            BrushUndoSnapshot snap = entry.getValue();
            if (snap.fromStr == snap.toStr && snap.fromTset == snap.toTset && snap.fromTile == snap.toTile)
                continue;
            layerhistory lh = new layerhistory(!first, snap.layer, entry.getKey(), snap.fromStr, snap.toStr,
                    snap.fromTset, snap.toTset, snap.fromTile, snap.toTile);
            undolayer.add(lh);
            mapDirty = true;
            uploaddata(lh);
            first = false;
        }
        if (!first)
            redolayer.clear();
        brushUndoSnapshots.clear();
    }

    private void trackBrushPreviewCell(int tileIndex) {
        if (!brushStrokeActive)
            return;
        if (brushStrokePaintedCells == null)
            brushStrokePaintedCells = new java.util.HashSet<Integer>();
        brushStrokePaintedCells.add(tileIndex);
    }

    private void drawBrushTileHighlight(int tileIndex) {
        if (tileIndex < 0 || tileIndex >= Tw * Th)
            return;
        int locx = tileIndex % Tw;
        int locy = tileIndex / Tw;
        if (orientation.equalsIgnoreCase("orthogonal")) {
            sr.rect(locx * Tsw, -locy * Tsh, Tsw, Tsh);
        } else if (orientation.equalsIgnoreCase("isometric")) {
            int offsetx = (locx * Tsw / 2) + (locy * Tsw / 2);
            int offsety = (locx * Tsh / 2) - (locy * Tsh / 2);
            sr.polygon(new float[] {
                    locx * Tsw + (Tsw / 2f) - offsetx, -locy * Tsh - offsety,
                    locx * Tsw + Tsw - offsetx, -locy * Tsh - (Tsh / 2f) - offsety,
                    locx * Tsw + (Tsw / 2f) - offsetx, -locy * Tsh - Tsh - offsety,
                    locx * Tsw - offsetx, -locy * Tsh - (Tsh / 2f) - offsety
            });
        }
    }

    private void drawBrushFootprintAt(int centerNum) {
        if (centerNum < 0 || centerNum >= Tw * Th)
            return;
        int curx = centerNum % Tw;
        int cury = centerNum / Tw;
        int half = brushsize / 2;
        for (int bx = 0; bx < brushsize; bx++) {
            for (int by = 0; by < brushsize; by++) {
                if (!isBrushCell(bx, by, brushsize, brushShape))
                    continue;
                int locx = curx - half + bx;
                int locy = cury - half + by;
                if (locx < 0 || locy < 0 || locx >= Tw || locy >= Th)
                    continue;
                drawBrushTileHighlight(locy * Tw + locx);
            }
        }
    }

    private void drawBrushPreview() {
        if (activetool != 4 || !kartu.equals("world") || layers.size() == 0 || Tw <= 0 || Th <= 0)
            return;

        int previewCenter = -1;
        if (Gdx.input.isTouched())
            previewCenter = mapTileAtScreen(Gdx.input.getX(), Gdx.input.getY());

        if (brushStrokeActive && brushStrokePaintedCells != null && !brushStrokePaintedCells.isEmpty()) {
            sr.setColor(1f, 0f, 0f, 0.35f);
            for (int tileIndex : brushStrokePaintedCells)
                drawBrushTileHighlight(tileIndex);
        }

        if (previewCenter >= 0) {
            sr.setColor(1f, 0f, 0f, 0.5f);
            drawBrushFootprintAt(previewCenter);
        }
    }

    private void deferBrushCache(int num) {
        if (Tw <= 0 || Th <= 0 || widd <= 0 || heii <= 0 || tcaches.isEmpty())
            return;
        int posx = (num % Tw) / widd;
        int posy = (num / Tw) / heii;
        int maxx = Tw / widd;
        if (Tw % widd != 0)
            maxx++;
        int tci = (posy * maxx) + posx;
        if (tci < 0 || tci >= tcaches.size())
            return;
        if (brushDirtyCacheChunks == null)
            brushDirtyCacheChunks = new java.util.HashSet<Integer>();
        brushDirtyCacheChunks.add(tci);
    }

    private void flushBrushDeferredCache() {
        if (brushDirtyCacheChunks == null || brushDirtyCacheChunks.isEmpty())
            return;
        for (int tci : brushDirtyCacheChunks) {
            if (tci >= 0 && tci < tcaches.size()) {
                tcaches.get(tci).setChanged(true);
                isupdatingcache = true;
            }
        }
        brushDirtyCacheChunks.clear();
    }

    private void flushBrushDeferredTerrain() {
        if (brushDeferredTerrainAnchors == null || brushDeferredTerrainAnchors.isEmpty())
            return;
        for (int num : brushDeferredTerrainAnchors) {
            tile t;
            if (isMacroTerrainPaintMode()) {
                int gid = (int) stripTileGidFlags(layers.get(selLayer).getStr().get(num));
                t = resolveMacroTerrainAutotileCenter(gid, macroTerrain.getTileMeta(gid));
                if (t == null)
                    t = ensureMacroTerrainCenterTile(macroTerrain.getSelTerrain());
            } else {
                int tsetIdx = layers.get(selLayer).getTset().get(num);
                if (tsetIdx < 0 || tsetIdx >= tilesets.size())
                    continue;
                long gid = layers.get(selLayer).getStr().get(num);
                if (gid == 0)
                    continue;
                int localId = (int) (stripTileGidFlags(gid) - tilesets.get(tsetIdx).getFirstgid());
                t = tilesets.get(tsetIdx).getTileMeta(localId);
                t = resolveTerrainAutotileCenter(tilesets.get(tsetIdx), t);
            }
            if (t != null)
                runTerrainifyFromCenter(num, t);
        }
        brushDeferredTerrainAnchors.clear();
    }

    private int resolveBrushTileListIndex(long oi, int tsetID) {
        if (oi == 0 || tsetID < 0 || tsetID >= tilesets.size())
            return -1;
        long bareGid = stripTileGidFlags(oi);
        tileset ts = tilesets.get(tsetID);
        if (ts.getTiles().size() == 0)
            return -1;
        for (int j = 0; j < ts.getTiles().size(); j++) {
            tile tt = ts.getTiles().get(j);
            if (tt.getTileID() + ts.getFirstgid() == bareGid)
                return j;
        }
        return -1;
    }

    private boolean isTerrainBrushPaintMode() {
        return curpickAuto || pickAuto || isMacroTerrainPaintMode();
    }

    private void paintBrushUnpaintedAt(int centerNum, long oi, long bareLocalGid, int brushTileIdx) {
        forEachBrushCell(centerNum, new BrushCellHandler() {
            @Override
            public void onCell(int tileIndex, int bx, int by) {
                if (!pencilMode && brushStrokePaintedCells != null && brushStrokePaintedCells.contains(tileIndex))
                    return;
                applyBrushCell(tileIndex, oi, bareLocalGid, isBrushTerrainAnchor(bx, by, brushsize), brushTileIdx);
            }
        });
    }

    private void applyBrushCell(int num, long oi, long bareLocalGid, boolean terra, int brushTileIdx) {
        trackBrushPreviewCell(num);
        if (!isTerrainBrushPaintMode()) {
            updateTileData(selLayer, num, oi, curtset, brushTileIdx);
            return;
        }
        tile t;
        if (isMacroTerrainPaintMode()) {
            int gid = (int) stripTileGidFlags(curspr);
            t = resolveMacroTerrainAutotileCenter(gid, macroTerrain.getTileMeta(gid));
            if (t == null)
                t = ensureMacroTerrainCenterTile(macroTerrain.getSelTerrain());
            if (t != null)
                gid = t.getTileID();
            int tsetIdx = resolveTilesetIndexForGid(gid, curtset);
            if (!pencilMode) updateTileData(selLayer, num, gid, tsetIdx);
        } else {
            t = tilesets.get(curtset).getTileMeta((int) bareLocalGid);
            t = resolveTerrainAutotileCenter(tilesets.get(curtset), t);
            if (!pencilMode) updateTileData(selLayer, num, oi, curtset);
        }
        if (!isMacroTerrainPaintMode() && oi == 0)
            return;
        if (t == null || !terra)
            return;
        if (pencilMode) {
            runTerrainifyPencil(num, t);
        } else if (brushDeferSideEffects) {
            if (brushDeferredTerrainAnchors == null)
                brushDeferredTerrainAnchors = new java.util.LinkedHashSet<Integer>();
            brushDeferredTerrainAnchors.add(num);
        } else {
            runTerrainifyFromCenter(num, t);
        }
    }

    private void stampBrushAt(int num) {
        if (layers.size() == 0)
            return;
        if (!eraser && !prepareBrushForDraw()) {
            status("Pick a tile in the tileset first", 2);
            return;
        }
        if (isPixelArtSwatchActive())
            return;

        beginBrushStroke();

        long oi = computeBrushOutputGid();
        String hex = Long.toHexString(curspr);
        String trailer = "00000000" + hex;
        hex = trailer.substring(trailer.length() - 8);
        long bareLocalGid = Long.decode("#00" + hex.substring(2)) - tilesets.get(curtset).getFirstgid();
        int brushTileIdx = resolveBrushTileListIndex(oi, curtset);
        if (isMacroTerrainPaintMode())
            refreshAutotileGraph();
        cue("tileclick");

        paintBrushUnpaintedAt(num, oi, bareLocalGid, brushTileIdx);
        brushLastCenter = num;
    }

    private String brushShapeLabel(BrushShape shape) {
        switch (shape) {
            case CIRCLE:
                return z.brushshapecircle != null ? z.brushshapecircle : "Circle brush";
            case DIAMOND:
                return z.brushshapediamond != null ? z.brushshapediamond : "Diamond brush";
            default:
                return z.brushshapesquare != null ? z.brushshapesquare : "Square brush";
        }
    }

    private void updateRotationNameFromRotate() {
        switch (rotate) {
            case 0:
                rotationName = "0";
                break;
            case 1:
                rotationName = "90";
                break;
            case 2:
                rotationName = "180";
                break;
            case 3:
                rotationName = "270";
                break;
            case 4:
                rotationName = "0*";
                break;
            case 5:
                rotationName = "90*";
                break;
            case 6:
                rotationName = "180*";
                break;
            case 7:
                rotationName = "270*";
                break;
            default:
                rotationName = "0";
                break;
        }
    }

    private void fillEntireLayer(int layerIdx, long gid) {
        if (layerIdx < 0 || layerIdx >= layers.size())
            return;
        if (layers.get(layerIdx).getType() != layer.Type.TILE)
            return;
        snapWholeMapPhase1(layerIdx);
        follower = false;
        for (int i = 0; i < Tw * Th; i++) {
            if (i > 0)
                follower = true;
            updateTileData(layerIdx, i, gid, curtset);
        }
        snapWholeMapPhase2(layerIdx);
        pushUpdateIfCollaborating();
    }

    private java.util.HashSet<Integer> collectConnectedRegion(int seed, long matchGid) {
        java.util.HashSet<Integer> region = new java.util.HashSet<Integer>();
        if (seed < 0 || seed >= Tw * Th)
            return region;
        if (layers.get(selLayer).getStr().get(seed) != matchGid)
            return region;
        java.util.ArrayDeque<Integer> queue = new java.util.ArrayDeque<Integer>();
        queue.add(seed);
        region.add(seed);
        while (!queue.isEmpty()) {
            int num = queue.removeFirst();
            int[] neighbors = new int[] { num - Tw, num + Tw, num - 1, num + 1 };
            for (int n = 0; n < neighbors.length; n++) {
                int next = neighbors[n];
                if (next < 0 || next >= Tw * Th)
                    continue;
                if (n == 2 && num % Tw == 0)
                    continue;
                if (n == 3 && num % Tw == Tw - 1)
                    continue;
                if (region.contains(next))
                    continue;
                if (layers.get(selLayer).getStr().get(next) != matchGid)
                    continue;
                region.add(next);
                queue.add(next);
            }
        }
        return region;
    }

    private static final int PACK_CORNER = 0;
    private static final int PACK_EDGE = 1;
    private static final int PACK_REVERSE = 2;
    private static final int PACK_MIN_RECT = 2;
    private static final int BF_CORNER_TL = 0;
    private static final int BF_CORNER_TR = 1;
    private static final int BF_CORNER_BL = 2;
    private static final int BF_CORNER_BR = 3;
    private static final int BF_EDGE_TOP = 4;
    private static final int BF_EDGE_BOTTOM = 5;
    private static final int BF_EDGE_LEFT = 6;
    private static final int BF_EDGE_RIGHT = 7;
    private static final int BF_INNER_TL = 8;
    private static final int BF_INNER_TR = 9;
    private static final int BF_INNER_BL = 10;
    private static final int BF_INNER_BR = 11;

    private static final class EdgePackRect {
        int y;
        int x;
        int w;
        int h;

        int area() {
            return w * h;
        }
    }

    private static final class EdgeFillSample {
        long gid;
        int tset;
    }

    private boolean isValidOrthoNeighbor(int num, int dir, int next) {
        if (next < 0 || next >= Tw * Th)
            return false;
        if (dir == 2 && num % Tw == 0)
            return false;
        if (dir == 3 && num % Tw == Tw - 1)
            return false;
        return true;
    }

    private EdgeFillSample edgeFillSampleAt(int num) {
        EdgeFillSample src = new EdgeFillSample();
        src.gid = layers.get(selLayer).getStr().get(num);
        src.tset = layers.get(selLayer).getTset().get(num);
        return src;
    }

    private int[] diagonalNeighbors(int num) {
        int x = num % Tw;
        java.util.ArrayList<Integer> diags = new java.util.ArrayList<Integer>(4);
        if (num >= Tw && x > 0)
            diags.add(num - Tw - 1);
        if (num >= Tw && x < Tw - 1)
            diags.add(num - Tw + 1);
        if (num < Tw * (Th - 1) && x > 0)
            diags.add(num + Tw - 1);
        if (num < Tw * (Th - 1) && x < Tw - 1)
            diags.add(num + Tw + 1);
        int[] out = new int[diags.size()];
        for (int i = 0; i < diags.size(); i++)
            out[i] = diags.get(i);
        return out;
    }

    private boolean isOutsideRegion(int num, java.util.HashSet<Integer> region) {
        if (num < 0 || num >= Tw * Th)
            return true;
        return !region.contains(num);
    }

    private EdgePackRect largestRectInHistogram(int[] heights, int bottomRow) {
        java.util.ArrayDeque<Integer> stack = new java.util.ArrayDeque<Integer>();
        int bestArea = 0;
        EdgePackRect best = null;
        for (int i = 0; i <= heights.length; i++) {
            int h = i < heights.length ? heights[i] : 0;
            while (!stack.isEmpty() && h < heights[stack.peekLast()]) {
                int height = heights[stack.removeLast()];
                int width = stack.isEmpty() ? i : i - stack.peekLast() - 1;
                int area = height * width;
                if (area > bestArea) {
                    bestArea = area;
                    best = new EdgePackRect();
                    best.y = bottomRow - height + 1;
                    best.x = stack.isEmpty() ? 0 : stack.peekLast() + 1;
                    best.w = width;
                    best.h = height;
                }
            }
            stack.addLast(i);
        }
        return best;
    }

    private EdgePackRect findMaximalInsideRectangle(java.util.HashSet<Integer> inside) {
        if (inside.isEmpty())
            return null;
        int minRow = Th, maxRow = 0, minCol = Tw, maxCol = 0;
        for (int num : inside) {
            int row = num / Tw;
            int col = num % Tw;
            if (row < minRow)
                minRow = row;
            if (row > maxRow)
                maxRow = row;
            if (col < minCol)
                minCol = col;
            if (col > maxCol)
                maxCol = col;
        }
        int bboxW = maxCol - minCol + 1;
        int[] heights = new int[bboxW];
        int bestArea = 0;
        EdgePackRect best = null;
        for (int row = minRow; row <= maxRow; row++) {
            for (int col = minCol; col <= maxCol; col++) {
                int num = row * Tw + col;
                int idx = col - minCol;
                heights[idx] = inside.contains(num) ? heights[idx] + 1 : 0;
            }
            EdgePackRect rowBest = largestRectInHistogram(heights, row);
            if (rowBest != null && rowBest.area() > bestArea) {
                bestArea = rowBest.area();
                best = rowBest;
                best.x += minCol;
            }
        }
        return best;
    }

    private boolean isPackRectValidSize(EdgePackRect rect) {
        return rect != null && rect.w >= PACK_MIN_RECT && rect.h >= PACK_MIN_RECT;
    }

    private boolean isPackRectCorner(int row, int col, EdgePackRect rect) {
        int endY = rect.y + rect.h - 1;
        int endX = rect.x + rect.w - 1;
        return (row == rect.y && col == rect.x) || (row == rect.y && col == endX)
                || (row == endY && col == rect.x) || (row == endY && col == endX);
    }

    private boolean isPackRectPerimeter(int row, int col, EdgePackRect rect) {
        if (row < rect.y || row >= rect.y + rect.h || col < rect.x || col >= rect.x + rect.w)
            return false;
        if (isPackRectCorner(row, col, rect))
            return true;
        return row == rect.y || row == rect.y + rect.h - 1 || col == rect.x || col == rect.x + rect.w - 1;
    }

    private int classifyInsideBoundaryTile(int num, java.util.HashSet<Integer> blob) {
        boolean nIn = num < Tw || blob.contains(num - Tw);
        boolean sIn = num + Tw >= Tw * Th || blob.contains(num + Tw);
        boolean wIn = (num % Tw == 0) || blob.contains(num - 1);
        boolean eIn = (num % Tw == Tw - 1) || blob.contains(num + 1);
        // Corners: two adjacent sides open, two adjacent sides still in the fill blob.
        if (!nIn && !wIn && sIn && eIn)
            return BF_CORNER_TL;
        if (!nIn && !eIn && wIn && sIn)
            return BF_CORNER_TR;
        if (!sIn && !wIn && nIn && eIn)
            return BF_CORNER_BL;
        if (!sIn && !eIn && wIn && nIn)
            return BF_CORNER_BR;
        if (!nIn && wIn && eIn)
            return BF_EDGE_TOP;
        if (!sIn && wIn && eIn)
            return BF_EDGE_BOTTOM;
        if (!wIn && nIn && sIn)
            return BF_EDGE_LEFT;
        if (!eIn && nIn && sIn)
            return BF_EDGE_RIGHT;
            
        // Inner corners: all orthogonal neighbors are IN, but a diagonal neighbor is OUT.
        if (nIn && sIn && wIn && eIn) {
            boolean nwIn = (num < Tw || num % Tw == 0) || blob.contains(num - Tw - 1);
            boolean neIn = (num < Tw || num % Tw == Tw - 1) || blob.contains(num - Tw + 1);
            boolean swIn = (num + Tw >= Tw * Th || num % Tw == 0) || blob.contains(num + Tw - 1);
            boolean seIn = (num + Tw >= Tw * Th || num % Tw == Tw - 1) || blob.contains(num + Tw + 1);
            
            if (!nwIn) return BF_INNER_TL;
            if (!neIn) return BF_INNER_TR;
            if (!swIn) return BF_INNER_BL;
            if (!seIn) return BF_INNER_BR;
        }
            
        return -1;
    }

    private int sourceNumForBoundaryRole(int num, int role) {
        switch (role) {
            case BF_CORNER_TL:
            case BF_INNER_TL:
                return num - Tw - 1;
            case BF_CORNER_TR:
            case BF_INNER_TR:
                return num - Tw + 1;
            case BF_CORNER_BL:
            case BF_INNER_BL:
                return num + Tw - 1;
            case BF_CORNER_BR:
            case BF_INNER_BR:
                return num + Tw + 1;
            case BF_EDGE_TOP:
                return num - Tw;
            case BF_EDGE_BOTTOM:
                return num + Tw;
            case BF_EDGE_LEFT:
                return num - 1;
            case BF_EDGE_RIGHT:
                return num + 1;
            default:
                return -1;
        }
    }

    private boolean isBoundaryCornerRole(int role) {
        return (role >= BF_CORNER_TL && role <= BF_CORNER_BR) || (role >= BF_INNER_TL && role <= BF_INNER_BR);
    }

    private int boundaryRoleToPackLabel(int role) {
        return isBoundaryCornerRole(role) ? PACK_CORNER : PACK_EDGE;
    }

    private int resolveInsideBoundarySourceNum(int num, java.util.HashSet<Integer> classifyBlob,
            java.util.HashSet<Integer> region, boolean requireOutsideRegion) {
        int role = classifyInsideBoundaryTile(num, classifyBlob);
        if (role < 0)
            return -1;
        int primary = sourceNumForBoundaryRole(num, role);
        if (primary >= 0 && primary < Tw * Th) {
            if (!requireOutsideRegion || !region.contains(primary))
                return primary;
        }
        if (!isBoundaryCornerRole(role) && primary >= 0 && primary < Tw * Th)
            return primary;
        return -1;
    }

    private int boundaryRoleToTerrainDirection(int role) {
        switch (role) {
            case BF_CORNER_TL:
                return 0;
            case BF_EDGE_TOP:
                return 1;
            case BF_CORNER_TR:
                return 2;
            case BF_EDGE_LEFT:
                return 3;
            case BF_EDGE_RIGHT:
                return 4;
            case BF_CORNER_BL:
                return 5;
            case BF_EDGE_BOTTOM:
                return 6;
            case BF_CORNER_BR:
                return 7;
            default:
                return -1;
        }
    }

    private boolean fillGidUsesMacroTerrain(long matchGid) {
        if (macroTerrain.getTerrains().isEmpty())
            return false;
        int gid = (int) stripTileGidFlags(matchGid);
        tile mt = macroTerrain.getTileMeta(gid);
        if (mt != null && mt.isTerrainForEditor())
            return true;
        for (int i = 0; i < macroTerrain.getTerrains().size(); i++) {
            if (macroTerrain.getTerrains().get(i).getTile() == gid)
                return true;
        }
        return false;
    }

    private tile getMacroOrLayerTileMeta(int layerIdx, int cellIdx) {
        if (layerIdx < 0 || layerIdx >= layers.size())
            return null;
        layer lay = layers.get(layerIdx);
        if (cellIdx < 0 || cellIdx >= lay.getStr().size())
            return null;
        long gid = stripTileGidFlags(lay.getStr().get(cellIdx));
        if (gid == 0)
            return null;
        tile t = macroTerrain.getTileMeta((int) gid);
        if (t != null)
            return t;
        return getLayerTileMeta(layerIdx, cellIdx);
    }

    private int[] edgeFillOutsideTerrain(int num, int role, java.util.HashSet<Integer> classifyBlob,
            java.util.HashSet<Integer> region, boolean requireOutsideRegion) {
        int[] empty = new int[] { -1, -1, -1, -1 };
        int srcNum = resolveInsideBoundarySourceNum(num, classifyBlob, region, requireOutsideRegion);
        if (srcNum < 0)
            return empty;
        tile t = getMacroOrLayerTileMeta(selLayer, srcNum);
        if (t != null && t.isTerrainForEditor())
            return t.getTerrain().clone();
        return empty;
    }

    private EdgeFillSample macroEdgeFillSampleFromGids(java.util.List<Integer> gids) {
        if (gids == null || gids.isEmpty())
            return null;
        int pickGid = gids.get(0);
        int tsetIdx = resolveTilesetIndexForGid(pickGid, -1);
        if (tsetIdx < 0)
            return null;
        EdgeFillSample src = new EdgeFillSample();
        src.gid = pickGid;
        src.tset = tsetIdx;
        return src;
    }

    private EdgeFillSample macroSampleForTerrainPattern(int direction, int[] aa, int[] bb) {
        int[] cc = terrainInt(direction, aa, bb);
        String ccStr = cc[0] + "," + cc[1] + "," + cc[2] + "," + cc[3];
        return macroEdgeFillSampleFromGids(macroTerrain.getGidsByTerrain(ccStr));
    }

    /** Read-only lookup matching placeMacroAutotileWithFallback. */
    private EdgeFillSample resolveMacroAutotileSample(int direction, int[] aa, int[] bb) {
        int[] empty = new int[] { -1, -1, -1, -1 };
        EdgeFillSample sample = macroSampleForTerrainPattern(direction, aa, bb);
        if (sample != null)
            return sample;
        if (bb[0] == -1 && bb[1] == -1 && bb[2] == -1 && bb[3] == -1)
            return null;
        int against = bb[0];
        if (bb[0] == aa[0])
            against = bb[1];
        if (bb[1] == aa[0])
            against = bb[2];
        if (bb[2] == aa[0])
            against = bb[3];
        findBestTile(aa[0], against);
        if (ATPath == null || ATPath.getCount() <= 1) {
            if (direction != 8)
                return macroSampleForTerrainPattern(direction, aa, empty);
            return null;
        }
        int ATid = ATPath.get(1).name;
        if (!(bb[0] == ATid && bb[1] == ATid && bb[2] == ATid && bb[3] == ATid)) {
            String centerStr = ATid + "," + ATid + "," + ATid + "," + ATid;
            sample = macroEdgeFillSampleFromGids(macroTerrain.getGidsByTerrain(centerStr));
            if (sample != null)
                return sample;
        }
        if (direction != 8)
            return macroSampleForTerrainPattern(direction, aa, empty);
        return null;
    }

    private EdgeFillSample tilesetSampleForTerrainPattern(int fillTset, int direction, int[] aa, int[] bb) {
        if (fillTset < 0 || fillTset >= tilesets.size())
            return null;
        int[] cc = terrainInt(direction, aa, bb);
        String ccStr = cc[0] + "," + cc[1] + "," + cc[2] + "," + cc[3];
        java.util.List<Integer> lint = new java.util.ArrayList<Integer>(
                tilesets.get(fillTset).getTilesByTerrain(ccStr));
        if (lint.isEmpty())
            return null;
        int tileindex = lint.get(0);
        tile y = tilesets.get(fillTset).getTiles().get(tileindex);
        EdgeFillSample src = new EdgeFillSample();
        src.gid = (long) y.getTileID() + tilesets.get(fillTset).getFirstgid();
        src.tset = fillTset;
        return src;
    }

    private tile resolveEdgeFillCenterTile(long matchGid, int seedNum) {
        int gid = (int) stripTileGidFlags(matchGid);
        if (fillGidUsesMacroTerrain(matchGid)) {
            tile center = resolveMacroTerrainAutotileCenter(gid, macroTerrain.getTileMeta(gid));
            if (center != null && center.isTerrainForEditor())
                return center;
        }
        int tsetIdx = layers.get(selLayer).getTset().get(seedNum);
        if (tsetIdx < 0)
            tsetIdx = resolveTilesetIndexForGid(matchGid, curtset);
        if (tsetIdx < 0 || tsetIdx >= tilesets.size())
            return null;
        long bare = stripTileGidFlags(matchGid);
        int localId = (int) (bare - tilesets.get(tsetIdx).getFirstgid());
        if (localId < 0)
            return null;
        tile t = tilesets.get(tsetIdx).getTileMeta(localId);
        return resolveTerrainAutotileCenter(tilesets.get(tsetIdx), t);
    }

    private int interiorCenterForBoundaryRole(int num, int role) {
        switch (role) {
            case BF_CORNER_TL:
                return num + Tw + 1;
            case BF_CORNER_TR:
                return num + Tw - 1;
            case BF_CORNER_BL:
                return num - Tw + 1;
            case BF_CORNER_BR:
                return num - Tw - 1;
            case BF_EDGE_TOP:
                return num + Tw;
            case BF_EDGE_BOTTOM:
                return num - Tw;
            case BF_EDGE_LEFT:
                return num + 1;
            case BF_EDGE_RIGHT:
                return num - 1;
            default:
                return -1;
        }
    }

    private EdgeFillSample sampleForTerrainPatternString(String ccStr, int fillTset) {
        if (!macroTerrain.getTerrains().isEmpty()) {
            EdgeFillSample sample = macroEdgeFillSampleFromGids(macroTerrain.getGidsByTerrain(ccStr));
            if (sample != null)
                return sample;
        }
        return tilesetSampleForTerrainString(fillTset, ccStr);
    }

    private EdgeFillSample resolveEdgeFillSampleFromWang(int num, java.util.HashSet<Integer> blob,
            int insideId, int outsideId, int fillTset) {
        boolean nIn = num >= Tw && blob.contains(num - Tw);
        boolean sIn = num + Tw < Tw * Th && blob.contains(num + Tw);
        boolean wIn = (num % Tw != 0) && blob.contains(num - 1);
        boolean eIn = (num % Tw != Tw - 1) && blob.contains(num + 1);

        int c0 = (nIn && wIn && (num >= Tw && num % Tw != 0 && blob.contains(num - Tw - 1))) ? insideId : outsideId;
        int c1 = (nIn && eIn && (num >= Tw && num % Tw != Tw - 1 && blob.contains(num - Tw + 1))) ? insideId : outsideId;
        int c2 = (sIn && wIn && (num + Tw < Tw * Th && num % Tw != 0 && blob.contains(num + Tw - 1))) ? insideId : outsideId;
        int c3 = (sIn && eIn && (num + Tw < Tw * Th && num % Tw != Tw - 1 && blob.contains(num + Tw + 1))) ? insideId : outsideId;

        String ccStr = c0 + "," + c1 + "," + c2 + "," + c3;
        return sampleForTerrainPatternString(ccStr, fillTset);
    }

    private int terrainIdAtCell(int cellIdx) {
        if (cellIdx < 0 || cellIdx >= Tw * Th)
            return -1;
        tile t = getMacroOrLayerTileMeta(selLayer, cellIdx);
        if (t == null || !t.isTerrainForEditor())
            return -1;
        int[] tr = t.getTerrain();
        if (tr == null)
            return -1;
        return tr[0];
    }

    private int cornerWangTerrain(boolean sideAIn, boolean sideBIn, int fill, int cellA, int cellB,
            boolean useOutsideTerrains) {
        if (sideAIn && sideBIn)
            return fill;
        if (!useOutsideTerrains)
            return -1;
        if (!sideAIn) {
            int t = terrainIdAtCell(cellA);
            if (t >= 0)
                return t;
        }
        if (!sideBIn) {
            int t = terrainIdAtCell(cellB);
            if (t >= 0)
                return t;
        }
        return -1;
    }

    /**
     * Build the 4 wang corner terrain ids (TL,TR,BL,BR) from fill blob membership.
     */
    private int[] wangCornersFromBlob(int num, int[] fillTerrain, java.util.HashSet<Integer> blob,
            boolean useOutsideTerrains) {
        int fill = fillTerrain[0];
        int[] c = new int[4];
        boolean nIn = num >= Tw && blob.contains(num - Tw);
        boolean sIn = num + Tw < Tw * Th && blob.contains(num + Tw);
        boolean wIn = (num % Tw != 0) && blob.contains(num - 1);
        boolean eIn = (num % Tw != Tw - 1) && blob.contains(num + 1);
        c[0] = cornerWangTerrain(nIn, wIn, fill, num - Tw, num - 1, useOutsideTerrains);
        c[1] = cornerWangTerrain(nIn, eIn, fill, num - Tw, num + 1, useOutsideTerrains);
        c[2] = cornerWangTerrain(sIn, wIn, fill, num + Tw, num - 1, useOutsideTerrains);
        c[3] = cornerWangTerrain(sIn, eIn, fill, num + Tw, num + 1, useOutsideTerrains);
        return c;
    }

    private EdgeFillSample tilesetSampleForTerrainString(int fillTset, String ccStr) {
        if (fillTset >= 0 && fillTset < tilesets.size()) {
            EdgeFillSample sample = tilesetSampleForTerrainStringInSet(fillTset, ccStr);
            if (sample != null)
                return sample;
        }
        for (int i = 0; i < tilesets.size(); i++) {
            if (i == fillTset)
                continue;
            EdgeFillSample sample = tilesetSampleForTerrainStringInSet(i, ccStr);
            if (sample != null)
                return sample;
        }
        return null;
    }

    private EdgeFillSample tilesetSampleForTerrainStringInSet(int fillTset, String ccStr) {
        if (fillTset < 0 || fillTset >= tilesets.size())
            return null;
        java.util.List<Integer> lint = new java.util.ArrayList<Integer>(
                tilesets.get(fillTset).getTilesByTerrain(ccStr));
        if (lint.isEmpty())
            return null;
        int tileindex = lint.get(0);
        tile y = tilesets.get(fillTset).getTiles().get(tileindex);
        EdgeFillSample src = new EdgeFillSample();
        src.gid = (long) y.getTileID() + tilesets.get(fillTset).getFirstgid();
        src.tset = fillTset;
        return src;
    }

    private EdgeFillSample sampleForWangPattern(int[] corners, boolean tryMacro, int fillTset) {
        String ccStr = corners[0] + "," + corners[1] + "," + corners[2] + "," + corners[3];
        if (tryMacro && !macroTerrain.getTerrains().isEmpty()) {
            EdgeFillSample sample = macroEdgeFillSampleFromGids(macroTerrain.getGidsByTerrain(ccStr));
            if (sample != null)
                return sample;
        }
        return tilesetSampleForTerrainString(fillTset, ccStr);
    }

    private EdgeFillSample resolveEdgeFillPatternSample(boolean useMacro, int fillTset, int direction, int[] aa,
            int[] bb) {
        if (useMacro && !macroTerrain.getTerrains().isEmpty()) {
            EdgeFillSample sample = resolveMacroAutotileSample(direction, aa, bb);
            if (sample != null)
                return sample;
        }
        return tilesetSampleForTerrainPattern(fillTset, direction, aa, bb);
    }

    private EdgeFillSample resolveEdgeFillTerrainSample(int num, int role, int fillTset, int[] fillTerrain,
            boolean fillUsesMacroTerrain, tile fillCenter, java.util.HashSet<Integer> classifyBlob,
            java.util.HashSet<Integer> region, boolean requireOutsideRegion) {
        // Just copy from the neighbor outside the fill.
        int srcNum = sourceNumForBoundaryRole(num, role);
        if (srcNum < 0 || srcNum >= Tw * Th)
            return null;
        return edgeFillSampleAt(srcNum);
    }

    private int previewSourceNumForBoundaryRole(int num, int role) {
        int srcNum = sourceNumForBoundaryRole(num, role);
        if (srcNum >= 0 && srcNum < Tw * Th)
            return srcNum;
        return -1;
    }

    private EdgeFillSample resolveInsideBoundarySource(int num, java.util.HashSet<Integer> classifyBlob,
            java.util.HashSet<Integer> region, boolean requireOutsideRegion) {
        int srcNum = resolveInsideBoundarySourceNum(num, classifyBlob, region, requireOutsideRegion);
        if (srcNum < 0)
            return null;
        return edgeFillSampleAt(srcNum);
    }

    private EdgeFillSample resolveShellTileSample(int num, java.util.HashSet<Integer> classifyBlob,
            java.util.HashSet<Integer> region, boolean requireOutsideRegion, int fillTset, int[] fillTerrain,
            boolean fillUsesMacroTerrain, tile fillCenter) {
        int role = classifyInsideBoundaryTile(num, classifyBlob);
        if (role < 0)
            return null;
        return resolveEdgeFillTerrainSample(num, role, fillTset, fillTerrain, fillUsesMacroTerrain, fillCenter,
                classifyBlob, region, requireOutsideRegion);
    }

    private EdgeFillSample resolvePackCornerSource(int num, java.util.HashSet<Integer> region) {
        int role = classifyInsideBoundaryTile(num, region);
        if (!isBoundaryCornerRole(role))
            return null;
        if (edgeFillJob != null && edgeFillJob.fillTerrain != null)
            return resolveEdgeFillTerrainSample(num, role, edgeFillJob.fillTset, edgeFillJob.fillTerrain,
                    edgeFillJob.fillUsesMacroTerrain, edgeFillJob.fillCenter, region, region, true);
        int srcNum = sourceNumForBoundaryRole(num, role);
        if (srcNum < 0 || srcNum >= Tw * Th)
            return null;
        return edgeFillSampleAt(srcNum);
    }

    private boolean hasPackEdgeBridge(int num, int diag, java.util.HashMap<Integer, Integer> labels) {
        int dx = (diag % Tw) - (num % Tw);
        int dy = (diag / Tw) - (num / Tw);
        int sideA;
        int sideB;
        if (dx < 0 && dy < 0) {
            sideA = num - Tw;
            sideB = num - 1;
        } else if (dx > 0 && dy < 0) {
            sideA = num - Tw;
            sideB = num + 1;
        } else if (dx < 0 && dy > 0) {
            sideA = num + Tw;
            sideB = num - 1;
        } else {
            sideA = num + Tw;
            sideB = num + 1;
        }
        Integer labelA = labels.get(sideA);
        Integer labelB = labels.get(sideB);
        return labelA != null && labelA == PACK_EDGE && labelB != null && labelB == PACK_EDGE;
    }

    private boolean isConcaveRegionVertex(int num, java.util.HashSet<Integer> region) {
        int n = isOutsideRegion(num - Tw, region) ? 1 : 0;
        int s = isOutsideRegion(num + Tw, region) ? 1 : 0;
        int w = (num % Tw == 0) || isOutsideRegion(num - 1, region) ? 1 : 0;
        int e = (num % Tw == Tw - 1) || isOutsideRegion(num + 1, region) ? 1 : 0;
        if (n == 1 && w == 1 && isOutsideRegion(num - Tw - 1, region))
            return true;
        if (n == 1 && e == 1 && isOutsideRegion(num - Tw + 1, region))
            return true;
        if (s == 1 && w == 1 && isOutsideRegion(num + Tw - 1, region))
            return true;
        if (s == 1 && e == 1 && isOutsideRegion(num + Tw + 1, region))
            return true;
        return false;
    }

    /**
     * Two edge tiles that are diagonal neighbors and both face the same tile
     * outside the region form a concave corner.
     */
    private boolean isConcaveCornerEdgePair(int num, int diag, java.util.HashMap<Integer, Integer> labels,
            java.util.HashSet<Integer> region) {
        Integer numLabel = labels.get(num);
        Integer diagLabel = labels.get(diag);
        if (numLabel == null || numLabel != PACK_EDGE || diagLabel == null || diagLabel != PACK_EDGE)
            return false;
        int numRole = classifyInsideBoundaryTile(num, region);
        int diagRole = classifyInsideBoundaryTile(diag, region);
        if (isBoundaryCornerRole(numRole) || isBoundaryCornerRole(diagRole) || numRole < 0 || diagRole < 0)
            return false;
        int numSrc = sourceNumForBoundaryRole(num, numRole);
        int diagSrc = sourceNumForBoundaryRole(diag, diagRole);
        if (numSrc != diagSrc)
            return false;
        return numSrc < 0 || numSrc >= Tw * Th || !region.contains(numSrc);
    }

    /**
     * Given two edge roles that form a concave corner, return the corner role
     * that connects them. E.g. BF_EDGE_TOP + BF_EDGE_RIGHT → BF_CORNER_TR.
     */
    private int edgeRoleToConcaveCorner(int numRole, int diagRole) {
        switch (numRole) {
            case BF_EDGE_TOP:
                if (diagRole == BF_EDGE_LEFT)
                    return BF_CORNER_TL;
                if (diagRole == BF_EDGE_RIGHT)
                    return BF_CORNER_TR;
                break;
            case BF_EDGE_BOTTOM:
                if (diagRole == BF_EDGE_LEFT)
                    return BF_CORNER_BL;
                if (diagRole == BF_EDGE_RIGHT)
                    return BF_CORNER_BR;
                break;
            case BF_EDGE_LEFT:
                if (diagRole == BF_EDGE_TOP)
                    return BF_CORNER_TL;
                if (diagRole == BF_EDGE_BOTTOM)
                    return BF_CORNER_BL;
                break;
            case BF_EDGE_RIGHT:
                if (diagRole == BF_EDGE_TOP)
                    return BF_CORNER_TR;
                if (diagRole == BF_EDGE_BOTTOM)
                    return BF_CORNER_BR;
                break;
        }
        return -1;
    }

    private boolean checkPackIrregularAdjacency(int num, int label, java.util.HashMap<Integer, Integer> labels,
            java.util.HashSet<Integer> region) {
        if (label != PACK_CORNER && label != PACK_EDGE)
            return false;
        // NOTE: isConcaveRegionVertex is intentionally NOT called here because it
        // cannot distinguish convex outer-boundary corners from true concave corners.
        // Both have exactly 2 adjacent cardinal sides outside the region with the
        // diagonal between them also outside, causing isConcaveRegionVertex to return
        // true for both. But convex corners were already correctly painted in the
        // first shell, and flagging them here causes them to be overwritten with edge
        // tiles in resolvePackReverseSource (which copies from an adjacent labeled
        // edge). Real concave corners (inner boundary around holes/indentations) are
        // always classified as EDGES by classifyInsideBoundaryTile, so
        // isConcaveRegionVertex
        // doesn't catch them anyway — the diagonal-corner-adjacency check below handles
        // those cases that truly need reverse-phase correction.
        int[] diags = diagonalNeighbors(num);
        for (int i = 0; i < diags.length; i++) {
            int d = diags[i];
            Integer diagLabel = labels.get(d);
            if (diagLabel != null && diagLabel == PACK_CORNER && !hasPackEdgeBridge(num, d, labels))
                return true;
            if (diagLabel != null && diagLabel == PACK_EDGE && isConcaveCornerEdgePair(num, d, labels, region))
                return true;
        }
        return false;
    }

    private EdgeFillSample resolvePackReverseSource(int num, java.util.HashSet<Integer> region,
            java.util.HashMap<Integer, Integer> labels) {
        // Concave corner: two orphaned edge tiles that share a diagonal and both
        // face the same outside tile. The orphaned edges themselves use edge shapes
        // (fall through to neighbor-copying below). Additionally, fill the corner
        // tile that sits BETWEEN the two diagonal orphaned edges — that tile should
        // use the shared outside corner tile (the "bridge" that connects the two
        // separated edge lines).
        {
            Integer lbl = labels.get(num);
            if (lbl != null && lbl == PACK_EDGE) {
                int[] diags = diagonalNeighbors(num);
                for (int i = 0; i < diags.length; i++) {
                    int d = diags[i];
                    if (isConcaveCornerEdgePair(num, d, labels, region)) {
                        int numRole = classifyInsideBoundaryTile(num, region);
                        int srcNum = sourceNumForBoundaryRole(num, numRole);
                        if (srcNum >= 0 && srcNum < Tw * Th) {
                            int nr = num / Tw;
                            int nc = num % Tw;
                            int dr = d / Tw;
                            int dc = d % Tw;
                            // The two orphaned edges and the shared source form a
                            // 2x2 block. The corner tile opposite the source is
                            // the missing bridge between the two edge lines.
                            int cornerTilePos = -1;
                            if (srcNum == dr * Tw + nc)
                                cornerTilePos = nr * Tw + dc;
                            else if (srcNum == nr * Tw + dc)
                                cornerTilePos = dr * Tw + nc;
                            if (cornerTilePos >= 0 && cornerTilePos < Tw * Th
                                    && region.contains(cornerTilePos)
                                    && !labels.containsKey(cornerTilePos)) {
                                EdgeFillSample cornerSrc = edgeFillSampleAt(srcNum);
                                follower = true;
                                updateTileData(selLayer, cornerTilePos,
                                        cornerSrc.gid, cornerSrc.tset);
                                labels.put(cornerTilePos, PACK_REVERSE);
                            }
                        }
                        break;
                    }
                }
            }
        }

        // Fall through to generic neighbor-copying for edge shapes on the
        // current orphaned edge tile itself.
        int[] diags = diagonalNeighbors(num);
        for (int i = 0; i < diags.length; i++) {
            int d = diags[i];
            if (!region.contains(d))
                return edgeFillSampleAt(d);
        }
        int[] neighbors = new int[] { num - Tw, num + Tw, num - 1, num + 1 };
        EdgeFillSample firstOutside = null;
        for (int n = 0; n < neighbors.length; n++) {
            int next = neighbors[n];
            if (!isValidOrthoNeighbor(num, n, next))
                continue;
            if (!region.contains(next))
                firstOutside = edgeFillSampleAt(next);
            else {
                Integer lbl = labels.get(next);
                if (lbl != null && (lbl == PACK_CORNER || lbl == PACK_EDGE || lbl == PACK_REVERSE))
                    return edgeFillSampleAt(next);
            }
        }
        if (firstOutside != null)
            return firstOutside;
        return resolvePackCornerSource(num, region);
    }

    private void resolvePackReverseCorners(java.util.HashMap<Integer, Integer> labels,
            java.util.HashSet<Integer> region) {
        java.util.ArrayList<Integer> cells = new java.util.ArrayList<Integer>(labels.keySet());
        for (int i = 0; i < cells.size(); i++) {
            int num = cells.get(i);
            Integer label = labels.get(num);
            if (label == null || (label != PACK_CORNER && label != PACK_EDGE))
                continue;
            if (!checkPackIrregularAdjacency(num, label, labels, region))
                continue;
            EdgeFillSample src = resolvePackReverseSource(num, region, labels);
            if (src == null)
                continue;
            follower = true;
            updateTileData(selLayer, num, src.gid, src.tset);
            labels.put(num, PACK_REVERSE);
        }
    }

    private java.util.HashSet<Integer> collectPackRectShellSelection(EdgePackRect rect,
            java.util.HashSet<Integer> inside) {
        java.util.HashSet<Integer> sel = new java.util.HashSet<Integer>();
        for (int row = rect.y; row < rect.y + rect.h; row++) {
            for (int col = rect.x; col < rect.x + rect.w; col++) {
                int num = row * Tw + col;
                if (!inside.contains(num))
                    continue;
                if (isPackRectPerimeter(row, col, rect))
                    sel.add(num);
            }
        }
        return sel;
    }

    private java.util.HashSet<Integer> collectRegionBoundaryShell(java.util.HashSet<Integer> region,
            java.util.HashSet<Integer> inside) {
        java.util.HashSet<Integer> shell = new java.util.HashSet<Integer>();
        for (int num : inside) {
            if (!region.contains(num))
                continue;
            if (classifyInsideBoundaryTile(num, region) >= 0)
                shell.add(num);
        }
        return shell;
    }

    private java.util.HashSet<Integer> collectShellSources(java.util.HashSet<Integer> shell,
            java.util.HashSet<Integer> classifyBlob, java.util.HashSet<Integer> region,
            boolean requireOutsideRegion) {
        java.util.HashSet<Integer> sources = new java.util.HashSet<Integer>();
        for (int num : shell) {
            int role = classifyInsideBoundaryTile(num, classifyBlob);
            if (role < 0)
                continue;
            int srcNum = previewSourceNumForBoundaryRole(num, role);
            if (srcNum >= 0)
                sources.add(srcNum);
        }
        return sources;
    }

    private boolean isInteriorCoreRemaining(java.util.HashSet<Integer> inside,
            java.util.HashMap<Integer, Integer> labels, java.util.HashSet<Integer> region) {
        if (inside.isEmpty())
            return false;
        for (int num : inside) {
            int[] neighbors = new int[] { num - Tw, num + Tw, num - 1, num + 1 };
            for (int n = 0; n < neighbors.length; n++) {
                int next = neighbors[n];
                if (!isValidOrthoNeighbor(num, n, next))
                    continue;
                if (inside.contains(next))
                    continue;
                if (!region.contains(next))
                    continue;
                if (!labels.containsKey(next))
                    return false;
            }
        }
        return true;
    }

    private boolean isShellFullyEnclosedByLabels(java.util.HashSet<Integer> shell,
            java.util.HashSet<Integer> inside, java.util.HashMap<Integer, Integer> labels,
            java.util.HashSet<Integer> region) {
        if (shell.isEmpty())
            return true;
        for (int num : shell) {
            int[] neighbors = new int[] { num - Tw, num + Tw, num - 1, num + 1 };
            for (int n = 0; n < neighbors.length; n++) {
                int next = neighbors[n];
                if (!isValidOrthoNeighbor(num, n, next))
                    continue;
                if (inside.contains(next))
                    continue;
                if (!region.contains(next))
                    return false;
                if (!labels.containsKey(next))
                    return false;
            }
        }
        return true;
    }

    private java.util.ArrayList<EdgeFillPaintPlan> planRegionBoundaryShell(java.util.HashSet<Integer> inside,
            int fillTset, int[] fillTerrain, int[] outsideTerrain, tile fillCenter) {
        java.util.ArrayList<EdgeFillPaintPlan> plans = new java.util.ArrayList<EdgeFillPaintPlan>();
        
        int insideId = fillTerrain != null ? fillTerrain[0] : -1;
        int outsideId = outsideTerrain != null ? outsideTerrain[0] : -1;
        
        for (int num : inside) {
            EdgeFillSample src = resolveEdgeFillSampleFromWang(num, inside, insideId, outsideId, fillTset);
            EdgeFillPaintPlan plan = new EdgeFillPaintPlan();
            plan.num = num;
            if (src != null) {
                plan.gid = src.gid;
                plan.tset = src.tset;
            } else {
                continue;
            }
            plan.label = PACK_EDGE; // Reuse label to just update tile
            plans.add(plan);
        }
        return plans;
    }

    private void setEdgeFillShellPreview() {
        if (edgeFillJob.shellIndex == 0) {
            edgeFillJob.previewShell = edgeFillJob.inside;
        }
    }

    private java.util.ArrayList<EdgeFillPaintPlan> planCurrentShell() {
        return planRegionBoundaryShell(edgeFillJob.inside, edgeFillJob.fillTset,
                edgeFillJob.fillTerrain, edgeFillJob.outsideTerrain, edgeFillJob.fillCenter);
    }

    private void cancelEdgeFillJob() {
        if (edgeFillJob == null)
            return;
        if (brushStrokeActive)
            endBrushStroke();
        edgeFillJob = null;
    }

    private void finishEdgeFillJob() {
        if (edgeFillJob != null && brushStrokeActive)
            endBrushStroke();
        edgeFillJob = null;
    }

    private void advanceEdgeFillToNextShell() {
        finishEdgeFillJob();
    }

    private void startEdgeFillReversePhase() {
        finishEdgeFillJob();
    }

    private void startEdgeFillJob(int seed, long matchGid) {
        cancelEdgeFillJob();
        java.util.HashSet<Integer> region = collectConnectedRegion(seed, matchGid);
        if (region.isEmpty())
            return;

        edgeFillJob = new EdgeFillJob();
        edgeFillJob.region = region;
        edgeFillJob.inside = new java.util.HashSet<Integer>(region);
        edgeFillJob.labels = new java.util.HashMap<Integer, Integer>();
        edgeFillJob.shellIndex = 0;

        // Map tile is the inside
        tile mapTile = resolveEdgeFillCenterTile(matchGid, seed);
        if (mapTile == null && !macroTerrain.getTerrains().isEmpty())
            mapTile = ensureMacroTerrainCenterTile(macroTerrain.getSelTerrain());
            
        // Picked tile is the outside
        long pickedBare = stripTileGidFlags(curspr);
        tile pickedTile = null;
        if (fillGidUsesMacroTerrain(curspr)) {
            pickedTile = resolveMacroTerrainAutotileCenter((int) pickedBare, macroTerrain.getTileMeta((int) pickedBare));
        } else {
            int localPickedId = -1;
            if (curtset >= 0 && curtset < tilesets.size()) {
                localPickedId = (int) (pickedBare - tilesets.get(curtset).getFirstgid());
            }
            if (curtset >= 0 && localPickedId >= 0 && localPickedId < tilesets.get(curtset).getTilecount()) {
                tile t = tilesets.get(curtset).getTileMeta(localPickedId);
                pickedTile = resolveTerrainAutotileCenter(tilesets.get(curtset), t);
            }
        }
        
        if (mapTile != null && mapTile.isTerrainForEditor() && pickedTile != null && pickedTile.isTerrainForEditor()) {
            edgeFillJob.fillCenter = mapTile;
            edgeFillJob.fillTerrain = mapTile.getTerrain().clone(); // inside
            edgeFillJob.outsideTerrain = pickedTile.getTerrain().clone(); // outside
            edgeFillJob.fillTset = curtset;
            if (!macroTerrain.getTerrains().isEmpty())
                updateMacroAT();
        } else if (mapTile != null && mapTile.isTerrainForEditor()) {
            // Fallback if picked tile is not terrain
            edgeFillJob.fillCenter = mapTile;
            edgeFillJob.fillTerrain = mapTile.getTerrain().clone();
            edgeFillJob.outsideTerrain = mapTile.getTerrain().clone();
            edgeFillJob.fillTset = layers.get(selLayer).getTset().get(seed);
            if (edgeFillJob.fillTset < 0)
                edgeFillJob.fillTset = resolveTilesetIndexForGid(matchGid, curtset);
            if (!macroTerrain.getTerrains().isEmpty())
                updateMacroAT();
        }

        setEdgeFillShellPreview();
        if (edgeFillJob.previewShell == null || edgeFillJob.previewShell.isEmpty()) {
            edgeFillJob = null;
            return;
        }
        edgeFillJob.phase = EdgeFillJob.Phase.PREVIEW;
        edgeFillJob.phaseTimer = EDGE_FILL_PREVIEW_SEC;
    }

    private void tickEdgeFillJob(float delta) {
        if (edgeFillJob == null || edgeFillJob.phase == EdgeFillJob.Phase.IDLE)
            return;

        if (edgeFillJob.phase == EdgeFillJob.Phase.PREVIEW) {
            edgeFillJob.phaseTimer -= delta;
            if (edgeFillJob.phaseTimer > 0f)
                return;
            edgeFillJob.paintQueue = planCurrentShell();
            edgeFillJob.paintIndex = 0;
            if (edgeFillJob.paintQueue.isEmpty()) {
                startEdgeFillReversePhase();
                return;
            }
            if (!brushStrokeActive) {
                beginBrushStroke();
                follower = false;
            }
            edgeFillJob.phase = EdgeFillJob.Phase.PAINT;
            return;
        }

        if (edgeFillJob.phase == EdgeFillJob.Phase.PAINT || edgeFillJob.phase == EdgeFillJob.Phase.REVERSE) {
            java.util.ArrayList<EdgeFillPaintPlan> queue = edgeFillJob.paintQueue;
            if (queue == null || queue.isEmpty()) {
                if (edgeFillJob.phase == EdgeFillJob.Phase.PAINT)
                    advanceEdgeFillToNextShell();
                else
                    finishEdgeFillJob();
                return;
            }
            int batch = EDGE_FILL_PAINT_BATCH;
            while (batch-- > 0 && edgeFillJob.paintIndex < queue.size()) {
                EdgeFillPaintPlan plan = queue.get(edgeFillJob.paintIndex++);
                if (plan.gid > 0) {
                    follower = true;
                    updateTileData(selLayer, plan.num, plan.gid, plan.tset);
                }
                if (edgeFillJob.phase == EdgeFillJob.Phase.PAINT) {
                    edgeFillJob.inside.remove(plan.num);
                }
            }
            if (edgeFillJob.paintIndex < queue.size())
                return;
            if (edgeFillJob.phase == EdgeFillJob.Phase.PAINT) {
                edgeFillJob.shellIndex++;
                advanceEdgeFillToNextShell();
            } else {
                finishEdgeFillJob();
            }
        }
    }

    private void drawEdgeFillPreview() {
        if (edgeFillJob == null || edgeFillJob.phase != EdgeFillJob.Phase.PREVIEW)
            return;
        if (edgeFillJob.previewSources != null && !edgeFillJob.previewSources.isEmpty()) {
            sr.setColor(0f, 0.85f, 1f, 0.35f);
            for (int num : edgeFillJob.previewSources)
                drawBrushTileHighlight(num);
        }
        if (edgeFillJob.previewShell != null && !edgeFillJob.previewShell.isEmpty()) {
            sr.setColor(1f, 0f, 0f, 0.35f);
            for (int num : edgeFillJob.previewShell)
                drawBrushTileHighlight(num);
        }
    }

    private void fillEdgesRegion(int seed, long matchGid) {
        startEdgeFillJob(seed, matchGid);
    }

    private void restoreWorldInput() {
        if (im != null)
            Gdx.input.setInputProcessor(im);
    }

    private interface ToolMenuCallback {
        void onSelect(int index);
    }

    private void showDrawingToolMenu(String title, String[] labels, int selectedIndex,
            final ToolMenuCallback onSelect) {
        final Dialog dlg = new Dialog("", skin, "dialog") {
            @Override
            public void hide() {
                super.hide();
                restoreWorldInput();
            }
        };
        Table content = dlg.getContentTable();
        float dialogBtnWidth = btnx > 0 ? btnx : getDialogContentWidth();
        if (title != null && !title.isEmpty()) {
            Label titleLabel = new Label(title, skin);
            titleLabel.setAlignment(Align.center);
            titleLabel.setWrap(true);
            content.add(titleLabel).width(dialogBtnWidth).pad(8).row();
        }
        for (int i = 0; i < labels.length; i++) {
            final int idx = i;
            String label = labels[i];
            if (i == selectedIndex)
                label = "> " + label;
            TextButton btn = new TextButton(label, skin);
            btn.addListener(new ChangeListener() {
                @Override
                public void changed(ChangeEvent event, Actor actor) {
                    dlg.hide();
                    onSelect.onSelect(idx);
                }
            });
            content.add(btn).width(dialogBtnWidth).height(btny).pad(3).row();
        }
        TextButton cancelBtn = new TextButton(z.cancel != null ? z.cancel : "Cancel", skin);
        cancelBtn.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor) {
                dlg.hide();
            }
        });
        content.add(cancelBtn).width(dialogBtnWidth).height(btny).pad(6).row();
        dlg.setWidth(dialogBtnWidth);
        Gdx.input.setInputProcessor(stage);
        dlg.show(stage);
    }

