    private void stampBrushBetween(int fromNum, int toNum) {
        if (fromNum < 0 || toNum < 0)
            return;
        if (fromNum == toNum) {
            stampBrushAt(toNum);
            return;
        }
        int x0 = fromNum % Tw, y0 = fromNum / Tw;
        int x1 = toNum % Tw, y1 = toNum / Tw;
        int dx = Math.abs(x1 - x0), dy = Math.abs(y1 - y0);
        int sx = x0 < x1 ? 1 : -1, sy = y0 < y1 ? 1 : -1;
        int err = dx - dy;
        int cx = x0, cy = y0;
        while (true) {
            stampBrushAt(cy * Tw + cx);
            if (cx == x1 && cy == y1)
                break;
            int e2 = 2 * err;
            boolean moveX = e2 > -dy;
            boolean moveY = e2 < dx;
            if (pencilMode && moveX && moveY) {
                // avoid pure diagonal: step horizontally first, stamp, then vertically
                err -= dy;
                cx += sx;
                stampBrushAt(cy * Tw + cx);
                err += dx;
                cy += sy;
            } else {
                if (moveX) {
                    err -= dy;
                    cx += sx;
                }
                if (moveY) {
                    err += dx;
                    cy += sy;
                }
            }
        }
    }

    /** Tile index under world-space touch for orthogonal tile grids, or -1. */
    private int orthogonalTileGridAt(float wx, float wy, int cols, int rows, int tileW, int tileH) {
        if (tileW < 1 || tileH < 1)
            return -1;
        if (wy >= tileH || wy <= -tileH * rows + tileH || wx <= 0 || wx >= tileW * cols)
            return -1;
        int col = (int) (wx / tileW);
        if (col >= cols)
            col = cols - 1;
        int row;
        if (wy > 0) {
            row = 0;
        } else {
            row = (int) Math.ceil(-wy / tileH - 1e-9);
        }
        if (col < 0 || row < 0 || col >= cols || row >= rows)
            return -1;
        return row * cols + col;
    }

    private int findOrAddPaletteColor(Color src) {
        int palIdx = getPixelArtPaletteIndex();
        if (palIdx < 0 || src == null)
            return -1;
        tileset palette = tilesets.get(palIdx);
        ensureTilesetPixmap(palette);
        for (int i = 0; i < pixelPaletteUsedCount; i++) {
            Color c = PixelArtPalette.getTileColor(palette, i);
            if (c.r == src.r && c.g == src.g && c.b == src.b && c.a == src.a)
                return i;
        }
        int slot = pixelPaletteUsedCount;
        pixelPaletteUsedCount++;
        savePaletteUsedCount();
        PixelArtPalette.setTileColor(palette, slot, src);
        PixelArtPalette.refreshTexture(palette);
        PixelArtPalette.syncEmbeddedPng(palette);
        resetCaches();
        return slot;
    }

    private void pickSwatchToPaletteAndMap(Color src) {
        int slot = findOrAddPaletteColor(src);
        if (slot >= 0)
            pickPaletteSlotAndMap(slot);
    }

    private void finishPixelArtPalettePick(int slotIndex) {
        pickPaletteSlotAndMap(slotIndex);
    }

    private void applySwatchToPalette(Color src, boolean replace) {
        if (!isPixelArtMap())
            return;
        int palIdx = getPixelArtPaletteIndex();
        if (palIdx < 0 || src == null)
            return;
        if (!replace) {
            appendSwatchToPaletteAndMap(src);
            return;
        }
        int slot = getSelectedPaletteSlot();
        if (slot < 0)
            return;
        tileset palette = tilesets.get(palIdx);
        ensureTilesetPixmap(palette);
        PixelArtPalette.setTileColor(palette, slot, src);
        PixelArtPalette.refreshTexture(palette);
        PixelArtPalette.syncEmbeddedPng(palette);
        resetCaches();
        pickPaletteSlotAndMap(slot);
    }

    /** Append a new palette slot even if the color already exists (Add New). */
    private void appendSwatchToPaletteAndMap(Color src) {
        int palIdx = getPixelArtPaletteIndex();
        if (palIdx < 0 || src == null)
            return;
        tileset palette = tilesets.get(palIdx);
        ensureTilesetPixmap(palette);
        int slot = pixelPaletteUsedCount;
        pixelPaletteUsedCount++;
        savePaletteUsedCount();
        PixelArtPalette.setTileColor(palette, slot, src);
        PixelArtPalette.refreshTexture(palette);
        PixelArtPalette.syncEmbeddedPng(palette);
        resetCaches();
        pickPaletteSlotAndMap(slot);
    }

    private void clearSelectedPaletteSlotsTransparent() {
        if (!isPixelArtMap())
            return;
        int palIdx = getPixelArtPaletteIndex();
        if (palIdx < 0)
            return;
        tileset palette = tilesets.get(palIdx);
        ensureTilesetPixmap(palette);
        boolean changed = false;
        for (int i = 0; i < massprops.size() && i < pixelPaletteUsedCount; i++) {
            if (massprops.get(i)) {
                PixelArtPalette.setTileTransparent(palette, i);
                changed = true;
            }
        }
        if (!changed) {
            int slot = getSelectedPaletteSlot();
            if (slot >= 0 && slot < pixelPaletteUsedCount) {
                PixelArtPalette.setTileTransparent(palette, slot);
                changed = true;
            }
        }
        if (changed) {
            PixelArtPalette.refreshTexture(palette);
            PixelArtPalette.syncEmbeddedPng(palette);
            resetCaches();
        }
    }

    private boolean isPixelArtPaletteView() {
        return isPixelArtMap() && seltset == getPixelArtPaletteIndex();
    }

    private boolean isPixelArtSwatchView() {
        return isPixelArtMap() && seltset == getPixelArtSwatchIndex();
    }

    private boolean isPixelArtSwatchActive() {
        return isPixelArtMap() && curtset == getPixelArtSwatchIndex();
    }

    /**
     * Zoom so a small 1×1-tile canvas fills the screen (lower value = more
     * magnification).
     */
    private float pixelArtMapZoom() {
        float viewMin = Math.min(ssx, ssy);
        if (viewMin <= 0f)
            viewMin = 800f;
        float mapW = Math.max(Tw * Tsw, 1f);
        float mapH = Math.max(Th * Tsh, 1f);
        float fit = Math.max(mapW / viewMin, mapH / viewMin) * 0.88f;
        float minZoom = Tsw / 320f;
        return Math.min(Math.max(fit, minZoom), maxWorldZoomOut());
    }

    private float pixelArtTilePickerZoom(tileset t) {
        float viewMin = Math.min(ssx, ssy);
        if (viewMin <= 0f)
            viewMin = 800f;
        float pickW = Math.max(t.getWidth() * t.getTilewidth(), 1f);
        float pickH = Math.max(t.getHeight() * t.getTileheight(), 1f);
        float fit = Math.max(pickW / viewMin, pickH / viewMin) * 0.75f;
        return Math.min(Math.max(fit, Tsw / 320f), 2f);
    }

    public void resetcam(boolean animate) {
        if (cam == null)
            return;
        int onset = 0;
        if (orientation.equalsIgnoreCase("isometric")) {
            onset = Tsw * Tw / 2;
        }
        float cx = Tsw * Tw / 2 - onset;
        float cy = -Tsh * Th / 2;
        if (is3DMode || isFull3DMode) {
            cam3dTargetX = cx;
            cam3dTargetY = cy;
            cam3dYaw = 225f;
            cam3dPitch = 45f;
            cam3dZoom = 1.0f;
        }
        boolean pixelArt = isPixelArtMap();
        float mapZoom = pixelArt ? pixelArtMapZoom() : 0.5f;
        float mapZoomTarget = pixelArt ? mapZoom : Tsw / 64f;

        if (animate) {
            float animZoom = pixelArt ? mapZoom : 0.25f;
            panTo(cx, cy, animZoom, pixelArt ? 0f : 0.5f);
        } else {
            cam.position.set(cx, cy, 0);
            cam.zoom = mapZoom;
            cam.update();
            panTo(cx, cy, mapZoomTarget, pixelArt ? 0f : 1f);
        }

        resetMinimap();

        if (tilesets.size() > 0) {
            float ttsw = tilesets.get(seltset).getTilewidth();
            float ttsh = tilesets.get(seltset).getTileheight();
            float ttkw = tilesets.get(seltset).getWidth();
            float ttkh = tilesets.get(seltset).getHeight();

            tilecam.position.set((int) ttsw * ttkw / 2, (int) -ttsh * ttkh / 2, 0);
            tilecam.zoom = pixelArt ? pixelArtTilePickerZoom(tilesets.get(seltset)) : 0.25f;
            tilecam.update();
        }

    }

    public java.util.List<Integer> cacheTset(java.util.List<Long> spr) {
        if (spr == null) {
            return new ArrayList<Integer>();
        }
        tilesetsize = tilesets.size();
        java.util.List<Integer> nyot = new ArrayList<>();
        for (int s = 0; s < spr.size(); s++) {
            int idx = resolveTilesetIndexForGid(spr.get(s), -1);
            nyot.add(idx);
        }
        return nyot;
    }

    private boolean tilesetFirstgidsNeedRenumber() {
        int next = 1;
        for (int i = 0; i < tilesets.size(); i++) {
            if (tilesets.get(i).getFirstgid() != next)
                return true;
            next += Math.max(1, tilesets.get(i).getTilecount());
        }
        return false;
    }

    private java.util.List<Integer> listObjectLayerIndices() {
        java.util.List<Integer> indices = new ArrayList<Integer>();
        for (int i = 0; i < layers.size(); i++) {
            if (layers.get(i).getType() == layer.Type.OBJECT)
                indices.add(i);
        }
        return indices;
    }

    private String objectLayerLabel(int layerIdx) {
        layer lay = layers.get(layerIdx);
        String name = lay.getName();
        if (name == null || name.isEmpty())
            name = z.objectgroup != null ? z.objectgroup : "Object Layer";
        return name + "  [" + (layerIdx + 1) + "]";
    }

    private int countAllMapObjects() {
        int count = 0;
        for (int i = 0; i < layers.size(); i++) {
            if (layers.get(i).getType() == layer.Type.OBJECT)
                count += layers.get(i).getObjects().size();
        }
        return count;
    }

