    @Override
    public boolean touchDown(float p1, float p2, int p3, int p4) {
        if (kartu.equalsIgnoreCase("game")) {
            return true;
        }
        if (kartu.equalsIgnoreCase("editor")) {
            Vector3 touch2 = new Vector3();
            uicam.unproject(touch2.set(p1, p2, 0));

            if (tapEditorMenu(touch2))
                return true;
        }

        velx = 0;
        vely = 0;
        pinchZoomActive = false;
        if ("world".equals(kartu)) {
            initialZoom = (is3DMode || isFull3DMode) ? cam3dZoom : cam.zoom;
            if (replaceRangePicking && beginReplaceRangeDrag(p1, p2))
                return true;
        } else if ("tile".equals(kartu) || "pickanim".equals(kartu)) {
            initialZoom = tilecam.zoom;
            if (isActiveTerrainEditorPicker() && tilesets.size() > 0) {
                Vector3 touch = new Vector3();
                tilecam.unproject(touch.set(p1, p2, 0));
                boolean hitTile = false;
                if (isMacroTerrainEditorPicker()) {
                    int hitIdx = findMacroTilesetAtWorld(touch.x, touch.y);
                    if (hitIdx >= 0 && hitIdx < tilesets.size()) {
                        float[][] pos = computeMacroPackedPositions();
                        float localX = touch.x - pos[0][hitIdx];
                        float localY = touch.y - pos[1][hitIdx];
                        hitTile = terrainEditorHalfCellAt(tilesets.get(hitIdx), localX, localY) >= 0;
                    }
                } else {
                    tileset editorTs = getActiveTerrainEditorTileset();
                    hitTile = editorTs != null && terrainEditorHalfCellAt(editorTs, touch.x, touch.y) >= 0;
                }
                if (hitTile) {
                    terrainHoldPending = true;
                    terrainHoldTimer = TERRAIN_HOLD_PAINT_SEC;
                    terrainHoldTouchX = p1;
                    terrainHoldTouchY = p2;
                }
            }
        }
        return false;
    }

