    @Override
    public boolean tap(float p1, float p2, int p3, int p4) {
        toggledThisTap.clear();
        // ve = uicam.project(new Vector3(p1,p2,0f));
        // status (ve.x+"==="+ve.y,5);
        // vo = minicam.unproject(ve);
        if (kartu.equalsIgnoreCase("game")) {
            return true;
        }

        if (loadingfile)
            return true;
        Vector3 touch2 = new Vector3();
        uicam.unproject(touch2.set(p1, p2, 0));
        if (!drag) {

            switch (kartu) {
                case "editor":
                    if (tapEditorActions(touch2))
                        return true;
                    break;
                case "world":

                    if (replaceRangePicking)
                        return true;

                    if (!roll)
                        if (tapWorldMenu(touch2))
                            return true;

                    if (tilesets.size() == 0) {
                        kartu = "tile";
                        return true;
                    }

                    Vector3 touch = new Vector3();
                    unprojectMain(touch.set(p1, p2, 0));

                    int ae = (int) touch.x;
                    int ab = (int) touch.y;

                    boolean touched = false;

                    if (orientation.equalsIgnoreCase("orthogonal")) {
                        touched = touch.y < Tsh && touch.y > -Tsh * Th + Tsh && touch.x > 0 && touch.x < Tsw * Tw;
                    } else if (orientation.equalsIgnoreCase("isometric")) {
                        touched = true;
                    }
                    log(touched + "");
                    if ("object".equals(mode))
                        touched = true;
                    int num = 0;

                    if (touched) {

                        if (orientation.equalsIgnoreCase("orthogonal")) {

                            num = orthogonalTileGridAt(touch.x, touch.y, Tw, Th, Tsw, Tsh);
                        } else if (orientation.equalsIgnoreCase("isometric")) {

                            // cool way to convert isometric to orthogonal, new iso tap detection
                            int newae = ae - ((Tsw / Tsh) * ab) + Tsw / 2;
                            int newab = (ae / (Tsw / Tsh)) + ab - Tsh / 2;
                            num = (Tw * ((-newab + Tsh) / Tsh) + (newae / Tsw));
                            // status(""+newae/2f+"|"+(newab-Tsh)+" num:"+num,1);
                            if (num < 0 || num > Tw * Th)
                                return true;
                            ae = (int) (newae / 2f);
                            ab = newab;
                            // check by the closest to a point, old iso tap detection.
                            /*
                             * float closest = 9999;
                             * for (int i = 0; i < Tw * Th; i++) {
                             * int offsetx = 0, offsety = 0;
                             * xpos = i % Tw;
                             * ypos = i / Tw;
                             * offsetx = (xpos * Tsw / 2) + (ypos * Tsw / 2);
                             * offsety = (xpos * Tsh / 2) - (ypos * Tsh / 2);
                             * int drawx = xpos * Tsw - offsetx;
                             * int drawy = -ypos * Tsh - offsety;
                             * int x = ae - drawx;
                             * int y = ab - drawy;
                             * int Tsws = Tsw / 2;
                             * int Tshs = Tsh / 2;
                             * float dx = Math.abs(x - Tsws);
                             * float dy = Math.abs(y - Tshs);
                             * if (dx / Tsws + dy / Tshs < closest) {
                             * num = i;
                             * closest = dx / Tsws + dy / Tshs;
                             * }
                             * }
                             * 
                             */
                        }
                    }

                    if ("tile".equals(mode) && touched && num >= 0) {

                        if (activetool == 4) {
                            stampBrushAt(num);
                            endBrushStroke();
                        } else {
                            tapTile(num, false, true, false, curspr);
                        }
                        log(num + "");
                    } else if ("object".equals(mode)) {
                        final java.util.List<obj> foundObjs = new ArrayList<obj>();
                        Vector3 touchObj = new Vector3();
                        unprojectMain(touchObj.set(p1, p2, 0));
                        float objX = touchObj.x;
                        float objY = touchObj.y;
                        world.QueryAABB(new com.badlogic.gdx.physics.box2d.QueryCallback() {
                            @Override
                            public boolean reportFixture(com.badlogic.gdx.physics.box2d.Fixture fixture) {
                                Object userData = fixture.getUserData();
                                if (userData instanceof obj) {
                                    obj candidate = (obj) userData;
                                    if (layers.get(selLayer).getObjects().contains(candidate)
                                            && !foundObjs.contains(candidate)) {
                                        foundObjs.add(candidate);
                                    }
                                }
                                return true;
                            }
                        }, objX - 3, objY - 3, objX + 3, objY + 3);

                        if (activeobjtoolmode == 1) {
                            boolean isMulti = sMultiSelect || Gdx.input.isKeyPressed(Input.Keys.SHIFT_LEFT)
                                    || Gdx.input.isKeyPressed(Input.Keys.SHIFT_RIGHT)
                                    || Gdx.input.isKeyPressed(Input.Keys.CONTROL_LEFT)
                                    || Gdx.input.isKeyPressed(Input.Keys.CONTROL_RIGHT);
                            if (!foundObjs.isEmpty()) {
                                if (isMulti) {
                                    checkBox2D(foundObjs.get(0));
                                } else {
                                    selobjs.clear();
                                    for (obj o : foundObjs) {
                                        checkBox2D(o);
                                    }
                                }
                            } else if (!isMulti) {
                                selobjs.clear();
                            }
                        } else if (activeobjtoolmode == 0) {
                            if (!foundObjs.isEmpty()) {
                                activeobjtoolmode = 1; // Switch to select mode
                                selobjs.clear();
                                for (obj o : foundObjs) {
                                    checkBox2D(o);
                                }
                            } else {
                                longpressObject(p1, p2);
                            }
                        }

                    } else if ("newpoly".equals(mode)) {
                        tapNewPoly(num, ae, ab);
                    }
                    break;
                case "tile":
                case "pickanim":
                default:
                    if (tapPickUI(p1, p2))
                        return true;
                    tapPick(p1, p2);
                    break;

            }
        }
        // updateMinimap();
        return false;

    }

    private boolean tapNewPoly(Integer num, int ae, int ab) {
        obj nyok = newobject;
        if (magnet == 1) {
            switch (nyok.getShape()) {
                case "polygon":
                case "polyline":
                    int a = ae - (int) nyok.getX();
                    int b = -ab - (int) nyok.getY() + Tsh;
                    if (a < 0)
                        a -= Tsw;
                    if (b < 0)
                        b -= Tsh;
                    int x = (a / Tsw) * Tsw;
                    int y = (b / Tsh) * Tsh;

                    nyok.addPoint(x, y);
                    break;

            }
        } else {
            nyok.addPoint((int) ae - nyok.getX(), -(int) ab + Tsh - nyok.getY());

        }
        return false;
    }

