    public void updateMarkers() {
        if (selobjs.size() == 0)
            return;
        if (!markermode && cam.zoom != lastMarkerZoom) {
            requestupdatemarker = true;
            lastMarkerZoom = cam.zoom;
        }
        if (requestupdatemarker) {
            requestupdatemarker = false;

            updateObjectCollision();

            if (layers.get(selLayer).getType() != layer.Type.OBJECT)
                return;
            for (obj o : layers.get(selLayer).getObjects()) {
                if (selobjs.contains(o)) {
                    o.updateVerticesActive(world, Tsh, cam.zoom);
                }
            }
        }

    }

    public String olddata;

    public void checkBox2D(obj o) {
        if (activeobjtoolmode != 1)
            return;

        boolean isMulti = sMultiSelect || Gdx.input.isKeyPressed(Input.Keys.SHIFT_LEFT)
                || Gdx.input.isKeyPressed(Input.Keys.SHIFT_RIGHT) || Gdx.input.isKeyPressed(Input.Keys.CONTROL_LEFT)
                || Gdx.input.isKeyPressed(Input.Keys.CONTROL_RIGHT);

        if (isMulti) {
            if (toggledThisTap.contains(o)) {
                return;
            }
            toggledThisTap.add(o);

            if (selobjs.contains(o)) {
                selobjs.remove(o);
                oldobjdata.remove(o.getId());
            } else {
                selobjs.add(o);

                obj oc = new obj();
                oc.setGid(o.getGid());
                oc.setProperties(o.getProperties());
                oc.setPoints(o.getPoints());
                oc.setW(o.getW());
                oc.setH(o.getH());
                oc.setX(o.getX());
                oc.setY(o.getY());
                oc.setId(o.getId());
                oc.setName(o.getName());
                oc.setRotation(o.getRotation());
                oc.setShape(o.getShape());
                oc.setType(o.getType());
                oc.setText(o.getText());
                Json json = new Json();
                String data = json.toJson(oc);
                oldobjdata.put(o.getId(), data);
                olddata = data;
            }
        } else {
            if (!selobjs.contains(o)) {
                selobjs.add(o);

                obj oc = new obj();
                oc.setGid(o.getGid());
                oc.setProperties(o.getProperties());
                oc.setPoints(o.getPoints());
                oc.setW(o.getW());
                oc.setH(o.getH());
                oc.setX(o.getX());
                oc.setY(o.getY());
                oc.setId(o.getId());
                oc.setName(o.getName());
                oc.setRotation(o.getRotation());
                oc.setShape(o.getShape());
                oc.setType(o.getType());
                oc.setText(o.getText());
                Json json = new Json();
                String data = json.toJson(oc);
                oldobjdata.put(o.getId(), data);
                olddata = data;
            }
        }
        requestupdatemarker = true;
    }

