    private void handleCollabConnectionLost() {
        if (!isClient)
            return;
        isClient = false;
        boolean wasCreator = isCreateRoom;
        boolean wasJoiner = isJoinRoom;
        String room = activeRoom;
        boolean connected = false;
        try {
            connected = client != null && client.isConnected();
        } catch (Exception ignored) {
        }
        try {
            if (connected) {
                if (wasCreator && room != null && !room.isEmpty()) {
                    command c = new command();
                    c.from = myID;
                    c.room = room;
                    c.command = "destroyRoom";
                    c.data = "";
                    client.sendTCP(c);
                } else if (wasJoiner && room != null && !room.isEmpty()) {
                    command c = new command();
                    c.from = myID;
                    c.room = room;
                    c.command = "leaveRequest";
                    c.data = "";
                    client.sendTCP(c);
                }
                command cc = new command();
                cc.command = "disconnect";
                cc.from = myID;
                client.sendTCP(cc);
            }
            if (client != null) {
                client.close();
                client.stop();
            }
        } catch (Exception ignored) {
        }
        resetCollabRoomUi();
        if (tbJoin != null)
            tbJoin.setText(z.join);
        logNet("Connection lost");
    }

    private void applyRemoteDraw(layerhistory h) {
        if (h == null || collabMapSyncInProgress || loadingfile)
            return;
        if (layers == null || layers.isEmpty())
            return;
        int lay = h.getLayer();
        if (lay < 0 || lay >= layers.size())
            return;
        if (layers.get(lay).getType() != layer.Type.TILE)
            return;
        int loc = h.getLocation();
        int total = Tw * Th;
        if (total <= 0 || loc < 0 || loc >= total)
            return;
        if (h.undo) {
            long frm = h.from;
            long toe = h.to;
            int frmts = h.oldtset;
            int toets = h.newtset;
            int frmtl = h.oldtile;
            int toetl = h.newtile;
            h.from = toe;
            h.to = frm;
            h.oldtset = toets;
            h.newtset = frmts;
            h.undo = false;
            h.oldtile = toetl;
            h.newtile = frmtl;
        }
        undolayer.add(h);
        mapDirty = true;
        redolayer.clear();
        layers.get(lay).getStr().set(loc, h.getTo());
        layers.get(lay).getTset().set(loc, h.getNewtset());
        layers.get(lay).getTile().set(loc, h.getNewtile());
        updateCache(loc);
    }

    public void pushUpdate() {
        if (isCreateRoom || isJoinRoom) {
            saveMapBlocking(curdir + "/" + curfile);
            FileHandle ff = Gdx.files.absolute(curdir + "/" + curfile);
            String dat = ff.readString();

            ///////
            command cc = new command();
            cc.command = "startDataAll";
            cc.from = myID;
            cc.room = activeRoom;
            client.sendTCP(cc);

            int len = dat.length();
            for (int i = 0; i < len; i += BufferSize) {
                String part = dat.substring(i, Math.min(len, i + BufferSize));
                cc = new command();
                cc.command = "dataAll";
                cc.from = myID;
                cc.room = activeRoom;
                cc.data = part;
                slowdown();
                client.sendTCP(cc);

            }
            ///////

            cc = new command();
            cc.command = "allReadThis";
            cc.room = activeRoom;
            cc.from = myID;
            client.sendTCP(cc);
            logNet("[C] Pushing map update...");
        }
    }

