    private void stopServer() {
        try {
            server.stop();
            isServer = false;
            tbHost.setText(z.host);
            activeClients.clear();
            logNet("Server stopped");
        } catch (Exception e) {
        }
    }

    private void stopClient() {
        try {
            if (!isClient)
                return;
            isClient = false;
            boolean wasCreator = isCreateRoom;
            boolean wasJoiner = isJoinRoom;
            String room = activeRoom;
            boolean connected = client != null;
            try {
                connected = connected && client.isConnected();
            } catch (Exception ignored) {
                connected = false;
            }
            if (connected) {
                if (wasCreator && room != null && !room.isEmpty()) {
                    command c = new command();
                    c.from = myID;
                    c.room = room;
                    c.command = "destroyRoom";
                    c.data = "";
                    client.sendTCP(c);
                } else if (wasJoiner && room != null && !room.isEmpty()) {
                    command c = new command();
                    c.from = myID;
                    c.room = room;
                    c.command = "leaveRequest";
                    c.data = "";
                    client.sendTCP(c);
                }

                command cc = new command();
                cc.command = "disconnect";
                cc.from = myID;
                client.sendTCP(cc);
                client.close();
                client.stop();
            } else if (client != null) {
                try {
                    client.close();
                    client.stop();
                } catch (Exception ignored) {
                }
            }

            resetCollabRoomUi();
            tbJoin.setText(z.join);
            logNet("Client disconnected");

        } catch (Exception e) {
        }
    }

    private void destroyRoom() {
        try {
            if (activeRoom == null || activeRoom.isEmpty()) {
                logNet("Not in a room.");
                return;
            }
            if (!isCreateRoom) {
                logNet("Only the room creator can destroy the room.");
                return;
            }
            command c = new command();
            c.from = myID;
            c.room = activeRoom;
            c.command = "destroyRoom";
            c.data = "";
            client.sendTCP(c);

        } catch (Exception e) {
        }
    }

