    private void broadcastRoomUsers(String room) {
        StringBuilder sb = new StringBuilder();
        for (actvClients av : activeClients) {
            if (av.room.equalsIgnoreCase(room)) {
                if (sb.length() > 0)
                    sb.append(", ");
                String cleanName = av.id.contains("_") ? av.id.substring(0, av.id.lastIndexOf("_")) : av.id;
                sb.append(cleanName);
            }
        }
        command cc = new command();
        cc.command = "roomUsers";
        cc.room = room;
        cc.data = sb.toString();
        server.sendToAllTCP(cc);
    }

    private void runServer(int port) {
        try {
            saveCollabPrefs();
            if (port <= 0) {
                logNet("Please enter port number.");
                return;
            }
            server.start();
            server.bind(port);
            if (mygame != null) {
                // mygame.server = server;
            }

            logNet("Server started on port :" + Integer.toString(port));
            logNet(z.listeningon + " " + getLocalIpAddress());
            isServer = true;
            tbHost.setText(z.stopserver);
            localIP = getLocalIpAddress();
            tfRemoteIP.setText(getLocalIpAddress());

        } catch (Exception e) {
        }
    }

    private void runClient(String aipi, int portNum) {
        try {
            saveCollabPrefs();
            if (portNum <= 0) {
                logNet("Please enter port number.");
                return;
            }

            client.start();
            client.connect(5000, aipi, portNum);
            if (mygame != null) {
                // mygame.client = client;
            }

            lcollabstatus.setText(z.status + ": " + z.connectedto + " " + aipi);
            logNet("Client connected to :" + aipi + ":" + Integer.toString(portNum));
            tbJoin.setText(z.disconnectclient);
            isClient = true;
            localIP = getLocalIpAddress();
            registerID();

        } catch (Exception e) {
            logNet(z.failedtoconnect);
            tbJoin.setText(z.join);
            isClient = false;

        }
    }

    private void setTsetFromCurspr() {
        int idx = resolveTilesetIndexForGid(curspr, seltset);
        if (idx >= 0)
            curtset = idx;
    }

    /** Picker tileset changed — drop stale brush GID from the previous tileset. */
    private void onActiveTilesetChanged() {
        pickerCacheValid = false;
        terrainPickerCacheValid = false;
        curtset = seltset;
        curspr = 0;
    }

    /**
     * Ensure curspr/curtset match before painting (avoids drawing with a stale
     * GID).
     */
    private boolean prepareBrushForDraw() {
        if (tilesets.isEmpty() || curspr <= 0)
            return false;
        int idx = resolveTilesetIndexForGid(curspr, curtset);
        if (idx < 0)
            return false;
        curtset = idx;
        return true;
    }

    private int getTsetFromSpr(int i) {
        return resolveTilesetIndexForGid(i, -1);
    }

    private boolean tileExistsInTileset(tileset ts, int localId) {
        if (localId < 0 || localId >= ts.getTilecount())
            return false;
        if (ts.isCollection())
            return CollectionTilesetOps.hasTileImage(ts, localId) || ts.getTileMeta(localId) != null;
        return true;
    }

    private Pixmap getOrphanTilePixmap() {
        if (orphanTilePixmap == null) {
            orphanTilePixmap = new Pixmap(ORPHAN_TILE_PX, ORPHAN_TILE_PX, Pixmap.Format.RGBA8888);
            int half = ORPHAN_TILE_PX / 2;
            for (int x = 0; x < ORPHAN_TILE_PX; x++) {
                for (int y = 0; y < ORPHAN_TILE_PX; y++) {
                    boolean magenta = ((x / half) + (y / half)) % 2 == 0;
                    orphanTilePixmap.setColor(magenta ? Color.MAGENTA : Color.BLACK);
                    orphanTilePixmap.drawPixel(x, y);
                }
            }
        }
        return orphanTilePixmap;
    }

    private Texture getOrphanTileTexture() {
        if (orphanTileTexture == null)
            orphanTileTexture = new Texture(getOrphanTilePixmap());
        return orphanTileTexture;
    }

    /**
     * True when a non-empty layer GID no longer maps to a drawable tile (e.g.
     * deleted tileset).
     */
    private boolean isOrphanedLayerTile(long gid, int preferredTset) {
        if (gid == 0)
            return false;
        if (tilesets.isEmpty())
            return true;
        long bare = stripTileGidFlags(gid);
        int tsetIdx = resolveTilesetIndexForGid(gid, preferredTset);
        if (tsetIdx < 0)
            return true;
        tileset ts = tilesets.get(tsetIdx);
        int localId = (int) (bare - ts.getFirstgid());
        if (localId < 0 || localId >= ts.getTilecount())
            return true;
        return !tileExistsInTileset(ts, localId);
    }

    private drawer orphanTileDrawer(float x, float y, float originX, float originY, float width, float height,
            long mm) {
        drawer d = new drawer();
        d.mm = mm;
        d.setOrphan(true);
        d.setdrawer(0, x, y, originX, originY, width, height, 1f, 1f, 0f, 0, 0, ORPHAN_TILE_PX, ORPHAN_TILE_PX,
                false, false);
        return d;
    }

    private void drawMapDrawer(SpriteBatch batch, drawer d) {
        if (d.isOrphan())
            d.draw(batch, getOrphanTileTexture());
        else
            d.draw(batch, tilesets.get(d.initset).getTexture());
    }

    private void addMapDrawer(SpriteCache cache, drawer d) {
        if (d.isOrphan())
            d.add(cache, getOrphanTileTexture());
        else
            d.add(cache, tilesets);
    }

    private void drawMapDrawerPixmap(drawer d, Pixmap pm2, int Tsw, int Tsh) {
        if (d.isOrphan())
            d.draw(pm2, tilesets, Tsw, Tsh, getOrphanTilePixmap());
        else
            d.draw(pm2, tilesets, Tsw, Tsh);
    }

    /**
     * Resolve which tileset owns a GID; prefers {@code preferredTset} and skips
     * empty collection ranges.
     */
    private int resolveTilesetIndexForGid(long gid, int preferredTset) {
        if (gid == 0)
            return -1;
        long bare = stripTileGidFlags(gid);
        int localId;

        if (preferredTset >= 0 && preferredTset < tilesets.size()) {
            tileset ts = tilesets.get(preferredTset);
            localId = (int) (bare - ts.getFirstgid());
            if (localId >= 0 && localId < ts.getTilecount() && tileExistsInTileset(ts, localId))
                return preferredTset;
        }

        int rangeFallback = -1;
        for (int ii = 0; ii < tilesets.size(); ii++) {
            tileset ts = tilesets.get(ii);
            localId = (int) (bare - ts.getFirstgid());
            if (localId < 0 || localId >= ts.getTilecount())
                continue;
            if (rangeFallback < 0)
                rangeFallback = ii;
            if (tileExistsInTileset(ts, localId))
                return ii;
        }
        return rangeFallback;
    }

    private int getTileFromSpr(int i, tileset t) {

        for (int ii = 0; ii < t.getTiles().size(); ii++) {
            tile ts = t.getTiles().get(ii);
            if (i == ts.getTileID()) {
                return ii;
            }
        }

        return -1;
    }

    private void adjustLayer(tileset ts) {
        for (property p : ts.getProperties()) {
            if (p.getName().equalsIgnoreCase("layer")) {
                for (int l = 0; l < layers.size(); l++) {
                    if (layers.get(l).getName().equalsIgnoreCase(p.getValue())) {
                        if (selLayer != l) {
                            selLayer = l;
                            status("auto switching layer to " + layers.get(l).getName(), 3);
                        } else {
                            selLayer = l;
                        }
                        updateObjectCollision();

                        switch (viewMode) {
                            case STACK:
                            case SINGLE:
                            case FOCUSED:
                                resetCaches();
                                break;
                        }

                        break;
                    }
                }
            }
        }

    }

    private void adjustTileset() {
        for (tileset t : tilesets) {
            for (property p : t.getProperties()) {

                if (layers.get(selLayer).getName().equalsIgnoreCase(p.getValue())) {
                    if (t.getTerrains().size() > 0) {
                        for (tile tl : t.getTiles()) {
                            if (tl.isTerrain() && tl.isCenter()) {
                                curspr = tl.getTileID() + t.getFirstgid();
                                break;
                            }
                        }

                    } else {
                        curspr = t.getFirstgid();
                    }
                    setTsetFromCurspr();
                    recenterpick();
                    return;
                }
            }
        }
    }

    private void updateObjectCollision() {
        if (layers.size() == 0)
            return;
        // if (layers.get(selLayer).getType()!=layer.Type.OBJECT) return;

        // for (layer l: layers){
        // if (l.getType()==layer.Type.OBJECT){

        com.badlogic.gdx.utils.Array<Body> bds = new com.badlogic.gdx.utils.Array<Body>();
        world.getBodies(bds);
        for (Body bd : bds) {
            if (bd == body)
                continue;
            if (world.getBodyCount() == 0)
                break;
            world.destroyBody(bd);
        }
        // }
        // }

        // Null out stale body pointers on all objects to prevent double-free crashes
        for (layer ly : layers) {
            if (ly.getType() == layer.Type.OBJECT) {
                for (obj o : ly.getObjects()) {
                    o.setBody(null);
                }
            }
        }

        for (obj ob : layers.get(selLayer).getObjects()) {
            ob.updateVertices(world, Tsh);
        }

    }

