    private boolean tapEditorActions(Vector3 touch2) {
        if (tapped(touch2, gui.editorcancel)) {
            if (sCustomUI) {
                loadInterface("custominterface.json");
            } else {
                guis gsu = new guis();
                gui = gsu;
            }

            backToMap();
            return true;
        }
        if (tapped(touch2, gui.editorsave)) {
            sCustomUI = true;
            prefs.putBoolean("customui", sCustomUI).flush();
            guis at = new guis();
            at = gui;
            Json json = new Json();
            writeThisAbs(Gdx.files.getExternalStoragePath() + "NotTiled/sample/" + "custominterface.json",
                    json.prettyPrint(at));
            msgbox(z.saved);

            backToMap();
            return true;
        }
        if (tapped(touch2, gui.editormode)) {
            switch (mode) {
                case "tile":
                    mode = "object";
                    break;
                case "object":
                    mode = "image";
                    break;
                case "image":
                    mode = "pick";
                    break;
                case "pick":
                    mode = "tile";
                    break;
            }

            return true;
        }

        if (selectedGUI == null)
            return true;

        if (tapped(touch2, gui.editorleft)) {
            if (landscape) {
                selectedGUI.wl -= 1;
            } else {
                selectedGUI.w -= 1;
            }
            return true;
        }
        if (tapped(touch2, gui.editorright)) {
            if (landscape) {
                selectedGUI.wl += 1;
            } else {
                selectedGUI.w += 1;
            }
            return true;
        }
        if (tapped(touch2, gui.editorup)) {
            if (landscape) {
                selectedGUI.yl -= 1;
            } else {
                selectedGUI.y -= 1;
            }
            return true;
        }
        if (tapped(touch2, gui.editordown)) {
            if (landscape) {
                selectedGUI.yl += 1;
            } else {
                selectedGUI.y += 1;
            }
            return true;
        }

        return false;
    }

