    public void removeSW(int num, String sws) {
        property todel = null;
        for (property p : properties) {
            if (p.getName().equalsIgnoreCase(sws)) {
                todel = p;
            }
        }
        properties.remove(todel);
    }

    boolean assemblying = false;

    @Override
    public boolean longPress(float p1, float p2) {
        if (loadingfile)
            return true;
        if (pinchZoomActive || Gdx.input.isTouched(1))
            return true;
        if (layers.size() == 0 && !(kartu.equals("pickanim") && tilePicker.equals("terraineditor")))
            return true;
        if (kartu.equalsIgnoreCase("game")) {
            return true;
        }

        // Gdx.input.vibrate(50);
        Vector3 touch = new Vector3();
        unprojectMain(touch.set(p1, p2, 0));
        Vector3 touch2 = new Vector3();
        uicam.unproject(touch2.set(p1, p2, 0));
        Vector3 touch3 = new Vector3();
        tilecam.unproject(touch3.set(p1, p2, 0));

        if ("world".equals(kartu)) {
            // autotile
            if (tapped(touch2, gui.autotile) && autotiles.size() > 0) {
                if ("tile".equals(mode) || "object".equals(mode)) {
                    // msgbox("Longpress to run Auto tiles");
                    if (!softcue("refresh") && lockUI)
                        return true;
                    loadList("macro");
                    cue("refresh");
                    return true;
                }
            }
            if ("object".equals(mode) || "tile".equals(mode) || "image".equals(mode)) {

                if (assemblymode && assemblynum != -1) {
                    assemblying = true;
                    boolean follower = false;
                    for (property p : autotiles.get(assemblyid).getProperties()) {

                        if (p.getName().contains(",")) {
                            String[] ass = p.getName().split(",");
                            int axpos = Integer.parseInt(ass[0]);
                            int aypos = Integer.parseInt(ass[1]);

                            int aspr = Integer.parseInt(p.getValue());
                            int atst = getTsetFromSpr(aspr);
                            int newnum = assemblynum + (axpos) + (aypos * Tw);
                            ////////////

                            long oi = aspr;
                            int num = newnum;
                            if (num < 0)
                                continue;
                            if (num >= Tw * Th)
                                continue;
                            updateTileData(selLayer, num, oi, atst);

                        } // comma
                    } // properties

                    return true;
                }

                if (swatches && "tile".equals(mode)) {
                    if (tapped(touch2, gui.sw1)) {
                        removeSW(swatchValue.get(0), "sw1");
                        swatchValue.set(0, 0);
                        return true;
                    }

                    if (tapped(touch2, gui.sw2)) {
                        removeSW(swatchValue.get(1), "sw2");
                        swatchValue.set(1, 0);
                        return true;
                    }
                    if (tapped(touch2, gui.sw3)) {
                        removeSW(swatchValue.get(2), "sw3");
                        swatchValue.set(2, 0);
                        return true;
                    }
                    if (tapped(touch2, gui.sw4)) {
                        removeSW(swatchValue.get(3), "sw4");
                        swatchValue.set(3, 0);
                        return true;
                    }
                    if (tapped(touch2, gui.sw5)) {
                        removeSW(swatchValue.get(4), "sw5");
                        swatchValue.set(4, 0);
                        return true;
                    }
                    if (tapped(touch2, gui.sw6)) {
                        removeSW(swatchValue.get(5), "sw6");
                        swatchValue.set(5, 0);
                        return true;
                    }
                }

                if (tapped(touch2, gui.save)) {
                    sAutoSave = !sAutoSave;
                    prefs.putBoolean("autosave", sAutoSave).flush();
                    return true;
                }

                if (tapped(touch2, gui.layer) || tapped(touch2, gui.layerpick)) {
                    clampSelLayerToSelectable();
                    selLayer = nextSelectableLayer(selLayer, -1);
                    applyLayerModeForSelLayer();
                    updateObjectCollision();
                    resetCaches();
                    // adjustTileset();
                    return true;
                    // '812398BB9
                }

                if (tapped(touch2, gui.viewmode)) {
                    layers.get(selLayer).setVisible(!layers.get(selLayer).isVisible());
                    resetCaches();
                    return true;
                }
                if (tapped(touch2, gui.tool2)) {
                    // eraser: no long-press menu
                    return true;
                }
                if (tapped(touch2, gui.mode)) { // actually add new layer...
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // do nothing, just to prevent longpressing.
                    return true;
                }
                if (tapped(touch2, gui.play)) { // actually add new layer...
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // do nothing, just to prevent longpressing.
                    return true;
                }
                if (tapped(touch2, gui.redo)) {
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // rotating = !rotating;
                    return true;
                }
                if (sMinimap && tapped(touch2, gui.minimap)) {
                    return true;
                }
                if (tapped(touch2, gui.undo)) {
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // loadInterface("custom1.json");
                    /*
                     * Json json = new Json();
                     * writeThisAbs(curdir + "/auto.json", json.prettyPrint(gui));
                     * msgbox("auto.json saved!");
                     */
                    return true;
                }

                if (tapped(touch2, gui.menu)) {
                    FileDialog(z.opentmxfile, "open", "file", new String[] { ".tmx" }, null);
                    return true;
                }
            }

            if ("tile".equals(mode)) {

                int ae = (int) touch.x;
                int ab = (int) touch.y;
                if (tapped(touch2, gui.tool5)) {
                    showBrushToolMenu();
                    return true;
                }

                if (tapped(touch2, gui.tool4)) {
                    showSelectToolMenu();
                    return true;
                }

                if (tapped(touch2, gui.tool3)) {
                    showFillToolMenu();
                    return true;
                }

                if (tapped(touch2, gui.tool1)) {
                    showShapeToolMenu();
                    return true;
                }

                if (tapped(touch2, gui.rotation)) {
                    showRotationToolMenu();
                    return true;
                }

                if (tapped(touch2, gui.picker)) {
                    // FileDialog(z.selectfile, "quickaddtset", "file", new String[]{".tsx", ".png",
                    // ".jpg", ".jpeg", ".bmp", ".gif"}, nullTable);
                    swatches = !swatches;
                    prefs.putBoolean("swatches", swatches).flush();
                    return true;
                }
                if (tilesets.size() == 0 && !replaceRangePicking)
                    return true;

                if (!replaceRangePicking && activetool == 2)
                    return true;

                // the main idea of longpressing is just this line.
                roll = true;
                if (replaceRangePicking)
                    activetool = 0;

                // isometric tile selection is so complicated, how did I make this? lol
                if (orientation.equalsIgnoreCase("orthogonal")) {
                    mapstartSelect = orthogonalTileGridAt(touch.x, touch.y, Tw, Th, Tsw, Tsh);
                } else if (orientation.equalsIgnoreCase("isometric")) {

                    // cool way to convert isometric to orthogonal, new iso tap detection
                    int newae = ae - ((Tsw / Tsh) * ab) + Tsw / 2;
                    int newab = (ae / (Tsw / Tsh)) + ab - Tsh / 2;
                    mapstartSelect = (Tw * ((-newab + Tsh) / Tsh) + (newae / Tsw));

                    if (mapstartSelect < 0 || mapstartSelect > Tw * Th)
                        return true;

                    /*
                     * old way
                     * float closest = 9999;
                     * for (int i = 0; i < Tw * Th; i++) {
                     * int offsetx = 0, offsety = 0;
                     * xpos = i % Tw;
                     * ypos = i / Tw;
                     * offsetx = (xpos * Tsw / 2) + (ypos * Tsw / 2);
                     * offsety = (xpos * Tsh / 2) - (ypos * Tsh / 2);
                     * int drawx = xpos * Tsw - offsetx;
                     * int drawy = -ypos * Tsh - offsety;
                     * int x = ae - drawx;
                     * int y = ab - drawy;
                     * int Tsws = Tsw / 2;
                     * int Tshs = Tsh / 2;
                     * float dx = Math.abs(x - Tsws);
                     * float dy = Math.abs(y - Tshs);
                     * if (dx / Tsws + dy / Tshs < closest) {
                     * mapstartSelect = i;
                     * closest = dx / Tsws + dy / Tshs;
                     * }
                     * }
                     * 
                     */
                }
                // mapstartSelect = (Tw * ((-ab + Tsh) / Tsh) + (ae / Tsw));

                if (replaceRangePicking) {
                    mapendSelect = mapstartSelect;
                    mapinitialSelect = mapstartSelect;
                    return true;
                }

                if (activetool == 4) {
                    stampBrushAt(mapstartSelect);
                }

                // code for the rest, so basically longpressing is just flagging "roll"
                mapendSelect = mapstartSelect;
                mapinitialSelect = mapstartSelect;
                prevnum = mapinitialSelect;

                // you will need this, otherwise the app will crash because it relies on panStop
                // to
                // duplicate to cliplayer

                if (activetool == 3) {
                    layer lay;
                    Json json = new Json();

                    String clip = json.toJson(layers.get(selLayer));
                    clipsource = selLayer;
                    lay = json.fromJson(layer.class, clip);
                    lay.setName("CLIPBOARD"); // why not, lol.
                    cliplayer = lay;

                    // now I have the clipboard layer, just put it on tap...
                }

            } else if ("object".equals(mode)) {
                if (tapped(touch2, gui.layer)) {
                    loadList("obj");
                    return true;
                }
                if (tapped(touch2, gui.mode)) {
                    // getNewTextInput(pNewObjLayerSC, z.addnew, z.object + " " + (layers.size() +
                    // 1), "");
                    return true;
                }
                if (tapped(touch2, gui.objectpickermid)) {
                    // status("Object picker",1);
                    return true;
                }
                if (tapped(touch2, gui.objtool5)) { // actually add new layer...
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // do nothing, just to prevent longpressing.
                    return true;
                }
                if (tapped(touch2, gui.objtool4)) { // actually add new layer...
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // do nothing, just to prevent longpressing.
                    return true;
                }
                if (tapped(touch2, gui.objtool3)) { // actually add new layer...
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // do nothing, just to prevent longpressing.
                    return true;
                }
                if (tapped(touch2, gui.objtool1)) {
                    return true;
                }
                if (tapped(touch2, gui.objtool2)) { // actually add new layer...
                    // getNewTextInput(pNewLayerSC, z.addnew, z.layer + " " + (layers.size() + 1),
                    // "");
                    // do nothing, just to prevent longpressing.
                    return true;
                }

                longpressobj(p1, p2);
                return true;
            }
        } else if ("tile".equals(kartu)) {
            // No tilesets loaded: only Back/Tilesets exist. Long-pressing anywhere
            // else (e.g. the orphaned button regions) must not fall through to
            // tilesets.get(seltset) below, which would crash on an empty list.
            if (tilesets.size() == 0) {
                return true;
            }
            if (tapped(touch2, gui.tilesetsright)) {
                return true;
            }
            if (tapped(touch2, gui.tilesetsleft)) {
                return true;
            }
            if (tapped(touch2, gui.tilesetsmid)) {
                showTilesetManager();
                return true;
            }

            if (pickAuto) {
                return true;
            }

            stamp = true;
            int ae = (int) touch3.x;
            int ab = (int) touch3.y;
            // this line is to sovlve problem of the first line not clicked on 1 x 1 tile.
            if (touch3.y > 0)
                ab = 1;
            int Tsh = tilesets.get(seltset).getTileheight();
            int Tsw = tilesets.get(seltset).getTilewidth();
            if (touch3.y < Tsh && touch3.y > -Tsh * tilesets.get(seltset).getHeight() + Tsh && touch3.x > 0
                    && touch3.x < Tsw * tilesets.get(seltset).getWidth()) {
                startSelect = (tilesets.get(seltset).getWidth() * ((-ab + Tsh) / Tsh) + (ae / Tsw));
                adjustLayer(tilesets.get(curtset));
                endSelect = startSelect;
                initialSelect = startSelect;
            }
        } else if ("pickanim".equals(kartu)) {
            switch (tilePicker) {
                case "massprops":
                    stamp = true;
                    int ae = (int) touch3.x;
                    int ab = (int) touch3.y;
                    int Tsh = tilesets.get(selTsetID).getTileheight();
                    int Tsw = tilesets.get(selTsetID).getTilewidth();
                    if (touch3.y < Tsh && touch3.y > -Tsh * tilesets.get(selTsetID).getHeight() + Tsh && touch3.x > 0
                            && touch3.x < Tsw * tilesets.get(selTsetID).getWidth()) {
                        startSelect = (tilesets.get(selTsetID).getWidth() * ((-ab + Tsh) / Tsh) + (ae / Tsw));
                        endSelect = startSelect;
                        initialSelect = startSelect;
                    }
                    break;

                case "terraineditor":
                    if (tapped(touch2, gui.tilesetsleft) || tapped(touch2, gui.tilesetsright)
                            || tapped(touch2, gui.tilesetsmid) || tapped(touch2, gui.terrainundo)
                            || tapped(touch2, gui.pickerback) || tapped(touch2, gui.terraindelete)
                            || tapped(touch2, gui.terrainshape) || tapped(touch2, gui.newterrain))
                        return true;
                    stamp = false; {
                    tileset tt = getActiveTerrainEditorTileset();
                    if (tt != null && tt.getTerrains().size() > 0
                            && terrainEditorHalfCellAt(tt, touch3.x, touch3.y) >= 0)
                        beginTerrainPaintAt(p1, p2);
                }
                    return true;
                case "macroterraineditor":
                    if (tapped(touch2, gui.tilesetsmid) || tapped(touch2, gui.terrainundo)
                            || tapped(touch2, gui.pickerback) || tapped(touch2, gui.terraindelete)
                            || tapped(touch2, gui.terrainshape) || tapped(touch2, gui.newterrain))
                        return true;
                    stamp = false; {
                    int macroHitIdx = findMacroTilesetAtWorld(touch3.x, touch3.y);
                    if (macroHitIdx >= 0 && macroHitIdx < tilesets.size()
                            && getActiveEditorTerrains().size() > 0) {
                        tileset tt = tilesets.get(macroHitIdx);
                        float[][] pos = computeMacroPackedPositions();
                        float macroLocalX = touch3.x - pos[0][macroHitIdx];
                        float macroLocalY = touch3.y - pos[1][macroHitIdx];
                        if (terrainEditorHalfCellAt(tt, macroLocalX, macroLocalY) >= 0)
                            beginTerrainPaintAt(p1, p2);
                    }
                }
                    return true;

            }

        }

        return false;
    }

