    private com.mirwanda.nottiled.platformer.game mygame;

    private boolean hasPlayerInstance() {
        if (layers == null)
            return false;
        for (layer l : layers) {
            if (l == null)
                continue;
            if (l.getType() == layer.Type.OBJECT) {
                if (l.getObjects() != null) {
                    for (obj o : l.getObjects()) {
                        if (o == null || o.getProperties() == null)
                            continue;
                        for (property p : o.getProperties()) {
                            if (p != null && p.getName() != null && p.getName().equalsIgnoreCase("object")
                                    && p.getValue() != null && p.getValue().trim().equalsIgnoreCase("player")) {
                                return true;
                            }
                        }
                    }
                }
            } else if (l.getType() == layer.Type.TILE) {
                if (l.getStr() != null && tilesets != null) {
                    for (long gid : l.getStr()) {
                        if (gid == 0)
                            continue;
                        for (tileset ts : tilesets) {
                            if (ts == null)
                                continue;
                            if (gid >= ts.getFirstgid() && gid < ts.getFirstgid() + ts.getTilecount()) {
                                int localId = (int) (gid - ts.getFirstgid());
                                if (ts.getTiles() != null) {
                                    for (tile t : ts.getTiles()) {
                                        if (t != null && t.getTileID() == localId && t.getProperties() != null) {
                                            for (property p : t.getProperties()) {
                                                if (p != null && p.getName() != null
                                                        && p.getName().equalsIgnoreCase("object")
                                                        && p.getValue() != null
                                                        && p.getValue().trim().equalsIgnoreCase("player")) {
                                                    return true;
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
        return false;
    }

    private void playgame(final String curdir, final String filex) {
        kartu = "game";
        mygame = new com.mirwanda.nottiled.platformer.game();
        mygame.face = face;
        mygame.create();
        mygame.startgame(curdir, filex, true);
        mygame.resize(Gdx.graphics.getWidth(), Gdx.graphics.getHeight());
    }

    public static String convertToAbsolutepath(String relativePath, String curdir) {
        String ss = "";
        if (relativePath.contains("../")) {
            String sr = relativePath;
            String sb = curdir;

            while (sr.contains("../")) {
                if (sb.lastIndexOf("/") != -1) {
                    sb = sb.substring(0, sb.lastIndexOf("/"));
                } else {
                    sb = "";
                }
                if (sr.length() > 3)
                    sr = sr.substring(3);
            }
            if (sb.equalsIgnoreCase("")) {
                ss = sr;
            } else {
                ss = sb + "/" + sr;
            }
        } else {
            ss = curdir + "/" + relativePath;
        }
        return ss;
    }

    public static String convertToRelativePath(String absolutePath, String relativeTo) {
        StringBuilder relativePath = null;

        absolutePath = absolutePath.replaceAll("\\\\", "/");
        relativeTo = relativeTo.replaceAll("\\\\", "/");

        if (absolutePath.equals(relativeTo) == true) {

        } else {
            String[] absoluteDirectories = absolutePath.split("/");
            String[] relativeDirectories = relativeTo.split("/");

            // Get the shortest of the two paths
            int length = absoluteDirectories.length < relativeDirectories.length ? absoluteDirectories.length
                    : relativeDirectories.length;

            // Use to determine where in the loop we exited
            int lastCommonRoot = -1;
            int index;

            // Find common root
            for (index = 0; index < length; index++) {
                if (absoluteDirectories[index].equals(relativeDirectories[index])) {
                    lastCommonRoot = index;
                } else {
                    break;
                    // If we didn't find a common prefix then throw
                }
            }
            if (lastCommonRoot != -1) {
                // Build up the relative path
                relativePath = new StringBuilder();
                // Add on the ..

                for (index = lastCommonRoot + 1; index < absoluteDirectories.length; index++) {
                    if (absoluteDirectories[index].length() > 0) {
                        relativePath.append("../");
                    }
                }
                for (index = lastCommonRoot + 1; index < relativeDirectories.length - 1; index++) {
                    relativePath.append(relativeDirectories[index] + "/");
                }
                relativePath.append(relativeDirectories[relativeDirectories.length - 1]);
            }
        }

        if (relativePath == null) {
            if (relativeTo.length() > absolutePath.length()) {
                relativePath = new StringBuilder().append(relativeTo.substring(absolutePath.length()));
            }
        }
        return relativePath == null ? null : relativePath.toString();
    }

