    @Override
    public boolean fling(float p1, float p2, int p3) {
        if (loadingfile || is3DMode || isFull3DMode)
            return true;
        if (nofling > 0)
            return true;

        velx = p1;
        vely = p2;
        if (velx > 4000)
            velx = 4000;
        if (velx < -4000)
            velx = -4000;
        if (vely > 4000)
            vely = 4000;
        if (vely < -4000)
            vely = -4000;
        // status(p1+"/"+p2+"/"+p3,5);

        return false;
    }

    long prevnum = 0;

    @Override
    public boolean pan(float p1, float p2, float p3, float p4) {
        if (loadingfile)
            return true;

        if ((is3DMode || isFull3DMode) && kartu.equalsIgnoreCase("world") && !roll) {
            if (is3DMoveMode) {
                com.badlogic.gdx.graphics.Camera activeCam = isFull3DMode ? camFull3D : cam3d;
                if (activeCam != null) {
                    com.badlogic.gdx.math.Vector3 dir = activeCam.direction.cpy();
                    dir.z = 0;
                    dir.nor();
                    com.badlogic.gdx.math.Vector3 right = dir.cpy().crs(activeCam.up);
                    right.z = 0;
                    right.nor();
                    float speed = cam3dZoom * (isFull3DMode ? 1.5f : 0.8f);
                    cam3dTargetX -= (right.x * p3 - dir.x * p4) * speed;
                    cam3dTargetY -= (right.y * p3 - dir.y * p4) * speed;
                }
            } else {
                cam3dYaw -= p3 * 0.25f;
                cam3dPitch += p4 * 0.25f;
                if (cam3dPitch > 85f)
                    cam3dPitch = 85f;
                if (cam3dPitch < 5f)
                    cam3dPitch = 5f;
            }
            return true;
        }

        if (markermode && activeobjtoolmode == 2) {
            editDragStarted = true;
            Vector3 touch2 = new Vector3();
            unprojectMain(touch2.set(p1, p2, 0));
            resizeobject(touch2.x, touch2.y);
            return true;
        }
        if (kartu.equalsIgnoreCase("game")) {
            return true;
        }

        if (kartu.equalsIgnoreCase("editor") && iseditGUI) {

            Vector3 touch2 = new Vector3();
            uicam.unproject(touch2.set(p1, p2, 0));

            if (landscape) {
                float width = selectedGUI.getWl() - selectedGUI.getXl();
                float height = selectedGUI.getHl() - selectedGUI.getYl();
                selectedGUI.setXl((int) touch2.x * 100 / ssy - width / 2);
                selectedGUI.setWl((int) touch2.x * 100 / ssy + width / 2);
                selectedGUI.setYl((int) touch2.y * 100 / ssx - height / 2);
                selectedGUI.setHl((int) touch2.y * 100 / ssx + height / 2);
            } else {
                float width = selectedGUI.getW() - selectedGUI.getX();
                float height = selectedGUI.getH() - selectedGUI.getY();
                selectedGUI.setX(touch2.x * 100 / ssx - width / 2);
                selectedGUI.setW(touch2.x * 100 / ssx + width / 2);
                selectedGUI.setY(touch2.y * 100 / ssy - height / 2);
                selectedGUI.setH(touch2.y * 100 / ssy + height / 2);
            }
            // Gdx.app.log( "HEHE",p1+"/"+ ssx+" : "+ p2+"/"+ssy);

            return true;
        }
        // status(p1+"/"+p2+"/"+p3+"/"+p4,5);

        // this is for tile pickers
        if (stamp && ("tile".equals(kartu) || ("pickanim".equals(kartu) && "massprops".equals(tilePicker)))) {
            Vector3 touch = new Vector3();
            tilecam.unproject(touch.set(p1, p2, 0));
            int ae = (int) touch.x;
            int ab = (int) touch.y;
            if (touch.y > 0)
                ab = 1;
            int posx = 0;
            int posy = 0;
            int initx = 0;
            int inity = 0;
            Integer num = -1;
            int usedtset;
            if ("tile".equals(kartu)) {
                usedtset = seltset;
            } else {
                usedtset = selTsetID;
            }
            int Tha = tilesets.get(usedtset).getHeight();
            int Twa = tilesets.get(usedtset).getWidth();
            int Tsh = tilesets.get(usedtset).getTileheight();
            int Tsw = tilesets.get(usedtset).getTilewidth();
            if (touch.y < Tsh && touch.y > -Tsh * Tha + Tsh && touch.x > 0 && touch.x < Tsw * Twa) {
                num = (Twa * ((-ab + Tsh) / Tsh) + (ae / Tsw));
                posx = ae / Tsw;
                posy = ((-ab + Tsh) / Tsh);
                initx = initialSelect % Twa;
                inity = initialSelect / Twa;
            }
            if (num == -1)
                return true;
            // kanan bawah
            if (posx >= initx && posy >= inity) {
                startSelect = initialSelect;
                endSelect = num;

            }
            // kanan atas
            if (posx >= initx && posy < inity) {
                startSelect = posy * Twa + initx;
                endSelect = inity * Twa + posx;
            }
            // kiri bawah
            if (posx < initx && posy >= inity) {
                startSelect = inity * Twa + posx;
                endSelect = posy * Twa + initx;
            }
            // kiri atas
            if (posx < initx && posy < inity) {
                startSelect = num;
                endSelect = initialSelect;
            }
            return true;
        }
        if (terrainHoldPending && isActiveTerrainEditorPicker()
                && (Math.abs(p3) > TERRAIN_HOLD_CANCEL_PAN || Math.abs(p4) > TERRAIN_HOLD_CANCEL_PAN))
            terrainHoldPending = false;
        if (terrainPainting && isActiveTerrainEditorPicker()) {
            terrainPaintMoved = true;
            return true;
        }

        // this is for map drawing
        if (roll) {
            usetool = true;
            Vector3 touch = new Vector3();
            unprojectMain(touch.set(p1, p2, 0));
            int posx = 0;
            int posy = 0;
            int initx = 0;
            int inity = 0;
            Integer num = mapTileAtWorld(touch.x, touch.y);

            if (num == -1) {
                // When dragging shape tool (activetool==0) to map edge, clamp to nearest edge
                // tile instead of stopping
                if (activetool == 0) {
                    num = clampToEdgeTile(touch.x, touch.y);
                } else {
                    return replaceRangePicking;
                }
            }

            // brushing, basically other tools are not using pan,
            // remember that longpressing fill will turn it into brush?
            if (replaceRangePicking) {
                activetool = 0;
            } else if (activetool == 4 && num != -1 && prevnum != num) {
                stampBrushBetween((int) prevnum, num);
                prevnum = num;

                nofling = 0.4f;
                velx = 0;
                vely = 0;
                return true;
            }

            // now finding pos x and y
            posx = num % Tw;
            posy = num / Tw;
            initx = mapinitialSelect % Tw;
            inity = mapinitialSelect / Tw;

            // kanan bawah
            if (posx >= initx && posy >= inity) {
                mapstartSelect = mapinitialSelect;
                mapendSelect = num;
                rising = false;
            }
            // kanan atas
            if (posx >= initx && posy < inity) {
                mapstartSelect = posy * Tw + initx;
                mapendSelect = inity * Tw + posx;
                rising = true;
            }
            // kiri bawah
            if (posx < initx && posy >= inity) {
                mapstartSelect = inity * Tw + posx;
                mapendSelect = posy * Tw + initx;
                rising = true;
            }
            // kiri atas
            if (posx < initx && posy < inity) {
                mapstartSelect = num;
                mapendSelect = mapinitialSelect;
                rising = false;
            }
            mapfinalSelect = num;
            return true;
        } else {

            // if not "roll", just move the screen then.
            drag = true;
            int buffer = Tsw + Tsh;
            float panspeed = (float) scrollspeed;

            switch (kartu) {

                case "world":

                    float x = p3 * panspeed * cam.zoom;
                    float y = p4 * panspeed * cam.zoom;

                    cam.translate(-x, y);
                    // uicam.translate(-x, y);
                    clampWorldCamPosition();

                    cam.update();
                    // uicam.update();
                    break;
                case "tile":
                case "pickanim":
                    if (tilesets.size() == 0)
                        return true;
                    x = p3 * panspeed * tilecam.zoom;
                    y = p4 * panspeed * tilecam.zoom;
                    tilecam.translate(-x, y);
                    tileset t = tilesets.get(seltset);
                    int scrollTw = t.getTilewidth();
                    int scrollTh = t.getTileheight();
                    if (!"tile".equals(kartu)) {
                        switch (tilePicker) {
                            case "terraineditor":
                            case "macroterraineditor":
                                t = getActiveTerrainEditorTileset();
                                if (t != null) {
                                    scrollTw = terrainEditorHalfCellW(t);
                                    scrollTh = terrainEditorHalfCellH(t);
                                }
                                break;
                            case "newimgobj":
                            case "props":
                            case "rnda":
                            case "rndb":
                            case "repa":
                            case "repb":
                            case "gena":
                            case "genb":
                                t = tilesets.get(selTsetID);
                                break;
                        }
                    }

                    if (tilePicker.equals("macroterraineditor")) {
                        float[][] bndPacked = computeMacroPackedPositions();
                        float maxX2 = 0, minY2 = 0;
                        for (int mi = 0; mi < tilesets.size(); mi++) {
                            tileset mts = tilesets.get(mi);
                            float rx = bndPacked[0][mi] + mts.getWidth() * terrainEditorHalfCellW(mts);
                            float by = bndPacked[1][mi] - getTilesetPickerHeight(mts);
                            if (rx > maxX2) maxX2 = rx;
                            if (by < minY2) minY2 = by;
                        }
                        if (tilecam.position.x < 0)
                            tilecam.position.x = 0;
                        if (tilecam.position.x > maxX2)
                            tilecam.position.x = maxX2;
                        if (tilecam.position.y > scrollTh)
                            tilecam.position.y = scrollTh;
                        if (tilecam.position.y < minY2 + scrollTh)
                            tilecam.position.y = minY2 + scrollTh;
                    } else if (pickAuto) {
                        if (tilecam.position.x < 0)
                            tilecam.position.x = 0;
                        if (tilecam.position.x > 6 * scrollTw)
                            tilecam.position.x = 6 * scrollTw;
                        if (tilecam.position.y > scrollTh)
                            tilecam.position.y = scrollTh;
                        if (tilecam.position.y < -(t.getTerrains().size() * scrollTh) + scrollTh)
                            tilecam.position.y = -(t.getTerrains().size() * scrollTh) + scrollTh;

                    } else {
                        if (tilecam.position.x < 0)
                            tilecam.position.x = 0;
                        if (tilecam.position.x > t.getWidth() * scrollTw)
                            tilecam.position.x = t.getWidth() * scrollTw;
                        if (tilecam.position.y > scrollTh)
                            tilecam.position.y = scrollTh;
                        if (tilecam.position.y < -(t.getHeight() * scrollTh) + scrollTh)
                            tilecam.position.y = -(t.getHeight() * scrollTh) + scrollTh;
                    }

                    tilecam.update();
            }
        }
        return true;
    }

    @Override
    public boolean panStop(float p1, float p2, int p3, int p4) {

        if (loadingfile)
            return true;
        if ("game".equals(kartu))
            return true;
        // stop moving screen
        drag = false;

        // after finishing stamp selection, go to map
        if (stamp && "tile".equals(kartu)) {
            if (!issettingtile) {
                currentShape = ShapeTool.RECTANGLE;
                curspr = (int) tilesets.get(seltset).getGidAtGridIndex(startSelect);
                curtset = seltset;
                curpickAuto = pickAuto;
                kartu = "world";
                activetool = 0;
            } else {
                stamp = false;
                tileset ts = tilesets.get(seltset);
                int widih = endSelect % tilesets.get(seltset).getWidth()
                        - startSelect % tilesets.get(seltset).getWidth() + 1;
                int heih = endSelect / tilesets.get(seltset).getWidth() - startSelect / tilesets.get(seltset).getWidth()
                        + 1;

                for (int yy = 0; yy < heih; yy++) {
                    for (int xx = 0; xx < widih; xx++) {
                        int num = startSelect;
                        int nyum = num + xx + (yy * ts.getWidth());
                        int pickerSlots = CollectionTilesetOps.getPickerGridSlots(ts);
                        if (nyum >= 0 && nyum < pickerSlots && nyum < massprops.size()) {
                            if (nyum % ts.getWidth() >= num % ts.getWidth()) {
                                massprops.set(nyum, !massprops.get(nyum));
                            }
                        }

                    }
                }

            }
        }

        // mass image properties, I am not dealing with this now.
        if (stamp && "pickanim".equals(kartu) && "massprops".equals(tilePicker)) {
            stamp = false;
            tileset ts = tilesets.get(selTsetID);
            int widih = endSelect % tilesets.get(selTsetID).getWidth()
                    - startSelect % tilesets.get(selTsetID).getWidth() + 1;
            int heih = endSelect / tilesets.get(selTsetID).getWidth() - startSelect / tilesets.get(selTsetID).getWidth()
                    + 1;

            for (int yy = 0; yy < heih; yy++) {
                for (int xx = 0; xx < widih; xx++) {
                    int num = startSelect;
                    int nyum = num + xx + (yy * ts.getWidth());
                    int pickerSlots = CollectionTilesetOps.getPickerGridSlots(ts);
                    if (nyum >= 0 && nyum < pickerSlots && nyum < massprops.size()) {
                        if (nyum % ts.getWidth() >= num % ts.getWidth()) {
                            if (massprops.get(nyum)) {
                                massprops.set(nyum, false);
                            } else {
                                massprops.set(nyum, true);
                            }

                        }
                    }

                }
            }
        }

        if (terrainPainting && isActiveTerrainEditorPicker()) {
            terrainPainting = false;
            lastTerrainPaintCell = -1;
            if (isMacroTerrainEditorPicker())
                saveMacroAutoTerrain();
        }
        terrainHoldPending = false;

        // after we roll the paint...
        if (roll) {

            if (replaceRangePicking) {
                finishReplaceRangePick();
                return true;
            }

            // rectangle (0) and eraser (1) (as they are basically the same tool...)
            // they are drawn on panstop
            // while other tools:
            // brush (4) is on pan
            // fill (2) is on tap
            // copy (3) have their mapend and mapstart on pan, and click on tap

            // I think
            // copy should start here, end of pan, copy things to clipboard.
            // put it into some kind of clipboard instead just marking it

            // let's try, if I am using a copy tool and stop panning
            if (activetool == 3) {
                layer lay = new layer();
                Json json = new Json();

                String clip = json.toJson(layers.get(selLayer));

                lay = json.fromJson(layer.class, clip);
                lay.setName("CLIPBOARD"); // why not, lol.
                cliplayer = lay;
                clipsource = selLayer;

                // now I have the clipboard layer, just put it on tap...
            }

            // no more activetool =1
            if (activetool == 0) {
                beginBrushStroke();

                int awidih = 0, aheih = 0;
                int widih = mapendSelect % Tw - mapstartSelect % Tw;
                int heih = mapendSelect / Tw - mapstartSelect / Tw;
                boolean follower = false;
                int num = mapstartSelect;
                int[] pon = new int[9];
                if (stamp) {

                    // get data from tileset
                    curtset = seltset;
                    int aTw = tilesets.get(seltset).getWidth();
                    awidih = endSelect % aTw - startSelect % aTw; // width of stamp
                    aheih = endSelect / aTw - startSelect / aTw; // height of stamp

                    // this stupidly weird code is to find the edges of stamp, for smart stamp
                    // stored in pon

                    for (int yy = 0; yy <= aheih; yy++) {
                        for (int xx = 0; xx <= awidih; xx++) {
                            int gridIdx = startSelect + xx + (yy * aTw);
                            int kodok = (int) tilesets.get(curtset).getGidAtGridIndex(gridIdx);
                            if (xx == 0 && yy == 0) {
                                // topleft
                                pon[0] = kodok;
                                pon[1] = kodok;
                                pon[3] = kodok;
                            }
                            if (xx > 0 && xx < awidih && yy == 0) {
                                pon[1] = kodok;
                                pon[4] = kodok;
                            }
                            if (xx == awidih && yy == 0) {
                                pon[2] = kodok;
                                pon[5] = kodok;
                            }

                            if (xx == 0 && yy > 0 && yy < aheih) {
                                pon[3] = kodok;
                                pon[4] = kodok;
                            }
                            if (xx > 0 && xx < awidih && yy > 0 && yy < aheih)
                                pon[4] = kodok;
                            if (xx == awidih && yy > 0 && yy < aheih)
                                pon[5] = kodok;

                            if (xx == 0 && yy == aheih) {
                                pon[6] = kodok;
                                pon[7] = kodok;
                            }
                            if (xx > 0 && xx < awidih && yy == aheih)
                                pon[7] = kodok;
                            if (xx == awidih && yy == aheih)
                                pon[8] = kodok;

                        }
                    }
                    // status(pon[0]+"-"+pon[1]+"-"+pon[2]+"-"+pon[3]+"-"+pon[4]+"-"+pon[5]+"-"+pon[6]+"-"+pon[7]+"-"+pon[8],5);
                }

                // and then, draw the stamp here, check this later for stamp on isometric...
                // tag: isometric stamp, stamp iso, iso stamp, whatever...

                boolean firstone = true;
                for (int yy = 0; yy <= heih; yy++) {
                    for (int xx = 0; xx <= widih; xx++) {
                        if ((num + xx + (yy * Tw)) < Th * Tw) {
                            if ((num + xx + (yy * Tw)) % Tw >= num % Tw) {
                                int oldcurspr = curspr;
                                // ini buat yg smart stamp rect
                                if (stamp) {

                                    if (xx == 0 && yy == 0)
                                        curspr = pon[0];
                                    if (xx > 0 && xx < widih && yy == 0)
                                        curspr = pon[1];
                                    if (xx == widih && yy == 0)
                                        curspr = pon[2];

                                    if (xx == 0 && yy > 0 && yy < heih)
                                        curspr = pon[3];
                                    if (xx > 0 && xx < widih && yy > 0 && yy < heih)
                                        curspr = pon[4];
                                    if (xx == widih && yy > 0 && yy < heih)
                                        curspr = pon[5];

                                    if (xx == 0 && yy == heih)
                                        curspr = pon[6];
                                    if (xx > 0 && xx < widih && yy == heih)
                                        curspr = pon[7];
                                    if (xx == widih && yy == heih)
                                        curspr = pon[8];
                                }
                                // log(curspr+"");

                                switch (currentShape) {
                                    case RECTANGLE:

                                        boolean terrar = false;
                                        // if (xx==0 || yy ==0 || xx==widih-1 || yy==heih-1) terrar=true;

                                        // this code halves the needed taptile with terrain true.

                                        if (xx == 0 && yy == 0)
                                            terrar = true;
                                        if (xx == widih && yy == 0)
                                            terrar = true;
                                        if (xx == widih && yy == heih)
                                            terrar = true;
                                        if (yy == heih && xx == 0)
                                            terrar = true;
                                        if (xx == 0 && yy % 2 == 0)
                                            terrar = true;
                                        if (yy == 0 && xx % 2 == 0)
                                            terrar = true;
                                        if (xx == widih && yy % 2 == 0)
                                            terrar = true;
                                        if (yy == heih && xx % 2 == 0)
                                            terrar = true;

                                        final boolean ft = terrar;
                                        final boolean firstonex = firstone;
                                        final int numa = num;
                                        final int xxx = xx;
                                        final int yyy = yy;
                                        final int Ttw = Tw;
                                        final int newcurspr = curspr;

                                        applyShapeTile(numa + xxx + (yyy * Ttw), newcurspr, ft);

                                        if (firstone)
                                            firstone = false;
                                        break;
                                    case ELLIPSE:
                                        // Ellipse follows the red box size: dx²/rx² + dy²/ry² <= 1
                                        float ex = xx - (widih / 2f + 0.5f);
                                        float ey = yy - (heih / 2f + 0.5f);
                                        float rx = (widih + 1) / 2f;
                                        float ry = (heih + 1) / 2f;
                                        if (rx > 0 && ry > 0 && (ex * ex) / (rx * rx) + (ey * ey) / (ry * ry) <= 1.0f) {
                                            applyShapeTile(num + xx + (yy * Tw), curspr, true);
                                        }
                                        break;
                                    case DIAMOND:
                                    // Diamond: |dx|/rx + |dy|/ry <= 1
                                    {
                                        float dx = Math.abs(xx - (widih / 2f + 0.5f));
                                        float dy = Math.abs(yy - (heih / 2f + 0.5f));
                                        float rrx = (widih + 1) / 2f;
                                        float rry = (heih + 1) / 2f;
                                        if (rrx > 0 && rry > 0 && dx / rrx + dy / rry <= 1.0f) {
                                            applyShapeTile(num + xx + (yy * Tw), curspr, true);
                                        }
                                    }
                                        break;
                                    case OCTAGON:
                                    // Octagon: rectangle with 45° corner cuts
                                    {
                                        float dx = Math.abs(xx - (widih / 2f + 0.5f));
                                        float dy = Math.abs(yy - (heih / 2f + 0.5f));
                                        float rrx = (widih + 1) / 2f;
                                        float rry = (heih + 1) / 2f;
                                        if (dx > rrx || dy > rry)
                                            break;
                                        float cut = Math.min(rrx, rry) * 0.2929f;
                                        // Inside inner rectangle, or inside the octagon corner cuts
                                        if (dx <= rrx - cut || dy <= rry - cut || dx + dy <= rrx + rry - cut) {
                                            applyShapeTile(num + xx + (yy * Tw), curspr, true);
                                        }
                                    }
                                        break;
                                    case PLUS:
                                    // Plus sign: horizontal or vertical arm
                                    {
                                        float dx = Math.abs(xx - (widih / 2f + 0.5f));
                                        float dy = Math.abs(yy - (heih / 2f + 0.5f));
                                        float rrx = (widih + 1) / 2f;
                                        float rry = (heih + 1) / 2f;
                                        float armW = rrx * 0.35f; // horizontal arm half-thickness
                                        float armH = rry * 0.35f; // vertical arm half-thickness
                                        if (dy <= armH || dx <= armW) {
                                            applyShapeTile(num + xx + (yy * Tw), curspr, true);
                                        }
                                    }
                                        break;

                                }

                                curspr = oldcurspr;

                            }
                        }
                    }
                } //

                if (currentShape == ShapeTool.LINE) {
                    // backhere

                    boolean vert = heih > widih ? true : false;

                    if (vert) {
                        if (rising) {
                            for (int yy = 0; yy <= heih; yy++) {
                                int xx = widih - Math.round((float) yy / (float) heih * (float) widih);
                                applyShapeTile(num + xx + (yy * Tw), curspr, true);
                            }
                        } else {
                            for (int yy = 0; yy <= heih; yy++) {
                                int xx = Math.round((float) yy / (float) heih * (float) widih);
                                applyShapeTile(num + xx + (yy * Tw), curspr, true);
                            }
                        }
                    } else {
                        if (rising) {
                            for (int xx = 0; xx <= widih; xx++) {
                                int yy = heih - Math.round((float) xx / (float) widih * (float) heih);
                                applyShapeTile(num + xx + (yy * Tw), curspr, true);
                            }
                        } else {
                            for (int xx = 0; xx <= widih; xx++) {
                                int yy = Math.round((float) xx / (float) widih * (float) heih);
                                applyShapeTile(num + xx + (yy * Tw), curspr, true);
                            }
                        }
                    }

                }

                endBrushStroke();
            }
            roll = false;
            // updateMinimap();
        }
        if (activetool == 4) {
            endBrushStroke();
            roll = false;
        }
        return false;
    }

